{
  "name": "React Admin Dashboard",
  "description": "A comprehensive, pure frontend admin dashboard built with React, TypeScript, and Tailwind CSS. Features include authentication, user management, data visualization, weather monitoring, and GenAI integration."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface User {
  id: string;
  username: string;
  email: string;
  status: 'active' | 'inactive';
  role: 'admin' | 'user';
  createdAt: string;
}

export interface UserProfile {
  username: string;
  email: string;
  nickname: string;
  avatar: string;
}

export interface WeatherData {
  city: string;
  temp: number;
  condition: string;
  icon: string;
  humidity: number;
  windSpeed: number;
}

export interface AuthState {
  isAuthenticated: boolean;
  token: string | null;
  user: UserProfile | null;
}

export enum RoutePath {
  LOGIN = '/login',
  DASHBOARD = '/',
  USERS = '/users',
  MAP = '/map',
  WEATHER = '/weather',
  PROFILE = '/profile',
  AI_ASSISTANT = '/ai-assistant'
}

import { UserProfile } from '../types';

const TOKEN_KEY = 'admin_dashboard_token';
const USER_KEY = 'admin_dashboard_user';

export const authService = {
  login: async (username: string, password: string): Promise<boolean> => {
    // Mock API delay
    await new Promise(resolve => setTimeout(resolve, 800));

    if (username === 'admin' && password === '123456') {
      const token = 'mock-jwt-token-' + Date.now();
      const user: UserProfile = {
        username: 'admin',
        nickname: 'Super Admin',
        email: 'admin@example.com',
        avatar: 'https://picsum.photos/200/200',
      };

      localStorage.setItem(TOKEN_KEY, token);
      localStorage.setItem(USER_KEY, JSON.stringify(user));
      return true;
    }
    return false;
  },

  logout: () => {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(USER_KEY);
  },

  isAuthenticated: (): boolean => {
    return !!localStorage.getItem(TOKEN_KEY);
  },

  getUser: (): UserProfile | null => {
    const userStr = localStorage.getItem(USER_KEY);
    return userStr ? JSON.parse(userStr) : null;
  },

  updateUser: (user: UserProfile) => {
    localStorage.setItem(USER_KEY, JSON.stringify(user));
  }
};

import { User } from '../types';

const USERS_STORAGE_KEY = 'admin_dashboard_users_list';

const INITIAL_USERS: User[] = [
  { id: '1', username: 'john_doe', email: 'john@example.com', status: 'active', role: 'user', createdAt: '2023-01-15' },
  { id: '2', username: 'jane_smith', email: 'jane@test.com', status: 'inactive', role: 'user', createdAt: '2023-03-20' },
  { id: '3', username: 'bob_builder', email: 'bob@builds.com', status: 'active', role: 'admin', createdAt: '2023-05-10' },
  { id: '4', username: 'alice_wonder', email: 'alice@wonderland.com', status: 'active', role: 'user', createdAt: '2023-06-01' },
];

export const userService = {
  getUsers: (): User[] => {
    const stored = localStorage.getItem(USERS_STORAGE_KEY);
    if (!stored) {
      localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(INITIAL_USERS));
      return INITIAL_USERS;
    }
    return JSON.parse(stored);
  },

  saveUser: (user: User): void => {
    const users = userService.getUsers();
    const index = users.findIndex(u => u.id === user.id);

    if (index >= 0) {
      users[index] = user;
    } else {
      users.push({ ...user, id: Date.now().toString(), createdAt: new Date().toISOString().split('T')[0] });
    }

    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(users));
  },

  deleteUser: (id: string): void => {
    const users = userService.getUsers();
    const newUsers = users.filter(u => u.id !== id);
    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(newUsers));
  }
};

import React from 'react';
import { NavLink } from 'react-router-dom';
import { LayoutDashboard, Users, Map as MapIcon, CloudSun, UserCircle, LogOut, Bot } from 'lucide-react';
import { authService } from '../services/authService';
import { RoutePath } from '../types';

interface SidebarProps {
  onLogout: () => void;
  isOpen: boolean;
  onCloseMobile: () => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ onLogout, isOpen, onCloseMobile }) => {
  const menuItems = [
    { path: RoutePath.DASHBOARD, icon: LayoutDashboard, label: 'Dashboard' },
    { path: RoutePath.USERS, icon: Users, label: 'User Management' },
    { path: RoutePath.MAP, icon: MapIcon, label: 'Maps' },
    { path: RoutePath.WEATHER, icon: CloudSun, label: 'Weather' },
    { path: RoutePath.AI_ASSISTANT, icon: Bot, label: 'AI Assistant' },
    { path: RoutePath.PROFILE, icon: UserCircle, label: 'Profile' },
  ];

  const sidebarClasses = `
    fixed inset-y-0 left-0 z-30 w-64 bg-slate-900 text-white transform transition-transform duration-200 ease-in-out
    ${isOpen ? 'translate-x-0' : '-translate-x-full'}
    md:translate-x-0 md:static md:inset-auto
  `;

  return (
    <>
      {/* Mobile Overlay */}
      {isOpen && (
        <div 
          className="fixed inset-0 z-20 bg-black bg-opacity-50 md:hidden"
          onClick={onCloseMobile}
        ></div>
      )}

      <aside className={sidebarClasses}>
        <div className="flex h-16 items-center justify-center border-b border-slate-700">
          <h1 className="text-xl font-bold tracking-wider text-blue-400">ADMIN<span className="text-white">PRO</span></h1>
        </div>

        <nav className="mt-6 px-4 space-y-2">
          {menuItems.map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              onClick={onCloseMobile}
              className={({ isActive }) => `
                flex items-center px-4 py-3 text-sm font-medium rounded-lg transition-colors
                ${isActive 
                  ? 'bg-blue-600 text-white shadow-lg shadow-blue-500/30' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'}
              `}
            >
              <item.icon className="mr-3 h-5 w-5" />
              {item.label}
            </NavLink>
          ))}
        </nav>

        <div className="absolute bottom-0 w-full border-t border-slate-700 p-4">
          <button
            onClick={onLogout}
            className="flex w-full items-center justify-center rounded-lg bg-red-600 px-4 py-2 text-sm font-medium text-white hover:bg-red-700 transition-colors"
          >
            <LogOut className="mr-2 h-4 w-4" />
            Sign Out
          </button>
        </div>
      </aside>
    </>
  );
};

import React, { useState, useEffect } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
import { Sidebar } from './Sidebar';
import { authService } from '../services/authService';
import { Menu, Bell } from 'lucide-react';
import { RoutePath } from '../types';

export const Layout: React.FC = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const user = authService.getUser();

  const handleLogout = () => {
    authService.logout();
    navigate(RoutePath.LOGIN);
  };

  useEffect(() => {
    if (!authService.isAuthenticated()) {
      navigate(RoutePath.LOGIN);
    }
  }, [navigate]);

  const getTitle = () => {
    switch (location.pathname) {
      case RoutePath.DASHBOARD: return 'Dashboard';
      case RoutePath.USERS: return 'User Management';
      case RoutePath.MAP: return 'Maps';
      case RoutePath.WEATHER: return 'Weather';
      case RoutePath.PROFILE: return 'My Profile';
      case RoutePath.AI_ASSISTANT: return 'GenAI Assistant';
      default: return 'Admin';
    }
  };

  return (
    <div className="flex h-screen overflow-hidden bg-gray-50">
      <Sidebar 
        onLogout={handleLogout} 
        isOpen={isSidebarOpen} 
        onCloseMobile={() => setIsSidebarOpen(false)}
      />

      <div className="flex flex-1 flex-col overflow-hidden">
        {/* Header */}
        <header className="flex h-16 items-center justify-between bg-white px-6 shadow-sm z-10">
          <div className="flex items-center">
            <button
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="mr-4 rounded-md p-1 text-gray-500 hover:bg-gray-100 md:hidden"
            >
              <Menu className="h-6 w-6" />
            </button>
            <h2 className="text-xl font-semibold text-gray-800">{getTitle()}</h2>
          </div>

          <div className="flex items-center space-x-4">
            <button className="relative rounded-full bg-gray-100 p-2 text-gray-500 hover:bg-gray-200">
              <Bell className="h-5 w-5" />
              <span className="absolute right-2 top-2 h-2 w-2 rounded-full bg-red-500"></span>
            </button>
            <div className="flex items-center space-x-3 border-l pl-4">
              <div className="text-right hidden sm:block">
                <p className="text-sm font-medium text-gray-900">{user?.nickname || 'Admin'}</p>
                <p className="text-xs text-gray-500">{user?.role || 'Administrator'}</p>
              </div>
              <img
                src={user?.avatar || 'https://picsum.photos/200'}
                alt="Profile"
                className="h-9 w-9 rounded-full border border-gray-200 object-cover"
              />
            </div>
          </div>
        </header>

        {/* Main Content */}
        <main className="flex-1 overflow-y-auto overflow-x-hidden p-6">
          <div className="mx-auto max-w-7xl animate-fade-in">
            <Outlet />
          </div>
        </main>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { authService } from '../services/authService';
import { Lock, User, AlertCircle } from 'lucide-react';
import { RoutePath } from '../types';

export const Login: React.FC = () => {
  const navigate = useNavigate();
  const [username, setUsername] = useState('admin');
  const [password, setPassword] = useState('123456');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    try {
      const success = await authService.login(username, password);
      if (success) {
        navigate(RoutePath.DASHBOARD);
      } else {
        setError('Invalid username or password');
      }
    } catch (err) {
      setError('An error occurred. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen items-center justify-center bg-slate-900 p-4">
      <div className="w-full max-w-md overflow-hidden rounded-2xl bg-white shadow-2xl">
        <div className="bg-blue-600 px-8 py-10 text-center">
          <h2 className="text-3xl font-bold text-white">Welcome Back</h2>
          <p className="mt-2 text-blue-100">Sign in to access your dashboard</p>
        </div>

        <div className="p-8">
          <form onSubmit={handleSubmit} className="space-y-6">
            {error && (
              <div className="flex items-center rounded-lg bg-red-50 p-4 text-sm text-red-600 border border-red-200">
                <AlertCircle className="mr-2 h-4 w-4" />
                {error}
              </div>
            )}

            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700">Username</label>
              <div className="relative">
                <User className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                <input
                  type="text"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  className="block w-full rounded-lg border border-gray-300 pl-10 p-2.5 text-gray-900 focus:border-blue-500 focus:ring-blue-500"
                  placeholder="admin"
                  required
                />
              </div>
            </div>

            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700">Password</label>
              <div className="relative">
                <Lock className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                <input
                  type="password"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="block w-full rounded-lg border border-gray-300 pl-10 p-2.5 text-gray-900 focus:border-blue-500 focus:ring-blue-500"
                  placeholder="••••••"
                  required
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              className={`w-full rounded-lg bg-blue-600 px-5 py-3 text-center text-sm font-medium text-white hover:bg-blue-700 focus:outline-none focus:ring-4 focus:ring-blue-300 ${
                loading ? 'cursor-not-allowed opacity-75' : ''
              }`}
            >
              {loading ? 'Signing in...' : 'Sign In'}
            </button>

            <div className="text-center text-xs text-gray-500 mt-4">
              Demo Credentials: admin / 123456
            </div>
          </form>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { userService } from '../services/userService';
import { User } from '../types';
import { Search, Plus, Trash2, Edit2, X } from 'lucide-react';

export const UsersPage: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [formData, setFormData] = useState<Partial<User>>({});

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = () => {
    setUsers(userService.getUsers());
  };

  const filteredUsers = users.filter(user => 
    user.username.toLowerCase().includes(searchTerm.toLowerCase()) || 
    user.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleDelete = (id: string) => {
    if (window.confirm('Are you sure you want to delete this user?')) {
      userService.deleteUser(id);
      loadUsers();
    }
  };

  const handleOpenModal = (user?: User) => {
    if (user) {
      setEditingUser(user);
      setFormData(user);
    } else {
      setEditingUser(null);
      setFormData({ status: 'active', role: 'user' });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.username || !formData.email) return;

    const userToSave: User = {
      id: editingUser ? editingUser.id : '',
      username: formData.username,
      email: formData.email,
      status: formData.status as 'active' | 'inactive',
      role: formData.role as 'admin' | 'user',
      createdAt: editingUser ? editingUser.createdAt : '',
    };

    userService.saveUser(userToSave);
    setIsModalOpen(false);
    loadUsers();
  };

  return (
    <div className="space-y-6">
      {/* Header Actions */}
      <div className="flex flex-col justify-between gap-4 sm:flex-row sm:items-center">
        <div className="relative">
          <Search className="absolute left-3 top-2.5 h-5 w-5 text-gray-400" />
          <input
            type="text"
            placeholder="Search users..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full rounded-lg border border-gray-300 pl-10 p-2 focus:border-blue-500 focus:ring-blue-500 sm:w-64"
          />
        </div>
        <button
          onClick={() => handleOpenModal()}
          className="flex items-center justify-center rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white hover:bg-blue-700"
        >
          <Plus className="mr-2 h-4 w-4" />
          Add User
        </button>
      </div>

      {/* Table */}
      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-gray-500">
            <thead className="bg-gray-50 text-xs uppercase text-gray-700">
              <tr>
                <th className="px-6 py-3">User</th>
                <th className="px-6 py-3">Role</th>
                <th className="px-6 py-3">Status</th>
                <th className="px-6 py-3">Created At</th>
                <th className="px-6 py-3 text-right">Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredUsers.length > 0 ? (
                filteredUsers.map((user) => (
                  <tr key={user.id} className="border-b bg-white hover:bg-gray-50 last:border-0">
                    <td className="px-6 py-4">
                      <div className="flex items-center">
                        <div className="h-8 w-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold mr-3">
                            {user.username.charAt(0).toUpperCase()}
                        </div>
                        <div>
                          <div className="font-medium text-gray-900">{user.username}</div>
                          <div className="text-xs text-gray-500">{user.email}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 capitalize">{user.role}</td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium ${
                        user.status === 'active' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                      }`}>
                        {user.status}
                      </span>
                    </td>
                    <td className="px-6 py-4">{user.createdAt}</td>
                    <td className="px-6 py-4 text-right">
                      <button onClick={() => handleOpenModal(user)} className="mr-2 text-blue-600 hover:text-blue-900">
                        <Edit2 className="h-4 w-4" />
                      </button>
                      <button onClick={() => handleDelete(user.id)} className="text-red-600 hover:text-red-900">
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={5} className="px-6 py-8 text-center text-gray-500">No users found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
          <div className="w-full max-w-md rounded-2xl bg-white shadow-xl">
            <div className="flex items-center justify-between border-b p-4">
              <h3 className="text-lg font-semibold">{editingUser ? 'Edit User' : 'New User'}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600">
                <X className="h-5 w-5" />
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-4 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700">Username</label>
                <input
                  type="text"
                  required
                  value={formData.username || ''}
                  onChange={e => setFormData({...formData, username: e.target.value})}
                  className="mt-1 block w-full rounded-md border border-gray-300 p-2 shadow-sm focus:border-blue-500 focus:ring-blue-500"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Email</label>
                <input
                  type="email"
                  required
                  value={formData.email || ''}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  className="mt-1 block w-full rounded-md border border-gray-300 p-2 shadow-sm focus:border-blue-500 focus:ring-blue-500"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700">Role</label>
                  <select
                    value={formData.role}
                    onChange={e => setFormData({...formData, role: e.target.value as any})}
                    className="mt-1 block w-full rounded-md border border-gray-300 p-2 shadow-sm focus:border-blue-500 focus:ring-blue-500"
                  >
                    <option value="user">User</option>
                    <option value="admin">Admin</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700">Status</label>
                  <select
                    value={formData.status}
                    onChange={e => setFormData({...formData, status: e.target.value as any})}
                    className="mt-1 block w-full rounded-md border border-gray-300 p-2 shadow-sm focus:border-blue-500 focus:ring-blue-500"
                  >
                    <option value="active">Active</option>
                    <option value="inactive">Inactive</option>
                  </select>
                </div>
              </div>
              <div className="pt-4">
                <button
                  type="submit"
                  className="w-full rounded-lg bg-blue-600 px-4 py-2 text-white hover:bg-blue-700"
                >
                  Save User
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import axios from 'axios';
import { Cloud, Search, Droplets, Wind, Thermometer } from 'lucide-react';
import { WeatherData } from '../types';

export const WeatherPage: React.FC = () => {
  const [city, setCity] = useState('New York');
  const [apiKey, setApiKey] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const fetchWeather = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!apiKey) {
        // Fallback demo mode if no key provided
        setError('Please provide an API Key (OpenWeatherMap) or use the demo button below.');
        return;
    }

    setLoading(true);
    setError('');

    try {
      const response = await axios.get(`https://api.openweathermap.org/data/2.5/weather?q=${city}&units=metric&appid=${apiKey}`);
      const data = response.data;

      setWeather({
        city: data.name,
        temp: Math.round(data.main.temp),
        condition: data.weather[0].main,
        icon: `https://openweathermap.org/img/wn/${data.weather[0].icon}@4x.png`,
        humidity: data.main.humidity,
        windSpeed: data.wind.speed
      });
    } catch (err) {
      setError('Failed to fetch weather. Check city name or API Key.');
    } finally {
      setLoading(false);
    }
  };

  const loadDemo = () => {
      setWeather({
          city: "Demo City",
          temp: 24,
          condition: "Clouds",
          icon: "https://openweathermap.org/img/wn/03d@4x.png",
          humidity: 65,
          windSpeed: 4.5
      });
      setError('');
  };

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <div className="rounded-2xl bg-white p-6 shadow-sm border border-gray-100">
        <h2 className="mb-4 text-lg font-semibold text-gray-800">Weather Forecast</h2>

        <form onSubmit={fetchWeather} className="space-y-4">
            <div>
                <label className="block text-xs font-medium text-gray-500 uppercase">OpenWeatherMap API Key</label>
                <input
                    type="text"
                    value={apiKey}
                    onChange={(e) => setApiKey(e.target.value)}
                    placeholder="Enter your API Key"
                    className="mt-1 block w-full rounded-lg border border-gray-300 p-2 text-sm"
                />
            </div>

            <div className="flex gap-2">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-2.5 h-5 w-5 text-gray-400" />
                    <input
                    type="text"
                    value={city}
                    onChange={(e) => setCity(e.target.value)}
                    placeholder="Enter city name..."
                    className="block w-full rounded-lg border border-gray-300 pl-10 p-2"
                    />
                </div>
                <button
                    type="submit"
                    disabled={loading}
                    className="rounded-lg bg-blue-600 px-6 py-2 text-white hover:bg-blue-700 disabled:opacity-50"
                >
                    {loading ? '...' : 'Search'}
