import React, { useEffect, useState } from 'react';
import AMapLoader from '@amap/amap-jsapi-loader';
import { useApp } from '../contexts/AppContext';
import { Shield, Key } from 'lucide-react';

export const MapPage: React.FC = () => {
  const { t } = useApp();
  const [map, setMap] = useState<any>(null);
  const [isKeySet, setIsKeySet] = useState(false);
  const [securityCode, setSecurityCode] = useState('');
  const [apiKey, setApiKey] = useState('');
  const [error, setError] = useState('');

  // Setup security config globally
  useEffect(() => {
    // Check if we already have keys stored or set
    const storedSecCode = localStorage.getItem('amap_security_code');
    const storedApiKey = localStorage.getItem('amap_api_key');

    if (storedSecCode && storedApiKey) {
      setSecurityCode(storedSecCode);
      setApiKey(storedApiKey);
      setIsKeySet(true);
    }
  }, []);

  useEffect(() => {
    if (!isKeySet) return;

    // AMap requires security config on window object
    (window as any)._AMapSecurityConfig = {
      securityJsCode: securityCode,
    };

    let mapInstance: any = null;

    AMapLoader.load({
      key: apiKey,
      version: "2.0",
      plugins: ['AMap.Scale', 'AMap.ToolBar'],
    })
      .then((AMap) => {
        mapInstance = new AMap.Map("map-container", {
          viewMode: "3D",
          zoom: 5,
          center: [105.602725, 35.076636], // Center of China
        });

        // Add some mock markers
        const locations = [
           { name: 'Beijing HQ', pos: [116.397428, 39.90923] },
           { name: 'Shanghai Branch', pos: [121.473701, 31.230416] },
           { name: 'Shenzhen Office', pos: [114.057868, 22.543099] },
        ];

        locations.forEach(loc => {
           const marker = new AMap.Marker({
               position: new AMap.LngLat(loc.pos[0], loc.pos[1]),
               title: loc.name
           });
           mapInstance.add(marker);
        });

        setMap(mapInstance);
        setError('');
      })
      .catch((e) => {
        console.error(e);
        setError('Failed to load map. Check your keys.');
        setIsKeySet(false); // Allow retry
      });

    return () => {
      if (mapInstance) {
        mapInstance.destroy();
      }
    };
  }, [isKeySet, apiKey, securityCode]);

  const handleSaveKeys = () => {
    if (securityCode && apiKey) {
      localStorage.setItem('amap_security_code', securityCode);
      localStorage.setItem('amap_api_key', apiKey);
      setIsKeySet(true);
    }
  };

  if (!isKeySet) {
    return (
      <div className="flex h-[calc(100vh-8rem)] items-center justify-center bg-gray-50 dark:bg-slate-900">
        <div className="w-full max-w-md rounded-xl bg-white p-8 shadow-lg dark:bg-slate-800">
          <div className="mb-6 text-center">
            <h2 className="text-xl font-bold text-gray-900 dark:text-white">{t('enterAmapKeys')}</h2>
            <p className="text-sm text-gray-500 dark:text-gray-400">
              Gaode Map requires a Web Key and Security Code.
            </p>
          </div>

          <div className="space-y-4">
            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                {t('securityCode')}
              </label>
              <div className="relative">
                <Shield className="absolute left-3 top-2.5 h-5 w-5 text-gray-400" />
                <input
                  type="password"
                  value={securityCode}
                  onChange={(e) => setSecurityCode(e.target.value)}
                  className="block w-full rounded-lg border border-gray-300 p-2.5 pl-10 text-sm focus:border-[var(--color-primary)] focus:ring-[var(--color-primary)] dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                  placeholder="Web Security Code"
                />
              </div>
            </div>

            <div>
              <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                 {t('accessKey')} (Key)
              </label>
              <div className="relative">
                <Key className="absolute left-3 top-2.5 h-5 w-5 text-gray-400" />
                <input
                  type="text"
                  value={apiKey}
                  onChange={(e) => setApiKey(e.target.value)}
                  className="block w-full rounded-lg border border-gray-300 p-2.5 pl-10 text-sm focus:border-[var(--color-primary)] focus:ring-[var(--color-primary)] dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                  placeholder="Web API Key"
                />
              </div>
            </div>

            {error && <p className="text-sm text-red-500">{error}</p>}

            <button
              onClick={handleSaveKeys}
              className="w-full rounded-lg bg-[var(--color-primary)] px-5 py-2.5 text-center text-sm font-medium text-white hover:bg-[var(--color-primary-hover)]"
            >
              {t('loadMap')}
            </button>
            <p className="text-xs text-center text-gray-400 mt-2">
                Keys are saved locally in your browser.
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="h-[calc(100vh-8rem)] w-full overflow-hidden rounded-xl border border-gray-200 shadow-sm relative z-0 dark:border-slate-700">
       <div id="map-container" className="h-full w-full bg-slate-100 dark:bg-slate-800"></div>
       <button 
         onClick={() => {
            localStorage.removeItem('amap_security_code');
            localStorage.removeItem('amap_api_key');
            setIsKeySet(false);
         }}
         className="absolute top-4 right-4 z-10 bg-white dark:bg-slate-800 px-3 py-1 rounded shadow text-xs font-medium"
       >
         Reset Keys
       </button>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Sparkles, Key, Trash2 } from 'lucide-react';
import { useApp } from '../contexts/AppContext';

interface Message {
  role: 'user' | 'assistant'; // DeepSeek uses 'assistant' not 'model'
  content: string;
}

export const AiAssistant: React.FC = () => {
  const { t } = useApp();
  const [apiKey, setApiKey] = useState('');
  const [isKeySet, setIsKeySet] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([
    { role: 'assistant', content: 'Hello! I am DeepSeek AI. How can I assist you today?' }
  ]);
  const [loading, setLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const storedKey = localStorage.getItem('deepseek_api_key');
    if (storedKey) {
        setApiKey(storedKey);
        setIsKeySet(true);
    }
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(scrollToBottom, [messages]);

  const saveKey = () => {
      if(apiKey.trim()) {
          localStorage.setItem('deepseek_api_key', apiKey);
          setIsKeySet(true);
      }
  };

  const clearKey = () => {
      localStorage.removeItem('deepseek_api_key');
      setApiKey('');
      setIsKeySet(false);
  };

  const handleSend = async () => {
    if (!input.trim() || !isKeySet) return;

    const userMessage = input;
    // Update local state immediately
    const newMessages = [...messages, { role: 'user', content: userMessage } as Message];
    setMessages(newMessages);
    setInput('');
    setLoading(true);

    try {
      const response = await fetch('https://api.deepseek.com/chat/completions', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${apiKey}`
        },
        body: JSON.stringify({
          model: 'deepseek-chat',
          messages: newMessages.map(m => ({ role: m.role, content: m.content })),
          stream: false 
        })
      });

      const data = await response.json();

      if (!response.ok) {
         throw new Error(data.error?.message || 'Failed to fetch');
      }

      const assistantContent = data.choices[0].message.content;
      setMessages(prev => [...prev, { role: 'assistant', content: assistantContent }]);

    } catch (error: any) {
      console.error(error);
      setMessages(prev => [...prev, { role: 'assistant', content: `Error: ${error.message || 'Could not connect to DeepSeek.'}` }]);
    } finally {
      setLoading(false);
    }
  };

  if (!isKeySet) {
      return (
          <div className="flex h-[calc(100vh-8rem)] items-center justify-center">
              <div className="bg-white dark:bg-slate-800 p-8 rounded-xl shadow-lg max-w-md w-full border border-gray-100 dark:border-slate-700">
                  <div className="text-center mb-6">
                      <div className="h-12 w-12 bg-blue-100 dark:bg-blue-900 rounded-full flex items-center justify-center mx-auto mb-4">
                          <Bot className="h-6 w-6 text-blue-600 dark:text-blue-400" />
                      </div>
                      <h2 className="text-xl font-bold dark:text-white">{t('setupKey')}</h2>
                      <p className="text-sm text-gray-500 dark:text-gray-400 mt-2">
                          Please enter your DeepSeek API Key to continue.
                      </p>
                  </div>
                  <div className="space-y-4">
                      <div className="relative">
                          <Key className="absolute left-3 top-3 h-5 w-5 text-gray-400" />
                          <input 
                              type="password" 
                              value={apiKey}
                              onChange={(e) => setApiKey(e.target.value)}
                              className="w-full pl-10 pr-4 py-2 rounded-lg border border-gray-300 dark:border-slate-600 dark:bg-slate-700 dark:text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                              placeholder="sk-..."
                          />
                      </div>
                      <button 
                          onClick={saveKey}
                          disabled={!apiKey}
                          className="w-full bg-[var(--color-primary)] text-white py-2 rounded-lg hover:opacity-90 transition-opacity disabled:opacity-50"
                      >
                          {t('signIn')}
                      </button>
                      <p className="text-xs text-center text-gray-400">
                          Your key is stored locally in your browser.
                      </p>
                  </div>
              </div>
          </div>
      );
  }

  return (
    <div className="flex flex-col h-[calc(100vh-8rem)] bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden dark:bg-slate-800 dark:border-slate-700">
      {/* Header */}
      <div className="bg-gradient-to-r from-[var(--color-primary)] to-purple-600 p-4 flex items-center justify-between text-white">
        <div className="flex items-center gap-2">
            <Sparkles className="h-5 w-5" />
            <h2 className="font-semibold">{t('aiTitle')}</h2>
        </div>
        <button 
            onClick={clearKey}
            className="p-1.5 hover:bg-white/20 rounded-lg transition-colors text-xs flex items-center gap-1"
        >
            <Trash2 className="h-4 w-4" />
            Clear Key
        </button>
      </div>

      {/* Chat Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50 dark:bg-slate-900">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex max-w-[80%] gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`h-8 w-8 rounded-full flex items-center justify-center flex-shrink-0 ${msg.role === 'user' ? 'bg-[var(--color-primary)]' : 'bg-purple-600'}`}>
                {msg.role === 'user' ? <User className="h-5 w-5 text-white" /> : <Bot className="h-5 w-5 text-white" />}
              </div>
              <div className={`p-3 rounded-2xl text-sm ${
                msg.role === 'user' 
                  ? 'bg-[var(--color-primary)] text-white rounded-tr-none' 
                  : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none shadow-sm dark:bg-slate-800 dark:border-slate-700 dark:text-gray-200'
              }`}>
                {msg.content}
              </div>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
             <div className="bg-white border border-gray-200 p-3 rounded-2xl rounded-tl-none shadow-sm text-sm text-gray-500 italic dark:bg-slate-800 dark:border-slate-700 dark:text-gray-400">
                {t('typing')}
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-gray-200 dark:bg-slate-800 dark:border-slate-700">
        <div className="flex gap-2">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            placeholder={t('aiPlaceholder')}
            disabled={loading}
            className="flex-1 border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-[var(--color-primary)] dark:bg-slate-700 dark:border-slate-600 dark:text-white"
          />
          <button
            onClick={handleSend}
            disabled={loading}
            className="bg-[var(--color-primary)] text-white rounded-lg px-4 py-2 hover:opacity-90 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
          >
            <Send className="h-5 w-5" />
          </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { userService } from '../services/userService';
import { User } from '../types';
import { Search, Plus, Trash2, Edit2, X } from 'lucide-react';
import { useApp } from '../contexts/AppContext';

export const UsersPage: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [formData, setFormData] = useState<Partial<User>>({});
  const { t } = useApp();

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = () => {
    setUsers(userService.getUsers());
  };

  const filteredUsers = users.filter(user => 
    user.username.toLowerCase().includes(searchTerm.toLowerCase()) || 
    user.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleDelete = (id: string) => {
    if (window.confirm('Are you sure you want to delete this user?')) {
      userService.deleteUser(id);
      loadUsers();
    }
  };

  const handleOpenModal = (user?: User) => {
    if (user) {
      setEditingUser(user);
      setFormData(user);
    } else {
      setEditingUser(null);
      setFormData({ status: 'active', role: 'user' });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.username || !formData.email) return;

    const userToSave: User = {
      id: editingUser ? editingUser.id : '',
      username: formData.username,
      email: formData.email,
      status: formData.status as 'active' | 'inactive',
      role: formData.role as 'admin' | 'user',
      createdAt: editingUser ? editingUser.createdAt : '',
    };

    userService.saveUser(userToSave);
    setIsModalOpen(false);
    loadUsers();
  };

  return (
    <div className="space-y-6">
      {/* Header Actions */}
      <div className="flex flex-col justify-between gap-4 sm:flex-row sm:items-center">
        <div className="relative">
          <Search className="absolute left-3 top-2.5 h-5 w-5 text-gray-400" />
          <input
            type="text"
            placeholder={t('search') + "..."}
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full rounded-lg border border-gray-300 pl-10 p-2 focus:border-[var(--color-primary)] focus:ring-[var(--color-primary)] sm:w-64 dark:bg-slate-800 dark:border-slate-700 dark:text-white"
          />
        </div>
        <button
          onClick={() => handleOpenModal()}
          className="flex items-center justify-center rounded-lg bg-[var(--color-primary)] px-4 py-2 text-sm font-medium text-white hover:bg-[var(--color-primary-hover)]"
        >
          <Plus className="mr-2 h-4 w-4" />
          {t('addUser')}
        </button>
      </div>

      {/* Table */}
