import { User } from '../types';

const USERS_STORAGE_KEY = 'admin_dashboard_users_list';

// Default password is '123456' for all initial users
const INITIAL_USERS: User[] = [
  { id: '1', username: 'admin', email: 'admin@example.com', status: 'active', role: 'admin', createdAt: '2023-01-01', password: '123456', nickname: 'Super Admin', avatar: 'https://picsum.photos/id/1005/200/200' },
  { id: '2', username: 'john_doe', email: 'john@example.com', status: 'active', role: 'user', createdAt: '2023-01-15', password: '123456', nickname: 'John Doe', avatar: 'https://picsum.photos/id/1011/200/200' },
  { id: '3', username: 'jane_smith', email: 'jane@test.com', status: 'inactive', role: 'user', createdAt: '2023-03-20', password: '123456', nickname: 'Jane Smith', avatar: 'https://picsum.photos/id/1027/200/200' },
];

export const userService = {
  getUsers: (): User[] => {
    const stored = localStorage.getItem(USERS_STORAGE_KEY);
    if (!stored) {
      localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(INITIAL_USERS));
      return INITIAL_USERS;
    }
    return JSON.parse(stored);
  },

  getUserByUsername: (username: string): User | undefined => {
    const users = userService.getUsers();
    return users.find(u => u.username === username);
  },

  saveUser: (user: User): void => {
    const users = userService.getUsers();
    const index = users.findIndex(u => u.id === user.id);

    // If creating a new user without a password, set a default one
    if (index === -1 && !user.password) {
        user.password = '123456'; 
    }

    // Preserve password if editing and not provided
    if (index >= 0 && !user.password) {
        user.password = users[index].password;
    }

    if (index >= 0) {
      users[index] = { ...users[index], ...user };
    } else {
      users.push({ ...user, id: Date.now().toString(), createdAt: new Date().toISOString().split('T')[0] });
    }

    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(users));
  },

  deleteUser: (id: string): void => {
    const users = userService.getUsers();
    const newUsers = users.filter(u => u.id !== id);
    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(newUsers));
  }
};

import { UserProfile } from '../types';
import { userService } from './userService';

const TOKEN_KEY = 'admin_dashboard_token';
const USER_KEY = 'admin_dashboard_user';

export const authService = {
  login: async (username: string, password: string): Promise<UserProfile | null> => {
    // Mock API delay
    await new Promise(resolve => setTimeout(resolve, 600));

    const user = userService.getUserByUsername(username);

    if (user && user.password === password && user.status === 'active') {
      const token = 'mock-jwt-token-' + Date.now();

      const profile: UserProfile = {
        ...user
      };

      localStorage.setItem(TOKEN_KEY, token);
      localStorage.setItem(USER_KEY, JSON.stringify(profile));
      return profile;
    }
    return null;
  },

  logout: () => {
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(USER_KEY);
  },

  isAuthenticated: (): boolean => {
    return !!localStorage.getItem(TOKEN_KEY);
  },

  getUser: (): UserProfile | null => {
    const userStr = localStorage.getItem(USER_KEY);
    return userStr ? JSON.parse(userStr) : null;
  },

  updateUser: (user: UserProfile) => {
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    // Also update the source of truth in user service
    userService.saveUser(user);
  }
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { Language, translations } from '../utils/i18n';
import { UserProfile } from '../types';
import { authService } from '../services/authService';

interface ThemeConfig {
  mode: 'light' | 'dark';
  color: string;
}

interface AppContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  theme: ThemeConfig;
  setTheme: (theme: ThemeConfig) => void;
  t: (key: keyof typeof translations['en']) => string;
  user: UserProfile | null;
  setUser: (user: UserProfile | null) => void;
  refreshUser: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguage] = useState<Language>('zh');
  // Load saved theme or default
  const [theme, setTheme] = useState<ThemeConfig>(() => {
      const saved = localStorage.getItem('app_theme');
      return saved ? JSON.parse(saved) : { mode: 'light', color: '#2563eb' };
  });

  const [user, setUser] = useState<UserProfile | null>(authService.getUser());

  const refreshUser = () => {
    setUser(authService.getUser());
  };

  useEffect(() => {
    // Persist theme
    localStorage.setItem('app_theme', JSON.stringify(theme));

    // Apply Dark Mode
    if (theme.mode === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }

    // Apply Primary Color
    // We use a timeout to ensure DOM is ready, though normally not needed in React effect
    const root = document.documentElement;
    root.style.setProperty('--color-primary', theme.color);

    // Calculate a hover color (simple darkening)
    // Note: This is a rough approximation for hex codes
    root.style.setProperty('--color-primary-hover', theme.color); 

  }, [theme]);

  const t = (key: keyof typeof translations['en']) => {
    return translations[language][key] || key;
  };

  return (
    <AppContext.Provider value={{ language, setLanguage, theme, setTheme, t, user, setUser, refreshUser }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

