import React, { useState, useRef } from 'react';
import { authService } from '../services/authService';
import { UserProfile } from '../types';
import { Camera, Save } from 'lucide-react';
import { useApp } from '../contexts/AppContext';

export const ProfilePage: React.FC = () => {
  const { user: contextUser, refreshUser } = useApp();
  // Initialize from context but keep local state for form editing
  const [user, setUser] = useState<UserProfile>(contextUser!);
  const [message, setMessage] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setUser({ ...user, [e.target.name]: e.target.value });
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUser({ ...user, avatar: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    authService.updateUser(user);
    refreshUser(); // Sync with global context immediately
    setMessage('Profile updated successfully!');
    setTimeout(() => setMessage(''), 3000);
  };

  if (!user) return <div>Loading...</div>;

  return (
    <div className="max-w-2xl mx-auto bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden dark:bg-slate-800 dark:border-slate-700">
      <div className="h-32 bg-gradient-to-r from-[var(--color-primary)] to-purple-600"></div>

      <div className="px-8 pb-8">
        <div className="relative -mt-12 mb-6 flex justify-center">
          <div className="relative">
            <img
              src={user.avatar || 'https://ui-avatars.com/api/?name=' + user.username}
              alt="Profile"
              className="h-24 w-24 rounded-full border-4 border-white bg-white object-cover shadow-md dark:border-slate-800"
            />
            <button
              onClick={() => fileInputRef.current?.click()}
              className="absolute bottom-0 right-0 rounded-full bg-gray-900 p-2 text-white hover:bg-gray-700 dark:bg-slate-700 dark:hover:bg-slate-600"
            >
              <Camera className="h-4 w-4" />
            </button>
            <input
              type="file"
              ref={fileInputRef}
              className="hidden"
              accept="image/*"
              onChange={handleImageUpload}
            />
          </div>
        </div>

        <div className="space-y-6">
          <div className="grid grid-cols-1 gap-6 sm:grid-cols-2">
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Username</label>
              <input
                type="text"
                disabled
                value={user.username}
                className="mt-1 block w-full rounded-md border border-gray-200 bg-gray-50 p-2 text-gray-500 dark:bg-slate-700 dark:border-slate-600 dark:text-gray-400"
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Nickname</label>
              <input
                type="text"
                name="nickname"
                value={user.nickname || ''}
                onChange={handleChange}
                className="mt-1 block w-full rounded-md border border-gray-300 p-2 focus:border-blue-500 focus:ring-blue-500 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
              />
            </div>
            <div className="sm:col-span-2">
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Email</label>
              <input
                type="email"
                name="email"
                value={user.email}
                onChange={handleChange}
                className="mt-1 block w-full rounded-md border border-gray-300 p-2 focus:border-blue-500 focus:ring-blue-500 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
              />
            </div>
            <div className="sm:col-span-2 border-t border-gray-100 pt-4 mt-2 dark:border-slate-700">
              <h4 className="text-sm font-medium text-gray-900 mb-4 dark:text-white">Change Password</h4>
              <div className="space-y-4">
                 <input
                    type="password"
                    placeholder="New Password"
                    onChange={(e) => setUser({...user, password: e.target.value})}
                    className="block w-full rounded-md border border-gray-300 p-2 focus:border-blue-500 focus:ring-blue-500 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                  />
              </div>
            </div>
          </div>

          <div className="flex items-center justify-between pt-4">
            <span className="text-sm text-green-600 font-medium">{message}</span>
            <button
              onClick={handleSave}
              className="flex items-center rounded-lg bg-[var(--color-primary)] px-6 py-2 text-white hover:opacity-90"
            >
              <Save className="mr-2 h-4 w-4" />
              Save Changes
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Cloud, Search, Droplets, Wind, Settings } from 'lucide-react';
import { WeatherData } from '../types';

// Mock data for Chinese cities to allow "Free" usage
const MOCK_CN_DATA: Record<string, WeatherData> = {
    'Beijing': { city: 'Beijing', temp: 22, condition: 'Sunny', humidity: 45, windSpeed: 3.5, icon: 'https://openweathermap.org/img/wn/01d@4x.png' },
    'Shanghai': { city: 'Shanghai', temp: 25, condition: 'Cloudy', humidity: 70, windSpeed: 4.2, icon: 'https://openweathermap.org/img/wn/03d@4x.png' },
    'Guangzhou': { city: 'Guangzhou', temp: 29, condition: 'Rain', humidity: 85, windSpeed: 2.1, icon: 'https://openweathermap.org/img/wn/10d@4x.png' },
    'Shenzhen': { city: 'Shenzhen', temp: 28, condition: 'Thunderstorm', humidity: 80, windSpeed: 5.0, icon: 'https://openweathermap.org/img/wn/11d@4x.png' },
    'Chengdu': { city: 'Chengdu', temp: 19, condition: 'Fog', humidity: 60, windSpeed: 1.5, icon: 'https://openweathermap.org/img/wn/50d@4x.png' },
};

export const WeatherPage: React.FC = () => {
  const [city, setCity] = useState('Beijing');
  const [apiKey, setApiKey] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showConfig, setShowConfig] = useState(false);
  const [useMock, setUseMock] = useState(true);

  useEffect(() => {
      // Load settings
      const savedKey = localStorage.getItem('weather_api_key');
      if (savedKey) {
          setApiKey(savedKey);
          setUseMock(false);
      } else {
          setUseMock(true);
      }

      // Initial load
      fetchWeather(null, 'Beijing');
  }, []);

  const saveConfig = () => {
      if (apiKey) {
          localStorage.setItem('weather_api_key', apiKey);
          setUseMock(false);
      } else {
          localStorage.removeItem('weather_api_key');
          setUseMock(true);
      }
      setShowConfig(false);
      fetchWeather(null, city);
  };

  const fetchWeather = async (e?: React.FormEvent | null, searchCity?: string) => {
    if (e) e.preventDefault();
    const queryCity = searchCity || city;
    setCity(queryCity);

    setLoading(true);
    setError('');

    if (useMock || !apiKey) {
        // Mock Mode logic
        await new Promise(r => setTimeout(r, 600)); // Simulate delay

        // Simple fuzzy match for mock data
        const foundKey = Object.keys(MOCK_CN_DATA).find(k => k.toLowerCase() === queryCity.toLowerCase());

        if (foundKey) {
            setWeather(MOCK_CN_DATA[foundKey]);
        } else {
            // Random generation for unknown mock cities
            setWeather({
                city: queryCity,
                temp: Math.floor(Math.random() * 15) + 15,
                condition: 'Partly Cloudy',
                icon: 'https://openweathermap.org/img/wn/02d@4x.png',
                humidity: Math.floor(Math.random() * 40) + 40,
                windSpeed: Math.floor(Math.random() * 10)
            });
        }
        setLoading(false);
        return;
    }

    // Real API Logic
    try {
      const response = await axios.get(`https://api.openweathermap.org/data/2.5/weather?q=${queryCity}&units=metric&appid=${apiKey}`);
      const data = response.data;

      setWeather({
        city: data.name,
        temp: Math.round(data.main.temp),
        condition: data.weather[0].main,
        icon: `https://openweathermap.org/img/wn/${data.weather[0].icon}@4x.png`,
        humidity: data.main.humidity,
        windSpeed: data.wind.speed
      });
    } catch (err) {
      setError('Failed to fetch weather. Check API Key or City name.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto space-y-6">
      <div className="rounded-2xl bg-white p-6 shadow-sm border border-gray-100 dark:bg-slate-800 dark:border-slate-700">
        <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-semibold text-gray-800 dark:text-white">Weather Forecast</h2>
            <button 
                onClick={() => setShowConfig(!showConfig)}
                className="text-gray-400 hover:text-[var(--color-primary)]"
                title="API Settings"
            >
                <Settings className="h-5 w-5" />
            </button>
        </div>

        {showConfig && (
            <div className="mb-6 p-4 bg-gray-50 rounded-lg dark:bg-slate-700 transition-all">
                <label className="block text-xs font-medium text-gray-500 dark:text-gray-300 uppercase mb-2">
                    OpenWeatherMap API Key (Optional)
                </label>
                <div className="flex gap-2">
                    <input
                        type="text"
                        value={apiKey}
                        onChange={(e) => setApiKey(e.target.value)}
                        placeholder="Leave empty to use Simulated Data (Free)"
                        className="flex-1 rounded-lg border border-gray-300 p-2 text-sm dark:bg-slate-600 dark:border-slate-500 dark:text-white"
                    />
                    <button onClick={saveConfig} className="bg-[var(--color-primary)] text-white px-4 rounded-lg text-sm">
                        Save
                    </button>
                </div>
                <p className="text-xs text-gray-400 mt-2">
                    Without a key, the system uses simulated data for Chinese cities.
                </p>
            </div>
        )}

        <form onSubmit={(e) => fetchWeather(e)} className="flex gap-2">
            <div className="relative flex-1">
                <Search className="absolute left-3 top-2.5 h-5 w-5 text-gray-400" />
                <input
                type="text"
                value={city}
                onChange={(e) => setCity(e.target.value)}
                placeholder="Enter city name (e.g. Beijing)"
                className="block w-full rounded-lg border border-gray-300 pl-10 p-2 dark:bg-slate-700 dark:border-slate-600 dark:text-white focus:outline-none focus:ring-2 focus:ring-[var(--color-primary)]"
                />
            </div>
            <button
                type="submit"
                disabled={loading}
                className="rounded-lg bg-[var(--color-primary)] px-6 py-2 text-white hover:opacity-90 disabled:opacity-50"
            >
                {loading ? '...' : 'Search'}
            </button>
        </form>

        {error && <p className="mt-4 text-sm text-red-500 text-center">{error}</p>}
