import React, { useEffect, useState } from 'react';
import AMapLoader from '@amap/amap-jsapi-loader';
import { useApp } from '../contexts/AppContext';
import { Shield, Key, Settings, ChevronUp, ChevronDown } from 'lucide-react';

export const MapPage: React.FC = () => {
  const { t } = useApp();
  const [map, setMap] = useState<any>(null);
  const [isKeySet, setIsKeySet] = useState(false);
  const [securityCode, setSecurityCode] = useState('');
  const [apiKey, setApiKey] = useState('');
  const [error, setError] = useState('');
  const [isConfigOpen, setIsConfigOpen] = useState(false);

  // Setup security config globally
  useEffect(() => {
    // Check if we already have keys stored or set
    const storedSecCode = localStorage.getItem('amap_security_code');
    const storedApiKey = localStorage.getItem('amap_api_key');

    if (storedSecCode && storedApiKey) {
      setSecurityCode(storedSecCode);
      setApiKey(storedApiKey);
      setIsKeySet(true);
    }
  }, []);

  useEffect(() => {
    if (!isKeySet) return;

    // AMap requires security config on window object
    (window as any)._AMapSecurityConfig = {
      securityJsCode: securityCode,
    };

    let mapInstance: any = null;

    AMapLoader.load({
      key: apiKey,
      version: "2.0",
      plugins: ['AMap.Scale', 'AMap.ToolBar'],
    })
      .then((AMap) => {
        mapInstance = new AMap.Map("map-container", {
          viewMode: "3D",
          zoom: 5,
          center: [105.602725, 35.076636], // Center of China
          mapStyle: 'amap://styles/whitesmoke' // Optional style
        });

        // Add some mock markers
        const locations = [
           { name: 'Beijing HQ', pos: [116.397428, 39.90923] },
           { name: 'Shanghai Branch', pos: [121.473701, 31.230416] },
           { name: 'Shenzhen Office', pos: [114.057868, 22.543099] },
        ];

        locations.forEach(loc => {
           const marker = new AMap.Marker({
               position: new AMap.LngLat(loc.pos[0], loc.pos[1]),
               title: loc.name
           });
           mapInstance.add(marker);
        });

        setMap(mapInstance);
        setError('');
      })
      .catch((e) => {
        console.error(e);
        setError('Failed to load map. Invalid Key or Security Code.');
        setIsKeySet(false); // Allow retry
      });

    return () => {
      if (mapInstance) {
        mapInstance.destroy();
      }
    };
  }, [isKeySet, apiKey, securityCode]);

  const handleSaveKeys = () => {
    if (securityCode && apiKey) {
      localStorage.setItem('amap_security_code', securityCode);
      localStorage.setItem('amap_api_key', apiKey);
      setIsKeySet(true);
      setIsConfigOpen(false); // Close panel on save
    }
  };

  return (
    <div className="relative h-[calc(100vh-8rem)] w-full overflow-hidden rounded-xl border border-gray-200 shadow-sm z-0 dark:border-slate-700 flex flex-col">
       {isKeySet ? (
           <div id="map-container" className="flex-1 w-full bg-slate-100 dark:bg-slate-800"></div>
       ) : (
        <div className="flex-1 flex items-center justify-center bg-gray-50 dark:bg-slate-900">
            <div className="text-center p-8">
                <Shield className="h-16 w-16 text-gray-300 mx-auto mb-4" />
                <h3 className="text-xl font-bold text-gray-700 dark:text-gray-300">Map Not Configured</h3>
                <p className="text-gray-500 mt-2 max-w-sm mx-auto">Please set your Gaode Map (AMap) keys in the configuration panel below to display the map.</p>
                <button 
                    onClick={() => setIsConfigOpen(true)}
                    className="mt-6 bg-[var(--color-primary)] text-white px-6 py-2 rounded-lg"
                >
                    Open Configuration
                </button>
            </div>
        </div>
       )}

       {/* Collapsible Configuration Bar at Bottom */}
       <div className={`border-t border-gray-200 bg-white dark:bg-slate-800 dark:border-slate-700 transition-all duration-300 ${isConfigOpen ? 'h-auto p-4' : 'h-12'}`}>
            <div 
                className="flex items-center justify-between cursor-pointer h-full"
                onClick={() => setIsConfigOpen(!isConfigOpen)}
            >
                <div className="flex items-center gap-2">
                    <Settings className="h-4 w-4 text-gray-500" />
                    <span className="font-semibold text-sm text-gray-700 dark:text-gray-200">{t('mapConfig')}</span>
                </div>
                {isConfigOpen ? <ChevronDown className="h-4 w-4" /> : <ChevronUp className="h-4 w-4" />}
            </div>

            {isConfigOpen && (
                <div className="mt-4 grid gap-4 sm:grid-cols-2 animate-fade-in">
                     <div>
                        <label className="mb-1 block text-xs font-medium text-gray-500 dark:text-gray-400">
                            {t('securityCode')} (Web Security)
                        </label>
                        <input
                            type="password"
                            value={securityCode}
                            onChange={(e) => setSecurityCode(e.target.value)}
                            className="block w-full rounded-lg border border-gray-300 p-2 text-sm dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                            placeholder="e.g. j82..."
                        />
                    </div>
                    <div>
                        <label className="mb-1 block text-xs font-medium text-gray-500 dark:text-gray-400">
                            {t('accessKey')} (Web Key)
                        </label>
                        <div className="flex gap-2">
                            <input
                                type="text"
                                value={apiKey}
                                onChange={(e) => setApiKey(e.target.value)}
                                className="block w-full rounded-lg border border-gray-300 p-2 text-sm dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                                placeholder="e.g. 5d9..."
                            />
                            <button
                                onClick={handleSaveKeys}
                                className="bg-[var(--color-primary)] text-white px-4 rounded-lg text-sm whitespace-nowrap"
                            >
                                Load Map
                            </button>
                        </div>
                    </div>
                    {error && <p className="text-xs text-red-500 col-span-2">{error}</p>}
                </div>
            )}
