import React, { useEffect, useState } from 'react';
import AMapLoader from '@amap/amap-jsapi-loader';
import { useApp } from '../contexts/AppContext';
import { Shield, Key, Settings, ChevronUp, ChevronDown } from 'lucide-react';

export const MapPage: React.FC = () => {
  const { t, theme } = useApp();
  const [map, setMap] = useState<any>(null);
  const [isKeySet, setIsKeySet] = useState(false);
  const [securityCode, setSecurityCode] = useState('');
  const [apiKey, setApiKey] = useState('');
  const [error, setError] = useState('');
  const [isConfigOpen, setIsConfigOpen] = useState(false);

  // Setup security config globally
  useEffect(() => {
    // Check if we already have keys stored or set
    const storedSecCode = localStorage.getItem('amap_security_code');
    const storedApiKey = localStorage.getItem('amap_api_key');

    if (storedSecCode && storedApiKey) {
      setSecurityCode(storedSecCode);
      setApiKey(storedApiKey);
      setIsKeySet(true);
    }
  }, []);

  // Update map style when theme changes
  useEffect(() => {
    if (map) {
      // amap://styles/dark for dark mode, amap://styles/normal (or other styles) for light
      const styleName = theme.mode === 'dark' ? 'amap://styles/darkblue' : 'amap://styles/normal';
      map.setMapStyle(styleName);
    }
  }, [theme.mode, map]);

  useEffect(() => {
    if (!isKeySet) return;

    // AMap requires security config on window object
    (window as any)._AMapSecurityConfig = {
      securityJsCode: securityCode,
    };

    let mapInstance: any = null;

    AMapLoader.load({
      key: apiKey,
      version: "2.0",
      plugins: ['AMap.Scale', 'AMap.ToolBar', 'AMap.ControlBar', 'AMap.HawkEye'],
    })
      .then((AMap) => {
        mapInstance = new AMap.Map("map-container", {
          viewMode: "3D",
          zoom: 5,
          center: [105.602725, 35.076636], // Center of China
          mapStyle: theme.mode === 'dark' ? 'amap://styles/darkblue' : 'amap://styles/normal'
        });

        // Add controls
        mapInstance.addControl(new AMap.Scale());
        mapInstance.addControl(new AMap.ToolBar());
        mapInstance.addControl(new AMap.ControlBar({ position: { right: '10px', top: '10px' } }));
        mapInstance.addControl(new AMap.HawkEye({ isOpen: true }));

        // Add some mock markers
        const locations = [
           { name: '北京总部 (Beijing)', pos: [116.397428, 39.90923] },
           { name: '上海分部 (Shanghai)', pos: [121.473701, 31.230416] },
           { name: '深圳研发中心 (Shenzhen)', pos: [114.057868, 22.543099] },
           { name: '成都办事处 (Chengdu)', pos: [104.066541, 30.572269] },
        ];

        locations.forEach(loc => {
           const marker = new AMap.Marker({
               position: new AMap.LngLat(loc.pos[0], loc.pos[1]),
               title: loc.name
           });

           // Simple info window
           const infoWindow = new AMap.InfoWindow({
               content: `<div style="padding:5px; color:#333;"><b>${loc.name}</b><br/>Status: Active</div>`,
               offset: new AMap.Pixel(0, -30)
           });

           marker.on('click', () => {
               infoWindow.open(mapInstance, marker.getPosition());
           });

           mapInstance.add(marker);
        });

        setMap(mapInstance);
        setError('');
      })
      .catch((e) => {
        console.error(e);
        setError('加载地图失败。请检查 Key 和安全密钥是否正确。');
        setIsKeySet(false); // Allow retry
      });

    return () => {
      if (mapInstance) {
        mapInstance.destroy();
      }
    };
  }, [isKeySet, apiKey, securityCode]);

  const handleSaveKeys = () => {
    if (securityCode && apiKey) {
      localStorage.setItem('amap_security_code', securityCode);
      localStorage.setItem('amap_api_key', apiKey);
      setIsKeySet(true);
      setIsConfigOpen(false); // Close panel on save
    }
  };

  return (
    <div className="relative h-[calc(100vh-8rem)] w-full overflow-hidden rounded-xl border border-gray-200 shadow-sm z-0 dark:border-slate-700 flex flex-col">
       {isKeySet ? (
           <div id="map-container" className="flex-1 w-full bg-slate-100 dark:bg-slate-800"></div>
       ) : (
        <div className="flex-1 flex items-center justify-center bg-gray-50 dark:bg-slate-900">
            <div className="text-center p-8">
                <Shield className="h-16 w-16 text-gray-300 mx-auto mb-4" />
                <h3 className="text-xl font-bold text-gray-700 dark:text-gray-300">{t('mapNotConfigured')}</h3>
                <p className="text-gray-500 mt-2 max-w-sm mx-auto">{t('mapConfigDesc')}</p>
                <button 
                    onClick={() => setIsConfigOpen(true)}
                    className="mt-6 bg-[var(--color-primary)] text-white px-6 py-2 rounded-lg"
                >
                    {t('openConfig')}
                </button>
            </div>
        </div>
       )}

       {/* Collapsible Configuration Bar at Bottom */}
       <div className={`border-t border-gray-200 bg-white dark:bg-slate-800 dark:border-slate-700 transition-all duration-300 ${isConfigOpen ? 'h-auto p-4' : 'h-12'}`}>
            <div 
                className="flex items-center justify-between cursor-pointer h-full"
                onClick={() => setIsConfigOpen(!isConfigOpen)}
            >
                <div className="flex items-center gap-2">
                    <Settings className="h-4 w-4 text-gray-500" />
                    <span className="font-semibold text-sm text-gray-700 dark:text-gray-200">{t('mapConfig')}</span>
                </div>
                {isConfigOpen ? <ChevronDown className="h-4 w-4" /> : <ChevronUp className="h-4 w-4" />}
            </div>

            {isConfigOpen && (
                <div className="mt-4 grid gap-4 sm:grid-cols-2 animate-fade-in">
                     <div>
                        <label className="mb-1 block text-xs font-medium text-gray-500 dark:text-gray-400">
                            {t('securityCode')} (Web Security)
                        </label>
                        <input
                            type="password"
                            value={securityCode}
                            onChange={(e) => setSecurityCode(e.target.value)}
                            className="block w-full rounded-lg border border-gray-300 p-2 text-sm dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                            placeholder="e.g. j82..."
                        />
                    </div>
                    <div>
                        <label className="mb-1 block text-xs font-medium text-gray-500 dark:text-gray-400">
                            {t('accessKey')} (Web Key)
                        </label>
                        <div className="flex gap-2">
                            <input
                                type="text"
                                value={apiKey}
                                onChange={(e) => setApiKey(e.target.value)}
                                className="block w-full rounded-lg border border-gray-300 p-2 text-sm dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                                placeholder="e.g. 5d9..."
                            />
                            <button
                                onClick={handleSaveKeys}
                                className="bg-[var(--color-primary)] text-white px-4 rounded-lg text-sm whitespace-nowrap"
                            >
                                {t('loadMap')}
                            </button>
                        </div>
                    </div>
                    {error && <p className="text-xs text-red-500 col-span-2">{error}</p>}
                </div>
            )}
       </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import AMapLoader from '@amap/amap-jsapi-loader';
import { useApp } from '../contexts/AppContext';
import { Shield, Settings, ChevronUp, ChevronDown, RefreshCw, ExternalLink, AlertTriangle } from 'lucide-react';

export const MapPage: React.FC = () => {
  const { t, theme } = useApp();
  const [map, setMap] = useState<any>(null);
  const [isKeySet, setIsKeySet] = useState(false);
  const [securityCode, setSecurityCode] = useState('');
  const [apiKey, setApiKey] = useState('');
  const [error, setError] = useState('');
  const [isConfigOpen, setIsConfigOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  // Load saved keys on mount
  useEffect(() => {
    const storedSecCode = localStorage.getItem('amap_security_code');
    const storedApiKey = localStorage.getItem('amap_api_key');

    if (storedSecCode && storedApiKey) {
      setSecurityCode(storedSecCode);
      setApiKey(storedApiKey);
      setIsKeySet(true);
    } else {
        setIsConfigOpen(true);
    }
  }, []);

  // Map Initialization Logic
  useEffect(() => {
    if (!isKeySet || !apiKey || !securityCode) return;

    // CRITICAL: Set security config on window BEFORE loading the script
    (window as any)._AMapSecurityConfig = {
      securityJsCode: securityCode,
    };

    let mapInstance: any = null;
    setIsLoading(true);
    setError('');

    AMapLoader.load({
      key: apiKey,
      version: "2.0",
      plugins: ['AMap.Scale', 'AMap.ToolBar', 'AMap.ControlBar', 'AMap.HawkEye', 'AMap.PlaceSearch'],
    })
      .then((AMap) => {
        mapInstance = new AMap.Map("map-container", {
          viewMode: "3D",
          zoom: 4,
          center: [105.602725, 35.076636],
          mapStyle: theme.mode === 'dark' ? 'amap://styles/darkblue' : 'amap://styles/normal'
        });

        mapInstance.addControl(new AMap.Scale());
        mapInstance.addControl(new AMap.ToolBar());
        mapInstance.addControl(new AMap.ControlBar({ position: { right: '10px', top: '10px' } }));
        mapInstance.addControl(new AMap.HawkEye({ isOpen: true }));

        // Mock Markers
        const locations = [
           { name: '北京总部 (Beijing)', pos: [116.397428, 39.90923] },
           { name: '上海分部 (Shanghai)', pos: [121.473701, 31.230416] },
           { name: '深圳 (Shenzhen)', pos: [114.057868, 22.543099] },
           { name: '成都 (Chengdu)', pos: [104.066541, 30.572269] },
           { name: '武汉 (Wuhan)', pos: [114.305393, 30.593099] }
        ];

        locations.forEach(loc => {
           const marker = new AMap.Marker({
               position: new AMap.LngLat(loc.pos[0], loc.pos[1]),
               title: loc.name
           });

           const infoWindow = new AMap.InfoWindow({
               content: `<div style="padding:10px; color:#000;">
                  <h4 style="font-weight:bold; margin-bottom:5px;">${loc.name}</h4>
                  <p style="font-size:12px;">Office Status: <span style="color:green">Active</span></p>
               </div>`,
               offset: new AMap.Pixel(0, -30)
           });

           marker.on('click', () => {
               infoWindow.open(mapInstance, marker.getPosition());
           });

           mapInstance.add(marker);
        });

        setMap(mapInstance);
        setIsLoading(false);
      })
      .catch((e) => {
        console.error("AMap Load Error:", e);
        setError('加载地图失败。请检查 Key 类型是否为 [Web端(JSAPI)] 且安全密钥正确。');
        setIsLoading(false);
        // Do not auto-reset isKeySet to allow user to see error and edit
      });

    return () => {
      if (mapInstance) {
        mapInstance.destroy();
      }
    };
  }, [isKeySet, apiKey, securityCode]);

  // Dynamic Theme Update
  useEffect(() => {
    if (map) {
      const styleName = theme.mode === 'dark' ? 'amap://styles/darkblue' : 'amap://styles/normal';
      map.setMapStyle(styleName);
    }
  }, [theme.mode, map]);

  const handleSaveKeys = () => {
    if (securityCode.trim() && apiKey.trim()) {
      localStorage.setItem('amap_security_code', securityCode.trim());
      localStorage.setItem('amap_api_key', apiKey.trim());

      // If we are already set, we might need to force a reload or re-run effect
      if (isKeySet) {
          window.location.reload(); // AMap loader caches things, reload is safest for key change
      } else {
          setIsKeySet(true);
          setIsConfigOpen(false);
      }
    }
  };

  const handleReset = () => {
      localStorage.removeItem('amap_security_code');
      localStorage.removeItem('amap_api_key');
      setSecurityCode('');
      setApiKey('');
      setIsKeySet(false);
      setMap(null);
      setError('');
      setIsConfigOpen(true);
  };

  return (
    <div className="relative h-[calc(100vh-8rem)] w-full overflow-hidden rounded-xl border border-gray-200 shadow-sm z-0 dark:border-slate-700 flex flex-col bg-white dark:bg-slate-800">
       {isKeySet && !error ? (
           <div id="map-container" className="flex-1 w-full bg-slate-100 dark:bg-slate-800 relative">
               {isLoading && (
                   <div className="absolute inset-0 flex items-center justify-center bg-white/50 dark:bg-black/50 z-10">
                       <div className="flex flex-col items-center">
                           <RefreshCw className="h-8 w-8 animate-spin text-[var(--color-primary)]" />
                           <span className="mt-2 text-sm font-semibold text-gray-700 dark:text-gray-200">地图加载中...</span>
                       </div>
                   </div>
               )}
           </div>
       ) : (
        <div className="flex-1 flex items-center justify-center bg-gray-50 dark:bg-slate-900 p-6">
            <div className="text-center max-w-lg">
                <Shield className="h-16 w-16 text-gray-300 mx-auto mb-4" />
                <h3 className="text-xl font-bold text-gray-700 dark:text-gray-300">
                    {error ? '配置错误 (Configuration Error)' : t('mapNotConfigured')}
                </h3>

                {error ? (
                    <div className="mt-4 p-4 bg-red-50 text-red-600 rounded-lg text-sm flex items-center text-left">
                        <AlertTriangle className="h-5 w-5 mr-2 flex-shrink-0" />
                        {error}
                    </div>
                ) : (
                    <p className="text-gray-500 mt-2">{t('mapConfigDesc')}</p>
                )}

                <div className="mt-8 flex flex-col gap-3 sm:flex-row sm:justify-center">
                    <button 
                        onClick={() => setIsConfigOpen(true)}
                        className="bg-[var(--color-primary)] text-white px-6 py-2 rounded-lg hover:opacity-90"
                    >
                        {t('openConfig')}
                    </button>
                    <a 
                        href="https://console.amap.com/dev/key/app" 
                        target="_blank" 
                        rel="noreferrer"
                        className="flex items-center justify-center px-6 py-2 border border-gray-300 rounded-lg text-gray-600 hover:bg-gray-100 dark:border-slate-600 dark:text-gray-300 dark:hover:bg-slate-700"
                    >
                        <ExternalLink className="h-4 w-4 mr-2" />
                        {t('howToGetKeys')}
                    </a>
                </div>
            </div>
        </div>
       )}

       {/* Configuration Panel */}
       <div className={`border-t border-gray-200 bg-white dark:bg-slate-800 dark:border-slate-700 transition-all duration-300 ${isConfigOpen ? 'h-auto p-6 shadow-[0_-5px_20px_rgba(0,0,0,0.1)]' : 'h-12'}`}>
            <div 
                className="flex items-center justify-between cursor-pointer h-full"
                onClick={() => setIsConfigOpen(!isConfigOpen)}
            >
                <div className="flex items-center gap-2">
                    <Settings className="h-4 w-4 text-gray-500" />
                    <span className="font-semibold text-sm text-gray-700 dark:text-gray-200">{t('mapConfig')}</span>
                </div>
                <div className="flex items-center gap-3">
                    {isKeySet && (
                        <button 
                            onClick={(e) => { e.stopPropagation(); handleReset(); }} 
                            className="text-xs text-red-500 hover:underline"
                        >
                            {t('resetKeys')}
                        </button>
                    )}
                    {isConfigOpen ? <ChevronDown className="h-4 w-4" /> : <ChevronUp className="h-4 w-4" />}
                </div>
            </div>

            {isConfigOpen && (
                <div className="mt-4 animate-fade-in">
                    <div className="grid gap-6 sm:grid-cols-2">
                        <div>
                            <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                                {t('accessKey')} <span className="text-xs text-gray-400 font-normal">(类型必须为 Web端 / JSAPI)</span>
                            </label>
                            <input
                                type="text"
                                value={apiKey}
                                onChange={(e) => setApiKey(e.target.value)}
                                className="block w-full rounded-lg border border-gray-300 p-2.5 text-sm dark:bg-slate-700 dark:border-slate-600 dark:text-white focus:ring-2 focus:ring-[var(--color-primary)] outline-none"
                                placeholder="输入 Key (例如: 5d9...)"
                            />
                        </div>
                        <div>
                            <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">
                                {t('securityCode')} <span className="text-xs text-gray-400 font-normal">(必填，为了安全)</span>
                            </label>
                            <input
                                type="password"
                                value={securityCode}
                                onChange={(e) => setSecurityCode(e.target.value)}
                                className="block w-full rounded-lg border border-gray-300 p-2.5 text-sm dark:bg-slate-700 dark:border-slate-600 dark:text-white focus:ring-2 focus:ring-[var(--color-primary)] outline-none"
                                placeholder="输入安全密钥 (例如: j82...)"
                            />
                        </div>
                    </div>
                    <div className="mt-6 flex justify-end">
                        <button
                            onClick={handleSaveKeys}
                            className="bg-[var(--color-primary)] text-white px-8 py-2.5 rounded-lg text-sm font-medium hover:opacity-90 transition-opacity"
                        >
                            {isKeySet ? '重新加载地图' : t('loadMap')}
                        </button>
                    </div>
                </div>
            )}
       </div>
    </div>
  );
};

