      setSecurityCode(storedSecCode);
      setApiKey(storedApiKey);
      setIsKeySet(true);
    } else {
        setIsConfigOpen(true);
    }
  }, []);

  // Map Initialization Logic
  useEffect(() => {
    if (!isKeySet || !apiKey || !securityCode) return;

    // CRITICAL: Set security config on window BEFORE loading the script
    (window as any)._AMapSecurityConfig = {
      securityJsCode: securityCode,
    };

    let mapInstance: any = null;
