                        <p style="font-size:12px;">Office Status: <span style="color:green">Active</span></p>
                    </div>`,
                    offset: new AMap.Pixel(0, -30)
                });

                marker.on('click', () => {
                    infoWindow.open(mapInstance, marker.getPosition());
                });

                mapInstance.add(marker);
            });

            setMap(mapInstance);
            setIsLoading(false);
            loadingRef.current = false;
            clearTimeout(timeoutId);
        } catch (initErr: any) {
            console.error("Map Init Failed:", initErr);
            setError('地图初始化失败: ' + initErr.message);
            setIsLoading(false);
            loadingRef.current = false;
        }
      })
      .catch((e) => {
        if (!isMounted) return;
        console.error("AMap Load Error:", e);
        setError('加载地图资源失败，请确认 Key 类型是否正确 (Web端 JSAPI)。');
        setIsLoading(false);
        loadingRef.current = false;
        clearTimeout(timeoutId);
      });

    return () => {
      isMounted = false;
      clearTimeout(timeoutId);
      if (mapInstance) {
        mapInstance.destroy();
      }
    };
