      if (isKeySet) {
          window.location.reload(); // AMap loader caches things, reload is safest for key change
      } else {
          setIsKeySet(true);
          setIsConfigOpen(false);
      }
    }
  };

  const handleReset = () => {
      localStorage.removeItem('amap_security_code');
      localStorage.removeItem('amap_api_key');
