  }, [theme.mode, map]);

  const handleSaveKeys = () => {
    if (securityCode.trim() && apiKey.trim()) {
      localStorage.setItem('amap_security_code', securityCode.trim());
      localStorage.setItem('amap_api_key', apiKey.trim());
      // Force reload to clear any bad AMap loader state
      window.location.reload();
    }
  };

  const handleReset = () => {
      localStorage.removeItem('amap_security_code');
      localStorage.removeItem('amap_api_key');
      // Force reload to clear state
      window.location.reload();
  };

  return (
    <div className="relative h-[calc(100vh-8rem)] w-full overflow-hidden rounded-xl border border-gray-200 shadow-sm z-0 dark:border-slate-700 flex flex-col bg-white dark:bg-slate-800">

