            <div 
                className="flex items-center justify-between cursor-pointer h-full"
                onClick={() => setIsConfigOpen(!isConfigOpen)}
            >
                <div className="flex items-center gap-2">
                    <Settings className="h-4 w-4 text-gray-500" />
                    <span className="font-semibold text-sm text-gray-700 dark:text-gray-200">{t('mapConfig')}</span>
                </div>
                <div className="flex items-center gap-3">
                    <span className="text-xs text-gray-400 font-mono hidden sm:inline">{isKeySet ? `Key: ${apiKey.slice(0,4)}...` : '未配置'}</span>
                    {isKeySet && (
                        <button 
                            onClick={(e) => { e.stopPropagation(); handleReset(); }} 
                            className="text-xs text-red-500 hover:underline px-2"
                        >
                            {t('resetKeys')}
                        </button>
                    )}
                    {isConfigOpen ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
                </div>
            </div>

            {isConfigOpen && (
                <div className="mt-4 animate-fade-in">
                    <div className="grid gap-6 sm:grid-cols-2">
