import React, { useState, useEffect } from 'react';
import { userService } from '../services/userService';
import { User } from '../types';
import { Search, Plus, Trash2, Edit2, X, Crown } from 'lucide-react';
import { useApp } from '../contexts/AppContext';

export const UsersPage: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [formData, setFormData] = useState<Partial<User>>({});
  const { t } = useApp();

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = () => {
    setUsers(userService.getUsers());
  };

  const filteredUsers = users.filter(user => 
    user.username.toLowerCase().includes(searchTerm.toLowerCase()) || 
    user.email.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleDelete = (user: User) => {
    if (user.username === 'admin') {
        alert(t('cannotDeleteAdmin'));
        return;
    }

    if (window.confirm(t('confirmDelete'))) {
      userService.deleteUser(user.id);
      loadUsers();
    }
  };

  const handleOpenModal = (user?: User) => {
    if (user) {
      setEditingUser(user);
      setFormData(user);
    } else {
      setEditingUser(null);
      setFormData({ status: 'active', role: 'user' });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.username || !formData.email) return;

    const userToSave: User = {
      id: editingUser ? editingUser.id : '',
      username: formData.username,
      email: formData.email,
      status: formData.status as 'active' | 'inactive',
      role: formData.role as 'admin' | 'user',
      createdAt: editingUser ? editingUser.createdAt : '',
      // Only update password if it was entered in the form
      password: formData.password || (editingUser ? editingUser.password : '123456'), 
      nickname: formData.nickname || formData.username,
      avatar: formData.avatar || editingUser?.avatar
    };

    userService.saveUser(userToSave);
    setIsModalOpen(false);
    loadUsers();
  };

  return (
    <div className="space-y-6">
      {/* Header Actions */}
      <div className="flex flex-col justify-between gap-4 sm:flex-row sm:items-center">
        <div className="relative">
          <Search className="absolute left-3 top-2.5 h-5 w-5 text-gray-400" />
          <input
            type="text"
            placeholder={t('search')}
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full rounded-lg border border-gray-300 pl-10 p-2 focus:border-[var(--color-primary)] focus:ring-[var(--color-primary)] sm:w-64 dark:bg-slate-800 dark:border-slate-700 dark:text-white"
          />
        </div>
        <button
          onClick={() => handleOpenModal()}
          className="flex items-center justify-center rounded-lg bg-[var(--color-primary)] px-4 py-2 text-sm font-medium text-white hover:bg-[var(--color-primary-hover)]"
        >
          <Plus className="mr-2 h-4 w-4" />
          {t('addUser')}
        </button>
      </div>

      {/* Table */}
      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm dark:bg-slate-800 dark:border-slate-700">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-gray-500 dark:text-gray-400">
            <thead className="bg-gray-50 text-xs uppercase text-gray-700 dark:bg-slate-700 dark:text-gray-200">
              <tr>
                <th className="px-6 py-3">{t('user')}</th>
                <th className="px-6 py-3">{t('role')}</th>
                <th className="px-6 py-3">{t('status')}</th>
                <th className="px-6 py-3">Created At</th>
                <th className="px-6 py-3 text-right">{t('actions')}</th>
              </tr>
            </thead>
            <tbody>
              {filteredUsers.length > 0 ? (
                filteredUsers.map((user) => (
                  <tr key={user.id} className="border-b bg-white hover:bg-gray-50 last:border-0 dark:bg-slate-800 dark:border-slate-700 dark:hover:bg-slate-700">
                    <td className="px-6 py-4">
                      <div className="flex items-center">
                        <div className="h-8 w-8 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold mr-3 dark:bg-blue-900 dark:text-blue-300 overflow-hidden shrink-0">
                            {user.avatar ? 
                                <img src={user.avatar} alt="avatar" className="w-full h-full object-cover" /> 
                                : user.username.charAt(0).toUpperCase()
                            }
                        </div>
                        <div>
                          <div className="font-medium text-gray-900 dark:text-white flex items-center gap-1.5">
                              {user.nickname || user.username}
                              {user.username === 'admin' && (
                                  <span className="inline-flex items-center rounded-md bg-amber-100 px-1.5 py-0.5 text-xs font-medium text-amber-800 border border-amber-200 dark:bg-amber-900/40 dark:text-amber-300 dark:border-amber-800/50">
                                      <Crown className="mr-0.5 h-3 w-3 fill-amber-500 text-amber-600 dark:fill-amber-400 dark:text-amber-300" />
                                      {t('svip')}
                                  </span>
                              )}
                          </div>
                          <div className="text-xs text-gray-500 dark:text-gray-400">{user.email}</div>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 capitalize">{t(user.role)}</td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center rounded-full px-2.5 py-0.5 text-xs font-medium ${
                        user.status === 'active' 
                          ? 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400' 
                          : 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400'
                      }`}>
                        {user.status === 'active' ? t('active') : t('inactive')}
                      </span>
                    </td>
                    <td className="px-6 py-4">{user.createdAt}</td>
                    <td className="px-6 py-4 text-right">
                      <button onClick={() => handleOpenModal(user)} className="mr-2 text-[var(--color-primary)] hover:opacity-80">
                        <Edit2 className="h-4 w-4" />
                      </button>

                      <button 
                        onClick={() => handleDelete(user)} 
                        disabled={user.username === 'admin'}
                        className={`text-red-600 transition-colors ${user.username === 'admin' ? 'opacity-30 cursor-not-allowed' : 'hover:text-red-900 dark:hover:text-red-400'}`}
                        title={user.username === 'admin' ? t('cannotDeleteAdmin') : ''}
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={5} className="px-6 py-8 text-center text-gray-500">No users found.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
          <div className="w-full max-w-md rounded-2xl bg-white shadow-xl dark:bg-slate-800">
            <div className="flex items-center justify-between border-b p-4 dark:border-slate-700">
              <h3 className="text-lg font-semibold dark:text-white">{editingUser ? t('editUser') : t('newUser')}</h3>
              <button onClick={() => setIsModalOpen(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-200">
                <X className="h-5 w-5" />
              </button>
            </div>
            <form onSubmit={handleSubmit} className="p-4 space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">{t('username')}</label>
                <input
                  type="text"
                  required
                  value={formData.username || ''}
                  onChange={e => setFormData({...formData, username: e.target.value})}
                  // Disable editing username for admin to prevent accidental lockout/identity change
                  disabled={editingUser?.username === 'admin'}
                  className={`mt-1 block w-full rounded-md border border-gray-300 p-2 shadow-sm focus:border-blue-500 focus:ring-blue-500 dark:bg-slate-700 dark:border-slate-600 dark:text-white ${editingUser?.username === 'admin' ? 'opacity-60 cursor-not-allowed' : ''}`}
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">Email</label>
                <input
                  type="email"
                  required
                  value={formData.email || ''}
                  onChange={e => setFormData({...formData, email: e.target.value})}
                  className="mt-1 block w-full rounded-md border border-gray-300 p-2 shadow-sm focus:border-blue-500 focus:ring-blue-500 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">{t('password')}</label>
                <input
                  type="password"
                  placeholder={editingUser ? "留空保持不变" : "默认: 123456"}
                  value={formData.password || ''}
                  onChange={e => setFormData({...formData, password: e.target.value})}
                  className="mt-1 block w-full rounded-md border border-gray-300 p-2 shadow-sm focus:border-blue-500 focus:ring-blue-500 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">{t('role')}</label>
                  <select
                    value={formData.role}
                    onChange={e => setFormData({...formData, role: e.target.value as any})}
                    className="mt-1 block w-full rounded-md border border-gray-300 p-2 shadow-sm focus:border-blue-500 focus:ring-blue-500 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                  >
                    <option value="user">{t('user')}</option>
                    <option value="admin">{t('admin')}</option>
                  </select>
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">{t('status')}</label>
                  <select
                    value={formData.status}
                    onChange={e => setFormData({...formData, status: e.target.value as any})}
                    className="mt-1 block w-full rounded-md border border-gray-300 p-2 shadow-sm focus:border-blue-500 focus:ring-blue-500 dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                  >
                    <option value="active">{t('active')}</option>
                    <option value="inactive">{t('inactive')}</option>
                  </select>
                </div>
              </div>
              <div className="pt-4">
                <button
                  type="submit"
                  className="w-full rounded-lg bg-[var(--color-primary)] px-4 py-2 text-white hover:opacity-90"
                >
                  {t('saveUser')}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

