export const userService = {
  getUsers: (): User[] => {
    const stored = localStorage.getItem(USERS_STORAGE_KEY);
    if (!stored) {
      localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(INITIAL_USERS));
      return INITIAL_USERS;
    }
    return JSON.parse(stored);
  },

  getUserByUsername: (username: string): User | undefined => {
    const users = userService.getUsers();
    return users.find(u => u.username === username);
  },

  saveUser: (user: User): void => {
    const users = userService.getUsers();
    const index = users.findIndex(u => u.id === user.id);

    // If creating a new user without a password, set a default one
    if (index === -1 && !user.password) {
        user.password = '123456'; 
    }

    // Preserve password if editing and not provided
    if (index >= 0 && !user.password) {
        user.password = users[index].password;
    }

    // Preserve points and check-in if not provided in update
    if (index >= 0) {
        if (user.points === undefined) user.points = users[index].points;
        if (user.lastCheckIn === undefined) user.lastCheckIn = users[index].lastCheckIn;
    } else {
        // New user default points
        if (user.points === undefined) user.points = 0;
    }

    if (index >= 0) {
      users[index] = { ...users[index], ...user };
    } else {
      users.push({ ...user, id: Date.now().toString(), createdAt: new Date().toISOString().split('T')[0] });
    }

    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(users));
  },

  deleteUser: (id: string): void => {
    const users = userService.getUsers();
    const newUsers = users.filter(u => u.id !== id);
    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(newUsers));
  }
};

