import React, { useEffect, useState, useRef } from 'react';
import AMapLoader from '@amap/amap-jsapi-loader';
import { useApp } from '../contexts/AppContext';
import { Shield, Settings, ChevronUp, ChevronDown, RefreshCw, ExternalLink, AlertTriangle } from 'lucide-react';

const DEFAULT_API_KEY = '7f9b20ffe8068cf62b24454bf046bc27';
const DEFAULT_SECURITY_CODE = '36182307c8c0a634b9f90c659153c197';

export const MapPage: React.FC = () => {
  const { t, theme } = useApp();
  const [map, setMap] = useState<any>(null);
  const [isKeySet, setIsKeySet] = useState(false);
  const [securityCode, setSecurityCode] = useState('');
  const [apiKey, setApiKey] = useState('');
  const [error, setError] = useState('');
  const [isConfigOpen, setIsConfigOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const mapContainerRef = useRef<HTMLDivElement>(null);
  const loadingRef = useRef(false);
  const mapInstanceRef = useRef<any>(null);

  useEffect(() => {
    const storedSecCode = localStorage.getItem('amap_security_code');
    const storedApiKey = localStorage.getItem('amap_api_key');

    if (storedSecCode && storedApiKey) {
      setSecurityCode(storedSecCode);
      setApiKey(storedApiKey);
      setIsKeySet(true);
    } else {
      setSecurityCode(DEFAULT_SECURITY_CODE);
      setApiKey(DEFAULT_API_KEY);
      setIsConfigOpen(true);
    }
  }, []);

  useEffect(() => {
    if (!isKeySet || !apiKey || !securityCode) return;

    (window as any)._AMapSecurityConfig = {
      securityJsCode: securityCode,
    };

    let isMounted = true;

    if (mapInstanceRef.current) {
        mapInstanceRef.current.destroy();
        mapInstanceRef.current = null;
    }
    setMap(null);
    setIsLoading(true);
    loadingRef.current = true;
    setError('');

    const timeoutId = setTimeout(() => {
        if (isMounted && loadingRef.current) {
            setIsLoading(false);
            loadingRef.current = false;
            setError('加载超时 (Timeout)。请检查网络或 Key 类型。');
        }
    }, 12000);

    AMapLoader.load({
      key: apiKey,
      version: "2.0",
      plugins: ['AMap.Scale', 'AMap.ToolBar', 'AMap.ControlBar', 'AMap.BezierCurve', 'AMap.MoveAnimation'],
    })
      .then((AMap) => {
        if (!isMounted) return;

        try {
            // Initialize map centered on China
            const mapInstance = new AMap.Map("map-container", {
                viewMode: "3D",
                zoom: 4.2,
                center: [108.5525, 34.3227], // Roughly center of China
                mapStyle: theme.mode === 'dark' ? 'amap://styles/darkblue' : 'amap://styles/light',
                pitch: 0, 
            });

            mapInstance.on('complete', () => {
                if (isMounted) {
                    setIsLoading(false);
                    loadingRef.current = false;
                }
            });

            mapInstance.addControl(new AMap.Scale());
            mapInstance.addControl(new AMap.ToolBar({position: 'RT'}));

            // --- Visualization Logic ---
            // Center Hub (e.g., Beijing)
            const centerPoint = new AMap.LngLat(116.397428, 39.90923);

            // Major cities for distribution points
            const cities = [
                { name: '乌鲁木齐 (Urumqi)', pos: [87.6168, 43.8256] },
                { name: '拉萨 (Lhasa)', pos: [91.1172, 29.6469] },
                { name: '成都 (Chengdu)', pos: [104.0665, 30.5723] },
                { name: '昆明 (Kunming)', pos: [102.8329, 24.8801] },
                { name: '广州 (Guangzhou)', pos: [113.2644, 23.1291] },
                { name: '哈尔滨 (Harbin)', pos: [126.5349, 45.8038] },
                { name: '上海 (Shanghai)', pos: [121.4737, 31.2304] },
                { name: '西安 (Xi\'an)', pos: [108.9398, 34.3416] },
                { name: '武汉 (Wuhan)', pos: [114.3054, 30.5931] },
                { name: '呼和浩特 (Hohhot)', pos: [111.7492, 40.8426] },
                { name: '海口 (Haikou)', pos: [110.1983, 20.0440] },
                { name: '台北 (Taipei)', pos: [121.5654, 25.0330] }
            ];

            // 1. Add Center Marker (Beijing)
            const centerMarker = new AMap.Marker({
                position: centerPoint,
                content: `<div style="background:rgba(255,0,0,0.8); width:16px; height:16px; border-radius:50%; box-shadow: 0 0 10px rgba(255,0,0,0.8); border: 2px solid white;"></div>`,
                offset: new AMap.Pixel(-8, -8),
                zIndex: 100
            });
            mapInstance.add(centerMarker);

            // 2. Draw Curves
            cities.forEach(city => {
                const endPoint = new AMap.LngLat(city.pos[0], city.pos[1]);

                // Calculate control point for curve (simple quadratic bezier logic)
                // We offset the midpoint slightly to create a curve
                const c1 = centerPoint.lng; 
                const c2 = centerPoint.lat;
                const e1 = endPoint.lng;
                const e2 = endPoint.lat;

                // Simple logic: Control point is somewhat perpendicular to the midpoint
                const m1 = (c1 + e1) / 2;
                const m2 = (c2 + e2) / 2;
                // Add some curvature based on distance
                const curveFactor = 5;
                const controlPoint = [m1, m2 + curveFactor]; 

                // AMap BezierCurve path format: [ [startLng, startLat], [controlLng, controlLat, endLng, endLat] ]
                // Note: JSAPI 2.0 BezierCurve expects path as: [start, [control1, end]] or [start, [control1, control2, end]]
                // For quadratic: start -> control -> end

                const path = [
                    [c1, c2], // Start
                    [m1, m2 + (Math.abs(c1 - e1) * 0.2), e1, e2] // Control point & End point. Adding curvature based on longitude diff
                ];

                const bezier = new AMap.BezierCurve({
                    path: path,
                    isOutline: false,
                    outlineColor: '#ffeeff',
                    borderWeight: 1,
                    strokeColor: "#00ff00", // Bright Green like the requested image
                    strokeOpacity: 0.8,
                    strokeWeight: 2,
                    strokeStyle: "solid",
                    strokeDasharray: [10, 10],
                    lineCap: 'round',
                    zIndex: 50,
                });

                mapInstance.add(bezier);

                // Add City Marker
                const marker = new AMap.Marker({
                    position: endPoint,
                    content: `<div style="display:flex; flex-direction:column; align-items:center;">
                        <div style="background:#fbbf24; width:10px; height:10px; border-radius:50%; box-shadow: 0 0 8px #fbbf24; border: 1.5px solid white;"></div>
                        <span style="font-size:10px; color:${theme.mode === 'dark' ? '#cbd5e1' : '#334155'}; text-shadow: 0 0 2px white; margin-top:2px;">${city.name.split(' ')[0]}</span>
                    </div>`,
                    offset: new AMap.Pixel(-5, -5),
                    zIndex: 60
                });
                mapInstance.add(marker);
            });

            // 3. Add Legend
            const legend = document.createElement('div');
            legend.style.position = 'absolute';
            legend.style.top = '20px';
            legend.style.left = '20px';
            legend.style.backgroundColor = theme.mode === 'dark' ? 'rgba(30, 41, 59, 0.9)' : 'rgba(255, 255, 255, 0.9)';
            legend.style.padding = '15px';
            legend.style.borderRadius = '8px';
            legend.style.boxShadow = '0 4px 6px -1px rgba(0, 0, 0, 0.1)';
            legend.style.zIndex = '100';
            legend.innerHTML = `
                <h4 style="margin:0 0 10px 0; font-size:14px; font-weight:bold; color:${theme.mode === 'dark' ? 'white' : 'black'}">全国用户分布</h4>
                <div style="display:flex; align-items:center; margin-bottom:5px;">
                    <span style="display:inline-block; width:12px; height:12px; background:red; border-radius:50%; margin-right:8px; border:2px solid white;"></span>
                    <span style="font-size:12px; color:${theme.mode === 'dark' ? '#cbd5e1' : '#64748b'}">运营中心 (Hub)</span>
                </div>
                <div style="display:flex; align-items:center;">
                    <span style="display:inline-block; width:10px; height:10px; background:#fbbf24; border-radius:50%; margin-right:8px; border:2px solid white;"></span>
                    <span style="font-size:12px; color:${theme.mode === 'dark' ? '#cbd5e1' : '#64748b'}">活跃区域 (Active)</span>
                </div>
            `;
            document.getElementById('map-container')?.appendChild(legend);


            mapInstanceRef.current = mapInstance;
            setMap(mapInstance);

            clearTimeout(timeoutId);

        } catch (initErr: any) {
            console.error("Map Init Error:", initErr);
            setError('地图初始化失败: ' + initErr.message);
            setIsLoading(false);
            loadingRef.current = false;
        }
      })
      .catch((e) => {
        if (!isMounted) return;
        setError('加载脚本失败。请确认 Key 配置正确。');
        setIsLoading(false);
        loadingRef.current = false;
        clearTimeout(timeoutId);
      });

    return () => {
      isMounted = false;
      clearTimeout(timeoutId);
      if (mapInstanceRef.current) {
        mapInstanceRef.current.destroy();
        mapInstanceRef.current = null;
      }
    };
  }, [isKeySet, apiKey, securityCode, theme.mode]);

  const handleSaveKeys = () => {
    if (securityCode.trim() && apiKey.trim()) {
      localStorage.setItem('amap_security_code', securityCode.trim());
      localStorage.setItem('amap_api_key', apiKey.trim());
      window.location.reload();
    }
  };

  const handleReset = () => {
      localStorage.removeItem('amap_security_code');
      localStorage.removeItem('amap_api_key');
      window.location.reload();
  };

  return (
    <div className="relative h-[calc(100vh-8rem)] w-full overflow-hidden rounded-xl border border-gray-200 shadow-sm z-0 dark:border-slate-700 flex flex-col bg-white dark:bg-slate-800">

       <div className={`border-b border-gray-200 bg-white dark:bg-slate-800 dark:border-slate-700 transition-all duration-300 ${isConfigOpen ? 'h-auto p-6 shadow-md z-20' : 'h-12 z-20'}`}>
            <div 
                className="flex items-center justify-between cursor-pointer h-full"
                onClick={() => setIsConfigOpen(!isConfigOpen)}
            >
                <div className="flex items-center gap-2">
                    <Settings className="h-4 w-4 text-gray-500" />
                    <span className="font-semibold text-sm text-gray-700 dark:text-gray-200">{t('mapConfig')}</span>
                </div>
                <div className="flex items-center gap-3">
                    <span className="text-xs text-gray-400 font-mono hidden sm:inline">{isKeySet ? `Key: ${apiKey.slice(0,4)}...` : '未配置'}</span>
                    {isKeySet && (
                        <button onClick={(e) => { e.stopPropagation(); handleReset(); }} className="text-xs text-red-500 hover:underline px-2">{t('resetKeys')}</button>
                    )}
                    {isConfigOpen ? <ChevronUp className="h-4 w-4" /> : <ChevronDown className="h-4 w-4" />}
                </div>
            </div>

            {isConfigOpen && (
                <div className="mt-4 animate-fade-in">
                    <div className="grid gap-6 sm:grid-cols-2">
                        <div>
                            <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">{t('accessKey')} (JSAPI)</label>
                            <input type="text" value={apiKey} onChange={(e) => setApiKey(e.target.value)} className="block w-full rounded-lg border border-gray-300 p-2.5 text-sm dark:bg-slate-700 dark:border-slate-600 dark:text-white" />
                        </div>
                        <div>
                            <label className="mb-1 block text-sm font-medium text-gray-700 dark:text-gray-300">{t('securityCode')}</label>
                            <input type="password" value={securityCode} onChange={(e) => setSecurityCode(e.target.value)} className="block w-full rounded-lg border border-gray-300 p-2.5 text-sm dark:bg-slate-700 dark:border-slate-600 dark:text-white" />
                        </div>
                    </div>
                    <div className="mt-6 flex justify-between items-center">
                        <p className="text-xs text-gray-500">保存后自动刷新</p>
                        <button onClick={handleSaveKeys} className="bg-[var(--color-primary)] text-white px-8 py-2.5 rounded-lg text-sm font-medium hover:opacity-90">{isKeySet ? '保存并重载' : t('loadMap')}</button>
                    </div>
                </div>
            )}
       </div>

       {isKeySet && !error ? (
           <div className="flex-1 w-full bg-slate-100 dark:bg-slate-800 relative z-10">
               <div id="map-container" className="w-full h-full" ref={mapContainerRef}></div>
               {isLoading && (
                   <div className="absolute inset-0 flex items-center justify-center bg-white/80 dark:bg-slate-900/80 z-20 backdrop-blur-sm">
                       <div className="flex flex-col items-center">
                           <RefreshCw className="h-10 w-10 animate-spin text-[var(--color-primary)] mb-4" />
                           <span className="text-sm font-semibold text-gray-700 dark:text-gray-200">正在加载可视化地图...</span>
                       </div>
                   </div>
               )}
           </div>
       ) : (
        <div className="flex-1 flex items-center justify-center bg-gray-50 dark:bg-slate-900 p-6 z-10">
            <div className="text-center max-w-lg">
                <Shield className="h-16 w-16 text-gray-300 mx-auto mb-4" />
                <h3 className="text-xl font-bold text-gray-700 dark:text-gray-300">{error ? '加载失败' : t('mapNotConfigured')}</h3>
                {error && <p className="mt-4 p-4 bg-red-50 text-red-600 rounded-lg text-sm">{error}</p>}
                {!error && <div className="mt-8 flex justify-center"><button onClick={() => setIsConfigOpen(true)} className="bg-[var(--color-primary)] text-white px-6 py-2 rounded-lg hover:opacity-90 shadow-sm">{t('openConfig')}</button></div>}
            </div>
        </div>
       )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  BarChart, Bar, PieChart, Pie, Cell, Legend 
} from 'recharts';
import { Users, Eye, Activity, TrendingUp, Plus, X, DollarSign, ShoppingBag, Calendar, Trophy, Star, Award, Crown, Zap } from 'lucide-react';
import { useApp } from '../contexts/AppContext';
import { DashboardStat, User } from '../types';
import { userService } from '../services/userService';
import { authService } from '../services/authService';

const initialStats: DashboardStat[] = [
  { id: '1', title: 'totalUsers', value: '12,345', iconName: 'Users', color: 'text-blue-600 bg-blue-600' },
  { id: '2', title: 'totalVisits', value: '84,231', iconName: 'Eye', color: 'text-green-600 bg-green-600' },
  { id: '3', title: 'systemStatus', value: '98.5%', iconName: 'Activity', color: 'text-purple-600 bg-purple-600' },
  { id: '4', title: 'growthRate', value: '+12.5%', iconName: 'TrendingUp', color: 'text-orange-600 bg-orange-600' },
];

const visitData = [
  { name: 'Mon', visits: 4000 },
  { name: 'Tue', visits: 3000 },
  { name: 'Wed', visits: 2000 },
  { name: 'Thu', visits: 2780 },
  { name: 'Fri', visits: 1890 },
  { name: 'Sat', visits: 2390 },
  { name: 'Sun', visits: 3490 },
];

const growthData = [
  { name: 'Jan', users: 400 },
  { name: 'Feb', users: 600 },
  { name: 'Mar', users: 800 },
  { name: 'Apr', users: 1200 },
  { name: 'May', users: 1500 },
  { name: 'Jun', users: 1800 },
];

const deviceData = [
  { name: 'Desktop', value: 65 },
  { name: 'Mobile', value: 25 },
  { name: 'Tablet', value: 10 },
];

const COLORS = ['#3b82f6', '#10b981', '#f59e0b'];

const IconMap = {
    Users, Eye, Activity, TrendingUp, DollarSign, ShoppingBag
};

export const Dashboard: React.FC = () => {
  const { t, user, refreshUser } = useApp();
  const [stats, setStats] = useState<DashboardStat[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newStat, setNewStat] = useState({ title: '', value: '', icon: 'Activity', color: 'blue' });

  // Check-in State
  const [isCheckedIn, setIsCheckedIn] = useState(false);
  const [earnedPoints, setEarnedPoints] = useState(0);
  const [showAnimation, setShowAnimation] = useState(false);

  // Leaderboard State
  const [leaderboardUsers, setLeaderboardUsers] = useState<User[]>([]);

  useEffect(() => {
      const saved = localStorage.getItem('dashboard_stats');
      if (saved) {
          setStats(JSON.parse(saved));
      } else {
          setStats(initialStats);
      }

      // Load Leaderboard Data
      const allUsers = userService.getUsers();
      // Sort by points desc, take top 5
      const topUsers = [...allUsers]
        .sort((a, b) => (b.points || 0) - (a.points || 0))
        .slice(0, 5);
      setLeaderboardUsers(topUsers);

  }, []);

  // Check check-in status
  useEffect(() => {
      if (user?.lastCheckIn) {
          const today = new Date().toLocaleDateString('zh-CN');
          if (user.lastCheckIn === new Date().toISOString().split('T')[0]) {
              setIsCheckedIn(true);
          }
      }
  }, [user]);

  const handleCheckIn = () => {
      if (!user || isCheckedIn) return;

      const points = Math.floor(Math.random() * 20) + 1; // Random 1-20
      const today = new Date().toISOString().split('T')[0];

      const updatedUser = {
          ...user,
          points: (user.points || 0) + points,
          lastCheckIn: today
      };

      userService.saveUser(updatedUser);
      authService.updateUser(updatedUser); // Update context
      refreshUser();

      setEarnedPoints(points);
      setIsCheckedIn(true);
      setShowAnimation(true);
      setTimeout(() => setShowAnimation(false), 3000);

      // Refresh leaderboard locally
      const allUsers = userService.getUsers();
      const topUsers = [...allUsers].sort((a, b) => (b.points || 0) - (a.points || 0)).slice(0, 5);
      setLeaderboardUsers(topUsers);
  };

  const saveStats = (newStats: DashboardStat[]) => {
      setStats(newStats);
      localStorage.setItem('dashboard_stats', JSON.stringify(newStats));
  };

  const handleAddStat = () => {
      const colorMap: any = {
          blue: 'text-blue-600 bg-blue-600',
          green: 'text-green-600 bg-green-600',
          purple: 'text-purple-600 bg-purple-600',
          orange: 'text-orange-600 bg-orange-600',
          red: 'text-red-600 bg-red-600',
      };

      const stat: DashboardStat = {
          id: Date.now().toString(),
          title: newStat.title,
          value: newStat.value,
          iconName: newStat.icon as any,
          color: colorMap[newStat.color]
      };

      saveStats([...stats, stat]);
      setIsModalOpen(false);
      setNewStat({ title: '', value: '', icon: 'Activity', color: 'blue' });
  };

  const removeStat = (id: string) => {
      saveStats(stats.filter(s => s.id !== id));
  };

  // Rank Logic
  const getRankInfo = (points: number = 0) => {
      if (points >= 600) return { title: 'rankSvip', color: 'from-amber-500 to-red-600', text: 'text-amber-600', icon: Trophy, next: 1500 };
      if (points >= 300) return { title: 'rankVip', color: 'from-purple-500 to-indigo-600', text: 'text-purple-600', icon: Star, next: 600 };
      if (points >= 100) return { title: 'rankNormal', color: 'from-blue-400 to-blue-600', text: 'text-blue-600', icon: Award, next: 300 };
      return { title: 'rankNewbie', color: 'from-gray-400 to-gray-600', text: 'text-gray-600', icon: Users, next: 100 };
  };

  const currentPoints = user?.points || 0;
  const rank = getRankInfo(currentPoints);
  const progress = Math.min(100, (currentPoints / rank.next) * 100);

  return (
    <div className="space-y-6">
      {/* Check-in & Rank Card */}
      <div className="relative overflow-hidden rounded-2xl bg-white p-0 shadow-sm border border-gray-100 dark:bg-slate-800 dark:border-slate-700">
         <div className={`h-2 bg-gradient-to-r ${rank.color}`}></div>
         <div className="p-6 flex flex-col md:flex-row items-center justify-between gap-6">
             <div className="flex items-center gap-4">
                 <div className={`h-16 w-16 rounded-full bg-gradient-to-br ${rank.color} flex items-center justify-center text-white shadow-lg`}>
                    <rank.icon className="h-8 w-8" />
                 </div>
                 <div>
                     <div className="flex items-center gap-2">
                         <h2 className="text-xl font-bold text-gray-900 dark:text-white">{t(rank.title as any)}</h2>
                         {showAnimation && <span className="text-sm font-bold text-orange-500 animate-bounce">+{earnedPoints} {t('points')}</span>}
                     </div>
                     <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                        {t('points')}: <span className={`font-bold ${rank.text}`}>{currentPoints}</span> 
                        <span className="mx-2">|</span>
                        {t('nextLevel')}: {rank.next}
                     </p>
                     {/* Progress Bar */}
                     <div className="mt-2 h-2 w-48 rounded-full bg-gray-100 dark:bg-slate-700 overflow-hidden">
                         <div className={`h-full rounded-full bg-gradient-to-r ${rank.color}`} style={{ width: `${progress}%` }}></div>
                     </div>
                 </div>
             </div>

             <div className="flex-shrink-0">
                 <button
                    onClick={handleCheckIn}
                    disabled={isCheckedIn}
                    className={`
                        relative overflow-hidden group flex items-center gap-2 px-8 py-3 rounded-xl font-bold shadow-md transition-all
                        ${isCheckedIn 
                            ? 'bg-gray-100 text-gray-400 cursor-not-allowed dark:bg-slate-700 dark:text-gray-500' 
                            : `bg-gradient-to-r ${rank.color} text-white hover:opacity-90 hover:scale-105 hover:shadow-lg`
                        }
                    `}
                 >
                    {isCheckedIn ? (
                        <>
                            <CheckCircleIcon className="h-5 w-5" />
                            {t('alreadyCheckedIn')}
                        </>
                    ) : (
                        <>
                            <Calendar className="h-5 w-5" />
                            {t('dailyCheckIn')}
                            <div className="absolute inset-0 -translate-x-full group-hover:animate-[shimmer_1.5s_infinite] bg-gradient-to-r from-transparent via-white/30 to-transparent z-10"></div>
                        </>
                    )}
                 </button>
                 {!isCheckedIn && <p className="text-xs text-center text-gray-400 mt-2">{t('checkInReward')}</p>}
             </div>
         </div>
      </div>

      <div className="flex justify-between items-center">
        <h2 className="text-lg font-semibold dark:text-white">{t('overview')}</h2>
        <button 
            onClick={() => setIsModalOpen(true)}
            className="flex items-center gap-2 bg-[var(--color-primary)] text-white px-3 py-1.5 rounded-lg text-sm hover:opacity-90"
        >
            <Plus className="h-4 w-4" />
            {t('addWidget')}
        </button>
      </div>

      <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-4">
        {stats.map((stat) => {
            const Icon = IconMap[stat.iconName] || Activity;
            const displayTitle = ['totalUsers', 'totalVisits', 'systemStatus', 'growthRate'].includes(stat.title) 
                ? t(stat.title as any) 
                : stat.title;

            return (
                <div key={stat.id} className="relative group rounded-xl bg-white p-6 shadow-sm border border-gray-100 transition-all hover:shadow-md dark:bg-slate-800 dark:border-slate-700">
                    <button 
                        onClick={() => removeStat(stat.id)}
                        className="absolute top-2 right-2 p-1 text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                        <X className="h-4 w-4" />
                    </button>
                    <div className="flex items-center justify-between">
                    <div>
                        <p className="text-sm font-medium text-gray-500 dark:text-gray-400">{displayTitle}</p>
                        <h3 className="mt-2 text-2xl font-bold text-gray-900 dark:text-white">{stat.value}</h3>
                    </div>
                    <div className={`rounded-full p-3 ${stat.color} bg-opacity-10`}>
                        <Icon className={`h-6 w-6 ${stat.color.replace('bg-', 'text-')}`} />
                    </div>
                    </div>
                </div>
            );
        })}
      </div>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
        {/* Line Chart */}
        <div className="rounded-xl bg-white p-6 shadow-sm border border-gray-100 dark:bg-slate-800 dark:border-slate-700 lg:col-span-2">
          <h3 className="mb-4 text-lg font-semibold text-gray-800 dark:text-white">{t('weeklyTraffic')}</h3>
          <div className="h-80 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={visitData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e5e7eb" className="dark:opacity-20" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#6b7280'}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#6b7280'}} />
                <Tooltip 
                  contentStyle={{ backgroundColor: 'var(--color-bg-popover)', borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)' }} 
                />
                <Line type="monotone" dataKey="visits" stroke="var(--color-primary)" strokeWidth={3} dot={{r: 4}} activeDot={{r: 8}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Leaderboard - Replaces User Growth or sits alongside */}
        <div className="rounded-xl bg-white p-0 shadow-sm border border-gray-100 dark:bg-slate-800 dark:border-slate-700 overflow-hidden flex flex-col">
          <div className="p-6 border-b border-gray-100 dark:border-slate-700 bg-gradient-to-r from-red-500 to-orange-500">
             <div className="flex items-center gap-2 text-white">
                 <Trophy className="h-6 w-6" />
                 <h3 className="text-lg font-bold">积分风云榜</h3>
             </div>
             <p className="text-red-100 text-xs mt-1">Top 5 Active Users</p>
          </div>
          <div className="flex-1 overflow-y-auto p-2">
             {leaderboardUsers.map((u, index) => {
                 const rankInfo = getRankInfo(u.points);
                 return (
                     <div key={u.id} className="flex items-center gap-3 p-3 hover:bg-gray-50 dark:hover:bg-slate-700 rounded-lg transition-colors border-b border-gray-50 last:border-0 dark:border-slate-700">
                         <div className={`
                             w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm shrink-0
                             ${index === 0 ? 'bg-yellow-100 text-yellow-600 ring-2 ring-yellow-200' : 
                               index === 1 ? 'bg-gray-100 text-gray-600 ring-2 ring-gray-200' :
                               index === 2 ? 'bg-orange-100 text-orange-600 ring-2 ring-orange-200' :
                               'text-gray-400'
                             }
                         `}>
                             {index + 1}
                         </div>
                         <div className="relative shrink-0">
                            <img src={u.avatar || 'https://ui-avatars.com/api/?name=' + u.username} className="w-10 h-10 rounded-full bg-gray-200" alt="avatar" />
                            {index === 0 && <Crown className="absolute -top-2 -right-1 h-4 w-4 text-yellow-500 fill-yellow-400 rotate-12" />}
                         </div>
                         <div className="flex-1 min-w-0">
                             <p className="font-semibold text-gray-900 dark:text-white truncate">{u.nickname || u.username}</p>
                             <div className="flex items-center gap-1 mt-0.5">
                                 <span className={`text-[10px] px-1.5 py-0.5 rounded border ${
                                     rankInfo.title === 'rankSvip' ? 'bg-amber-100 text-amber-700 border-amber-200' :
                                     rankInfo.title === 'rankVip' ? 'bg-purple-100 text-purple-700 border-purple-200' :
                                     'bg-gray-100 text-gray-600 border-gray-200'
                                 }`}>
                                     {t(rankInfo.title as any)}
                                 </span>
                             </div>
                         </div>
                         <div className="text-right">
                             <p className="font-bold text-[var(--color-primary)]">{u.points || 0}</p>
                             <p className="text-[10px] text-gray-400">PTS</p>
                         </div>
                     </div>
                 );
             })}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-6 lg:grid-cols-3">
        {/* Pie Chart */}
        <div className="rounded-xl bg-white p-6 shadow-sm border border-gray-100 lg:col-span-1 dark:bg-slate-800 dark:border-slate-700">
          <h3 className="mb-4 text-lg font-semibold text-gray-800 dark:text-white">{t('deviceDist')}</h3>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={deviceData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {deviceData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend verticalAlign="bottom" height={36}/>
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="rounded-xl bg-white p-6 shadow-sm border border-gray-100 lg:col-span-2 dark:bg-slate-800 dark:border-slate-700">
            <h3 className="mb-4 text-lg font-semibold text-gray-800 dark:text-white">{t('recentActivity')}</h3>
            <div className="space-y-4">
                {[1, 2, 3].map((i) => (
                    <div key={i} className="flex items-center space-x-4 border-b border-gray-50 pb-4 last:border-0 dark:border-slate-700">
                        <div className="h-10 w-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold text-sm dark:bg-blue-900/30 dark:text-blue-400">
                            U{i}
                        </div>
                        <div className="flex-1">
                            <p className="text-sm font-medium text-gray-900 dark:text-white">{t('newUserReg')}</p>
                            <p className="text-xs text-gray-500 dark:text-gray-400">2 {t('hoursAgo')}</p>
                        </div>
                        <span className="text-xs font-medium text-green-600 bg-green-50 px-2 py-1 rounded dark:bg-green-900/30 dark:text-green-400">{t('success')}</span>
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Add Widget Modal */}
      {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
              <div className="w-full max-w-sm rounded-xl bg-white p-6 shadow-xl dark:bg-slate-800">
                  <div className="flex justify-between items-center mb-4">
                      <h3 className="font-bold dark:text-white">{t('addCustomWidget')}</h3>
                      <button onClick={() => setIsModalOpen(false)}><X className="h-5 w-5 text-gray-500" /></button>
                  </div>
                  <div className="space-y-4">
                      <input 
                        className="w-full border p-2 rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white" 
                        placeholder={t('widgetTitle')}
                        value={newStat.title}
                        onChange={e => setNewStat({...newStat, title: e.target.value})}
                      />
                      <input 
                        className="w-full border p-2 rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white" 
                        placeholder={t('widgetValue')}
                        value={newStat.value}
                        onChange={e => setNewStat({...newStat, value: e.target.value})}
                      />
                      <div className="grid grid-cols-2 gap-2">
                        <select 
                            className="border p-2 rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                            value={newStat.icon}
