            <h3 className="mb-4 text-lg font-semibold text-gray-800 dark:text-white">{t('recentActivity')}</h3>
            <div className="space-y-4">
                {[1, 2, 3].map((i) => (
                    <div key={i} className="flex items-center space-x-4 border-b border-gray-50 pb-4 last:border-0 dark:border-slate-700">
                        <div className="h-10 w-10 rounded-full bg-blue-100 flex items-center justify-center text-blue-600 font-bold text-sm dark:bg-blue-900/30 dark:text-blue-400">
                            U{i}
                        </div>
                        <div className="flex-1">
                            <p className="text-sm font-medium text-gray-900 dark:text-white">{t('newUserReg')}</p>
                            <p className="text-xs text-gray-500 dark:text-gray-400">2 {t('hoursAgo')}</p>
                        </div>
                        <span className="text-xs font-medium text-green-600 bg-green-50 px-2 py-1 rounded dark:bg-green-900/30 dark:text-green-400">{t('success')}</span>
                    </div>
                ))}
            </div>
        </div>
      </div>

      {/* Add Widget Modal */}
      {isModalOpen && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black bg-opacity-50 p-4">
              <div className="w-full max-w-sm rounded-xl bg-white p-6 shadow-xl dark:bg-slate-800">
                  <div className="flex justify-between items-center mb-4">
                      <h3 className="font-bold dark:text-white">{t('addCustomWidget')}</h3>
                      <button onClick={() => setIsModalOpen(false)}><X className="h-5 w-5 text-gray-500" /></button>
                  </div>
                  <div className="space-y-4">
                      <input 
                        className="w-full border p-2 rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white" 
                        placeholder={t('widgetTitle')}
                        value={newStat.title}
                        onChange={e => setNewStat({...newStat, title: e.target.value})}
                      />
                      <input 
                        className="w-full border p-2 rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white" 
                        placeholder={t('widgetValue')}
                        value={newStat.value}
                        onChange={e => setNewStat({...newStat, value: e.target.value})}
                      />
                      <div className="grid grid-cols-2 gap-2">
                        <select 
                            className="border p-2 rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                            value={newStat.icon}
                            onChange={e => setNewStat({...newStat, icon: e.target.value})}
                        >
                            {Object.keys(IconMap).map(k => <option key={k} value={k}>{k}</option>)}
                        </select>
                        <select 
                            className="border p-2 rounded dark:bg-slate-700 dark:border-slate-600 dark:text-white"
                            value={newStat.color}
                            onChange={e => setNewStat({...newStat, color: e.target.value})}
                        >
                            <option value="blue">Blue</option>
