      if (points >= 3001) return { title: 'rankVip', color: 'from-purple-500 to-indigo-600', text: 'text-purple-600', icon: Star, next: 6001 };
      if (points >= 1000) return { title: 'rankNormal', color: 'from-blue-400 to-blue-600', text: 'text-blue-600', icon: Award, next: 3001 };
      return { title: 'rankNewbie', color: 'from-gray-400 to-gray-600', text: 'text-gray-600', icon: Users, next: 1000 };
