                 <div className={`h-16 w-16 shrink-0 rounded-full bg-gradient-to-br ${rank.color} flex items-center justify-center text-white shadow-lg`}>
                    <rank.icon className="h-8 w-8" />
                 </div>
                 <div className="flex-1">
