import { ActivityLog, User } from '../types';

const ACTIVITY_STORAGE_KEY = 'admin_dashboard_activities';

export const activityService = {
  getActivities: (): ActivityLog[] => {
    const stored = localStorage.getItem(ACTIVITY_STORAGE_KEY);
    if (!stored) {
      // Mock initial data if empty
      const initialLogs: ActivityLog[] = [
        { id: '1', userId: '1', username: 'admin', userAvatar: '', action: 'login', timestamp: new Date(Date.now() - 1000 * 60 * 30).toISOString(), details: 'System login' },
        { id: '2', userId: '5', username: 'wukong', userAvatar: '', action: 'checkIn', timestamp: new Date(Date.now() - 1000 * 60 * 120).toISOString(), details: 'Daily check-in' },
        { id: '3', userId: '2', username: 'john_doe', userAvatar: '', action: 'update', timestamp: new Date(Date.now() - 1000 * 60 * 60 * 5).toISOString(), details: 'Updated profile' },
      ];
      localStorage.setItem(ACTIVITY_STORAGE_KEY, JSON.stringify(initialLogs));
      return initialLogs;
    }
    return JSON.parse(stored);
  },

  logActivity: (user: User, action: ActivityLog['action'], details?: string) => {
    const activities = activityService.getActivities();
    const newLog: ActivityLog = {
      id: Date.now().toString(),
      userId: user.id,
      username: user.nickname || user.username,
      userAvatar: user.avatar,
      action,
      timestamp: new Date().toISOString(),
      details
    };

    // Keep only last 50 activities
    const updatedActivities = [newLog, ...activities].slice(0, 50);
    localStorage.setItem(ACTIVITY_STORAGE_KEY, JSON.stringify(updatedActivities));
  },

  clearActivities: () => {
    localStorage.removeItem(ACTIVITY_STORAGE_KEY);
  }
};

import { UserProfile } from '../types';
import { userService } from './userService';
import { activityService } from './activityService';

const TOKEN_KEY = 'admin_dashboard_token';
const USER_KEY = 'admin_dashboard_user';

export const authService = {
  login: async (username: string, password: string): Promise<UserProfile | null> => {
    // Mock API delay
    await new Promise(resolve => setTimeout(resolve, 600));

    const user = userService.getUserByUsername(username);

    if (user && user.password === password && user.status === 'active') {
      const token = 'mock-jwt-token-' + Date.now();

      const profile: UserProfile = {
        ...user
      };

      localStorage.setItem(TOKEN_KEY, token);
      localStorage.setItem(USER_KEY, JSON.stringify(profile));

      // Log Activity
      activityService.logActivity(profile, 'login', 'User logged in successfully');

      return profile;
    }
    return null;
  },

  logout: () => {
    // Optional: Log logout before clearing storage if we had the user object available easily here
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(USER_KEY);
  },

  isAuthenticated: (): boolean => {
    return !!localStorage.getItem(TOKEN_KEY);
  },

  getUser: (): UserProfile | null => {
    const userStr = localStorage.getItem(USER_KEY);
    return userStr ? JSON.parse(userStr) : null;
  },

  updateUser: (user: UserProfile) => {
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    // Also update the source of truth in user service
    userService.saveUser(user);
    // Log Activity
    activityService.logActivity(user, 'update', 'User profile updated');
  }
};

