                        { name: '黑龙江', value: 160 },
                        { name: '吉林', value: 150 },
                        { name: '贵州', value: 240 },
                        { name: '河北', value: 310 },
                        { name: '台湾', value: 50 },
                        { name: '香港', value: 400 },
                        { name: '澳门', value: 100 }
                    ]
                },
                {
                    name: 'Top 5',
                    type: 'effectScatter',
                    coordinateSystem: 'geo',
                    data: [
                        { name: '北京', value: [116.407526, 39.90403, 800] },
                        { name: '上海', value: [121.473701, 31.230416, 900] },
                        { name: '广州', value: [113.264385, 23.129112, 1000] },
                        { name: '成都', value: [104.066541, 30.572269, 500] },
                        { name: '杭州', value: [120.15507, 30.274085, 700] }
                    ],
                    symbolSize: function (val: any) {
                        return val[2] / 40;
                    },
                    encode: {
                        value: 2
                    },
                    showEffectOn: 'render',
                    rippleEffect: {
                        brushType: 'stroke'
                    },
                    label: {
                        formatter: '{b}',
                        position: 'right',
                        show: true,
                        color: theme.mode === 'dark' ? '#fff' : '#000'
                    },
                    itemStyle: {
                        color: '#f4e925',
                        shadowBlur: 10,
                        shadowColor: '#333'
                    },
                    zlevel: 1
                }
            ]
        };

        myChart.setOption(option);
    };

    const handleResize = () => {
        chartInstance.current?.resize();
    };

    window.addEventListener('resize', handleResize);

    return () => {
        window.removeEventListener('resize', handleResize);
        chartInstance.current?.dispose();
    };
  }, [theme.mode]);

  return (
    <div className="h-[calc(100vh-8rem)] w-full rounded-xl border border-gray-200 shadow-sm bg-white dark:bg-slate-800 dark:border-slate-700 p-4 relative flex flex-col">
        {loading && (
            <div className="absolute inset-0 flex items-center justify-center bg-white/50 dark:bg-slate-800/50 z-10 backdrop-blur-sm rounded-xl">
