import { AppNotification } from '../types';

const NOTIF_STORAGE_KEY = 'admin_dashboard_notifications';

const INITIAL_NOTIFICATIONS: AppNotification[] = [
  { id: '1', title: 'System Update', message: 'The system has been updated to v2.0.', time: new Date(Date.now() - 1000 * 60 * 60 * 2).toISOString(), read: false, type: 'info' },
  { id: '2', title: 'New User', message: 'User "Tang Monk" registered.', time: new Date(Date.now() - 1000 * 60 * 60 * 5).toISOString(), read: false, type: 'success' },
  { id: '3', title: 'High Traffic', message: 'Server load reached 85%.', time: new Date(Date.now() - 1000 * 60 * 60 * 24).toISOString(), read: false, type: 'warning' },
];

export const notificationService = {
  getNotifications: (): AppNotification[] => {
    const stored = localStorage.getItem(NOTIF_STORAGE_KEY);
    if (!stored) {
      localStorage.setItem(NOTIF_STORAGE_KEY, JSON.stringify(INITIAL_NOTIFICATIONS));
      return INITIAL_NOTIFICATIONS;
    }
    return JSON.parse(stored);
  },

  markAllAsRead: (): AppNotification[] => {
    const notifs = notificationService.getNotifications();
    const updated = notifs.map(n => ({ ...n, read: true }));
    localStorage.setItem(NOTIF_STORAGE_KEY, JSON.stringify(updated));
    return updated;
  },

  addNotification: (notification: Omit<AppNotification, 'id' | 'read' | 'time'>) => {
    const notifs = notificationService.getNotifications();
    const newNotif: AppNotification = {
      ...notification,
      id: Date.now().toString(),
      read: false,
      time: new Date().toISOString()
    };
    const updated = [newNotif, ...notifs].slice(0, 20); // Keep last 20
    localStorage.setItem(NOTIF_STORAGE_KEY, JSON.stringify(updated));
    return updated;
  },

  getUnreadCount: (): number => {
      const notifs = notificationService.getNotifications();
      return notifs.filter(n => !n.read).length;
  }
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { Language, translations } from '../utils/i18n';
import { UserProfile } from '../types';
import { authService } from '../services/authService';

interface ThemeConfig {
  mode: 'light' | 'dark';
  color: string;
}

interface AppContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  theme: ThemeConfig;
  setTheme: (theme: ThemeConfig) => void;
  t: (key: keyof typeof translations['en']) => string;
  user: UserProfile | null;
  setUser: (user: UserProfile | null) => void;
  refreshUser: () => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

// Helper function to darken a hex color
const darkenColor = (hex: string, percent: number) => {
    let num = parseInt(hex.replace("#", ""), 16),
    amt = Math.round(2.55 * percent),
    R = (num >> 16) - amt,
    B = ((num >> 8) & 0x00FF) - amt,
    G = (num & 0x0000FF) - amt;

    return "#" + (0x1000000 + (R<255?R<1?0:R:255)*0x10000 + (B<255?B<1?0:B:255)*0x100 + (G<255?G<1?0:G:255)).toString(16).slice(1);
};

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  // Default to 'zh' for 100% Chinese requirement
  const [language, setLanguage] = useState<Language>('zh');

  // Load saved theme or default
  const [theme, setTheme] = useState<ThemeConfig>(() => {
      const saved = localStorage.getItem('app_theme');
      return saved ? JSON.parse(saved) : { mode: 'light', color: '#2563eb' };
  });

  const [user, setUser] = useState<UserProfile | null>(authService.getUser());

  const refreshUser = () => {
    setUser(authService.getUser());
  };

  useEffect(() => {
    // Persist theme
    localStorage.setItem('app_theme', JSON.stringify(theme));

    // Apply Dark Mode
    if (theme.mode === 'dark') {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }

    // Apply Primary Color
    const root = document.documentElement;
    root.style.setProperty('--color-primary', theme.color);

    // Calculate a hover color (darken by 10%)
    try {
        const hoverColor = darkenColor(theme.color, 15);
        root.style.setProperty('--color-primary-hover', hoverColor); 
    } catch (e) {
        // Fallback if color parsing fails
        root.style.setProperty('--color-primary-hover', theme.color);
    }

  }, [theme]);

  const t = (key: keyof typeof translations['en']) => {
    return translations[language][key] || key;
  };

  return (
    <AppContext.Provider value={{ language, setLanguage, theme, setTheme, t, user, setUser, refreshUser }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useApp must be used within AppProvider');
  return context;
};

import React, { useState, useEffect } from 'react';
import { Outlet, useNavigate, useLocation } from 'react-router-dom';
