                                            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1 line-clamp-2">{notif.message}</p>
                                        </div>
                                    </div>
                                </div>
                            )) : (
                                <div className="p-6 text-center text-gray-400 text-sm">
