    'Suzhou': { id: '101190401', lat: 31.2989, lon: 120.5853, cnName: '苏州' },
};

// WMO Weather interpretation codes (OpenMeteo)
const getWeatherCondition = (code: number): { text: string, icon: string } => {
    if (code === 0) return { text: 'Sunny', icon: '01d' };
    if (code >= 1 && code <= 3) return { text: 'Cloudy', icon: '03d' };
    if (code >= 45 && code <= 48) return { text: 'Fog', icon: '50d' };
    if (code >= 51 && code <= 67) return { text: 'Rain', icon: '09d' };
    if (code >= 71 && code <= 77) return { text: 'Snow', icon: '13d' };
    if (code >= 80 && code <= 82) return { text: 'Showers', icon: '09d' };
    if (code >= 95 && code <= 99) return { text: 'Thunderstorm', icon: '11d' };
    return { text: 'Unknown', icon: '02d' };
};

export const WeatherPage: React.FC = () => {
  const { t } = useApp();
  const [city, setCity] = useState('Beijing');
  const [apiKey, setApiKey] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showConfig, setShowConfig] = useState(false);
  const [dataSource, setDataSource] = useState<'openmeteo' | 'openweathermap'>('openmeteo');
  const [weatherCnLink, setWeatherCnLink] = useState('');

  useEffect(() => {
      const savedKey = localStorage.getItem('weather_api_key');
      if (savedKey) {
          setApiKey(savedKey);
          setDataSource('openweathermap');
      }
      fetchWeather(null, 'Beijing');
  }, []);

  const saveConfig = () => {
      if (apiKey) {
          localStorage.setItem('weather_api_key', apiKey);
          setDataSource('openweathermap');
      } else {
          localStorage.removeItem('weather_api_key');
          setDataSource('openmeteo');
      }
      setShowConfig(false);
      fetchWeather(null, city);
  };

  const fetchWeather = async (e?: React.FormEvent | null, searchCity?: string) => {
    if (e) e.preventDefault();
    const queryCity = searchCity || city;
    setCity(queryCity);
    setLoading(true);
    setError('');
    setWeatherCnLink('');

    // Check if known Chinese city for Weather.com.cn linking
    const knownCity = Object.values(CITY_DB).find(
        c => c.cnName === queryCity || Object.keys(CITY_DB).find(k => k.toLowerCase() === queryCity.toLowerCase()) === c.cnName || 
             Object.keys(CITY_DB).find(k => k.toLowerCase() === queryCity.toLowerCase())
    );

    // Normalize city name key
    let cityKey = Object.keys(CITY_DB).find(k => k.toLowerCase() === queryCity.toLowerCase());
    if(!cityKey && knownCity) {
        // Find key by value if user typed Chinese
        cityKey = Object.keys(CITY_DB).find(key => CITY_DB[key].id === knownCity.id);
    }

    if (cityKey && CITY_DB[cityKey]) {
        setWeatherCnLink(`http://www.weather.com.cn/weather/${CITY_DB[cityKey].id}.shtml`);
    }

    try {
        if (dataSource === 'openmeteo' || !apiKey) {
            // Use Open-Meteo (Free, Real Data)
            // If we have coordinates in DB, use them
            let lat, lon, cityName = queryCity;

            if (cityKey && CITY_DB[cityKey]) {
                lat = CITY_DB[cityKey].lat;
                lon = CITY_DB[cityKey].lon;
                cityName = cityKey; // Use English name for display
            } else {
                // Fallback geocoding (OpenMeteo Geocoding API)
                const geoRes = await axios.get(`https://geocoding-api.open-meteo.com/v1/search?name=${queryCity}&count=1&language=en&format=json`);
                if (geoRes.data.results && geoRes.data.results.length > 0) {
                    lat = geoRes.data.results[0].latitude;
                    lon = geoRes.data.results[0].longitude;
                    cityName = geoRes.data.results[0].name;
                } else {
                    throw new Error('City not found');
                }
            }

            const res = await axios.get(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current=temperature_2m,relative_humidity_2m,weather_code,wind_speed_10m`);
            const current = res.data.current;
            const condition = getWeatherCondition(current.weather_code);

            setWeather({
                city: cityName,
                temp: Math.round(current.temperature_2m),
                condition: condition.text,
                icon: `https://openweathermap.org/img/wn/${condition.icon}@4x.png`, // Reuse icons
                humidity: current.relative_humidity_2m,
                windSpeed: current.wind_speed_10m
            });

        } else {
            // OpenWeatherMap
            const response = await axios.get(`https://api.openweathermap.org/data/2.5/weather?q=${queryCity}&units=metric&appid=${apiKey}`);
            const data = response.data;
            setWeather({
                city: data.name,
                temp: Math.round(data.main.temp),
                condition: data.weather[0].main,
                icon: `https://openweathermap.org/img/wn/${data.weather[0].icon}@4x.png`,
                humidity: data.main.humidity,
                windSpeed: data.wind.speed
            });
        }
    } catch (err) {
        console.error(err);
        setError('Failed to fetch weather data. Please check the city name.');
    } finally {
        setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
      <div className="rounded-2xl bg-white p-6 shadow-sm border border-gray-100 dark:bg-slate-800 dark:border-slate-700">
        <div className="flex justify-between items-center mb-6">
            <h2 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <ThermometerSun className="h-6 w-6 text-[var(--color-primary)]" />
                {t('weatherForecast')}
            </h2>
            <button 
                onClick={() => setShowConfig(!showConfig)}
                className="text-gray-400 hover:text-[var(--color-primary)] transition-colors p-2 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-full"
                title="API Settings"
            >
                <Settings className="h-5 w-5" />
            </button>
        </div>

        {showConfig && (
            <div className="mb-6 p-4 bg-gray-50 rounded-xl dark:bg-slate-700/50 border border-gray-100 dark:border-slate-600 transition-all animate-fade-in">
                <label className="block text-xs font-bold text-gray-500 dark:text-gray-300 uppercase mb-2 tracking-wide">
                    Weather Provider
                </label>
                <div className="space-y-3">
                    <div className="flex gap-2">
                         <input
                            type="text"
                            value={apiKey}
                            onChange={(e) => setApiKey(e.target.value)}
                            placeholder="OpenWeatherMap API Key (Optional)"
                            className="flex-1 rounded-lg border border-gray-300 p-2 text-sm dark:bg-slate-600 dark:border-slate-500 dark:text-white focus:ring-2 focus:ring-[var(--color-primary)] outline-none"
                        />
                        <button onClick={saveConfig} className="bg-[var(--color-primary)] text-white px-4 py-2 rounded-lg text-sm font-medium hover:opacity-90">
                            {t('save')}
                        </button>
                    </div>
                    <p className="text-xs text-gray-400">
                        Default: <strong>Open-Meteo</strong> (Free, No Key). Enter an OpenWeatherMap key to switch provider.
                    </p>
                </div>
            </div>
        )}

        <form onSubmit={(e) => fetchWeather(e)} className="flex gap-3">
            <div className="relative flex-1 group">
                <Search className="absolute left-3 top-3 h-5 w-5 text-gray-400 group-focus-within:text-[var(--color-primary)] transition-colors" />
                <input
                type="text"
                value={city}
                onChange={(e) => setCity(e.target.value)}
                placeholder={t('enterCity')}
                className="block w-full rounded-xl border border-gray-300 pl-10 p-3 dark:bg-slate-700 dark:border-slate-600 dark:text-white focus:outline-none focus:ring-2 focus:ring-[var(--color-primary)]/50 focus:border-[var(--color-primary)] transition-all"
                />
