};

// WMO Weather interpretation codes (OpenMeteo) - Localized to Chinese
const getWeatherCondition = (code: number): { text: string, icon: string } => {
    if (code === 0) return { text: '晴', icon: '01d' };
    if (code >= 1 && code <= 3) return { text: '多云', icon: '03d' };
    if (code >= 45 && code <= 48) return { text: '雾', icon: '50d' };
    if (code >= 51 && code <= 67) return { text: '雨', icon: '09d' };
    if (code >= 71 && code <= 77) return { text: '雪', icon: '13d' };
    if (code >= 80 && code <= 82) return { text: '阵雨', icon: '09d' };
    if (code >= 95 && code <= 99) return { text: '雷雨', icon: '11d' };
    return { text: '未知', icon: '02d' };
};

export const WeatherPage: React.FC = () => {
  const { t } = useApp();
  const [city, setCity] = useState('北京'); // Default to Chinese
  const [apiKey, setApiKey] = useState('');
  const [weather, setWeather] = useState<WeatherData | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showConfig, setShowConfig] = useState(false);
  const [dataSource, setDataSource] = useState<'openmeteo' | 'openweathermap'>('openmeteo');
  const [weatherCnLink, setWeatherCnLink] = useState('');

  useEffect(() => {
      const savedKey = localStorage.getItem('weather_api_key');
      if (savedKey) {
          setApiKey(savedKey);
          setDataSource('openweathermap');
      }
      fetchWeather(null, '北京');
  }, []);

  const saveConfig = () => {
      if (apiKey) {
          localStorage.setItem('weather_api_key', apiKey);
          setDataSource('openweathermap');
      } else {
          localStorage.removeItem('weather_api_key');
          setDataSource('openmeteo');
      }
      setShowConfig(false);
      fetchWeather(null, city);
  };

  const fetchWeather = async (e?: React.FormEvent | null, searchCity?: string) => {
    if (e) e.preventDefault();
    const queryCity = searchCity || city;
    setCity(queryCity);
    setLoading(true);
    setError('');
    setWeatherCnLink('');

    // Check if known Chinese city for Weather.com.cn linking
    const knownCity = Object.values(CITY_DB).find(
        c => c.cnName === queryCity || Object.keys(CITY_DB).find(k => k.toLowerCase() === queryCity.toLowerCase()) === c.cnName || 
             Object.keys(CITY_DB).find(k => k.toLowerCase() === queryCity.toLowerCase())
    );

    // Normalize city name key
    let cityKey = Object.keys(CITY_DB).find(k => k.toLowerCase() === queryCity.toLowerCase());
    if(!cityKey && knownCity) {
        // Find key by value if user typed Chinese
        cityKey = Object.keys(CITY_DB).find(key => CITY_DB[key].id === knownCity.id);
    }

    if (cityKey && CITY_DB[cityKey]) {
        setWeatherCnLink(`http://www.weather.com.cn/weather/${CITY_DB[cityKey].id}.shtml`);
    }

    try {
        if (dataSource === 'openmeteo' || !apiKey) {
            // Use Open-Meteo (Free, Real Data)
            // If we have coordinates in DB, use them
            let lat, lon, cityName = queryCity;

            if (cityKey && CITY_DB[cityKey]) {
                lat = CITY_DB[cityKey].lat;
                lon = CITY_DB[cityKey].lon;
                cityName = CITY_DB[cityKey].cnName; // Use Chinese name for display
            } else {
                // Fallback geocoding (OpenMeteo Geocoding API) - Request Chinese results
                const geoRes = await axios.get(`https://geocoding-api.open-meteo.com/v1/search?name=${queryCity}&count=1&language=zh&format=json`);
                if (geoRes.data.results && geoRes.data.results.length > 0) {
                    lat = geoRes.data.results[0].latitude;
                    lon = geoRes.data.results[0].longitude;
                    cityName = geoRes.data.results[0].name;
                } else {
                    throw new Error('未找到该城市');
                }
            }

            const res = await axios.get(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current=temperature_2m,relative_humidity_2m,weather_code,wind_speed_10m`);
            const current = res.data.current;
            const condition = getWeatherCondition(current.weather_code);

            setWeather({
                city: cityName,
                temp: Math.round(current.temperature_2m),
                condition: condition.text,
                icon: `https://openweathermap.org/img/wn/${condition.icon}@4x.png`, // Reuse icons
                humidity: current.relative_humidity_2m,
                windSpeed: current.wind_speed_10m
            });

        } else {
            // OpenWeatherMap - Request Simplified Chinese
            const response = await axios.get(`https://api.openweathermap.org/data/2.5/weather?q=${queryCity}&units=metric&lang=zh_cn&appid=${apiKey}`);
            const data = response.data;
            setWeather({
                city: data.name,
                temp: Math.round(data.main.temp),
                condition: data.weather[0].description, // description is localized with lang=zh_cn
                icon: `https://openweathermap.org/img/wn/${data.weather[0].icon}@4x.png`,
                humidity: data.main.humidity,
                windSpeed: data.wind.speed
            });
        }
    } catch (err) {
        console.error(err);
        setError('获取天气数据失败，请检查城市名称。');
    } finally {
        setLoading(false);
    }
  };

  return (
    <div className="max-w-3xl mx-auto space-y-6">
