                title="API 设置"
            >
                <Settings className="h-5 w-5" />
            </button>
        </div>

        {showConfig && (
            <div className="mb-6 p-4 bg-gray-50 rounded-xl dark:bg-slate-700/50 border border-gray-100 dark:border-slate-600 transition-all animate-fade-in">
                <label className="block text-xs font-bold text-gray-500 dark:text-gray-300 uppercase mb-2 tracking-wide">
                    天气数据源
                </label>
                <div className="space-y-3">
                    <div className="flex gap-2">
                         <input
                            type="text"
                            value={apiKey}
                            onChange={(e) => setApiKey(e.target.value)}
                            placeholder="OpenWeatherMap API Key (选填)"
                            className="flex-1 rounded-lg border border-gray-300 p-2 text-sm dark:bg-slate-600 dark:border-slate-500 dark:text-white focus:ring-2 focus:ring-[var(--color-primary)] outline-none"
                        />
                        <button onClick={saveConfig} className="bg-[var(--color-primary)] text-white px-4 py-2 rounded-lg text-sm font-medium hover:opacity-90">
                            {t('save')}
                        </button>
                    </div>
                    <p className="text-xs text-gray-400">
                        默认: <strong>Open-Meteo</strong> (免费, 无需 Key). 输入 OpenWeatherMap Key 可切换数据源.
                    </p>
                </div>
            </div>
        )}

        <form onSubmit={(e) => fetchWeather(e)} className="flex gap-3">
            <div className="relative flex-1 group">
                <Search className="absolute left-3 top-3 h-5 w-5 text-gray-400 group-focus-within:text-[var(--color-primary)] transition-colors" />
                <input
                type="text"
                value={city}
                onChange={(e) => setCity(e.target.value)}
                placeholder={t('enterCity')}
                className="block w-full rounded-xl border border-gray-300 pl-10 p-3 dark:bg-slate-700 dark:border-slate-600 dark:text-white focus:outline-none focus:ring-2 focus:ring-[var(--color-primary)]/50 focus:border-[var(--color-primary)] transition-all"
                />
            </div>
            <button
                type="submit"
                disabled={loading}
                className="rounded-xl bg-[var(--color-primary)] px-6 py-2 text-white font-medium hover:opacity-90 disabled:opacity-50 shadow-lg shadow-blue-500/20 active:scale-95 transition-all"
            >
                {loading ? '...' : t('search')}
            </button>
        </form>

        <div className="mt-4 flex flex-wrap gap-2">
            {Object.keys(CITY_DB).slice(0, 8).map(key => {
                const item = CITY_DB[key];
                return (
                    <button 
                        key={key}
                        onClick={() => { setCity(item.cnName); fetchWeather(null, item.cnName); }}
                        className="text-xs bg-gray-100 dark:bg-slate-700 text-gray-600 dark:text-gray-300 px-3 py-1 rounded-full hover:bg-[var(--color-primary)] hover:text-white transition-colors"
                    >
                        {item.cnName}
                    </button>
                )
            })}
        </div>

        {error && (
            <div className="mt-4 p-3 bg-red-50 text-red-600 text-sm rounded-lg text-center border border-red-100 dark:bg-red-900/20 dark:border-red-800 dark:text-red-400">
                {error}
            </div>
        )}
      </div>

      {weather && (
        <div className="relative overflow-hidden rounded-3xl bg-gradient-to-br from-[#4facfe] to-[#00f2fe] p-8 text-white shadow-xl animate-fade-in group">
          <div className="absolute -top-10 -right-10 p-4 opacity-10 group-hover:scale-110 transition-transform duration-700">
              <Cloud className="h-64 w-64" />
          </div>

          <div className="relative z-10 flex flex-col items-center justify-between sm:flex-row">
            <div>
              <div className="flex items-center gap-2 mb-1">
                  <MapPin className="h-5 w-5 opacity-80" />
                  <h2 className="text-3xl font-bold tracking-tight">{weather.city}</h2>
                  {weatherCnLink && (
                      <a 
                        href={weatherCnLink} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="ml-2 bg-white/20 hover:bg-white/30 text-xs px-2 py-1 rounded-md flex items-center gap-1 transition-colors backdrop-blur-sm"
