          <div className="mt-8 grid grid-cols-2 gap-4 border-t border-white/20 pt-8 relative z-10">
            <div className="flex items-center gap-4 bg-white/10 p-4 rounded-2xl backdrop-blur-sm hover:bg-white/20 transition-colors">
