// WMO Weather interpretation codes (OpenMeteo) - Localized to Chinese
const getWeatherCondition = (code: number): { text: string, icon: string } => {
    if (code === 0) return { text: '晴', icon: '01d' };
    if (code >= 1 && code <= 3) return { text: '多云', icon: '03d' };
    if (code >= 45 && code <= 48) return { text: '雾', icon: '50d' };
    if (code >= 51 && code <= 67) return { text: '雨', icon: '09d' };
    if (code >= 71 && code <= 77) return { text: '雪', icon: '13d' };
    if (code >= 80 && code <= 82) return { text: '阵雨', icon: '09d' };
    if (code >= 95 && code <= 99) return { text: '雷雨', icon: '11d' };
    return { text: '未知', icon: '02d' };
};

export const WeatherPage: React.FC = () => {
  const { t } = useApp();
  const [searchCity, setSearchCity] = useState(''); 
  const [apiKey, setApiKey] = useState('');
  const [weatherList, setWeatherList] = useState<WeatherData[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [showConfig, setShowConfig] = useState(false);
  const [dataSource, setDataSource] = useState<'openmeteo' | 'openweathermap'>('openmeteo');

  useEffect(() => {
      const savedKey = localStorage.getItem('weather_api_key');
      if (savedKey) {
          setApiKey(savedKey);
          setDataSource('openweathermap');
      }
      loadRandomCities();
  }, []);

  const saveConfig = () => {
      if (apiKey) {
          localStorage.setItem('weather_api_key', apiKey);
          setDataSource('openweathermap');
      } else {
          localStorage.removeItem('weather_api_key');
          setDataSource('openmeteo');
      }
      setShowConfig(false);
      loadRandomCities(); // Refresh with new source
  };

  const loadRandomCities = async () => {
      setLoading(true);
      setError('');

      // Select 9 random cities from DB
      const keys = Object.keys(CITY_DB);
      const shuffled = keys.sort(() => 0.5 - Math.random());
      const selectedKeys = shuffled.slice(0, 9);

      try {
        const promises = selectedKeys.map(key => fetchCityData(CITY_DB[key].cnName));
        const results = await Promise.all(promises);
        setWeatherList(results.filter((w): w is WeatherData => w !== null));
      } catch (e) {
          setError('加载天气数据失败，请重试');
      } finally {
          setLoading(false);
      }
  };

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchCity.trim()) return;

    setLoading(true);
    try {
        const data = await fetchCityData(searchCity);
        if (data) {
            // Add to top of list, remove duplicate if exists
            setWeatherList(prev => {
                const filtered = prev.filter(item => item.city !== data.city);
                return [data, ...filtered];
            });
            setSearchCity('');
        } else {
            setError('未找到该城市或获取失败');
        }
    } catch (e) {
        setError('搜索失败');
    } finally {
        setLoading(false);
    }
  };

  const fetchCityData = async (queryCity: string): Promise<WeatherData | null> => {
    // Check if known Chinese city
    const knownCity = Object.values(CITY_DB).find(
        c => c.cnName === queryCity || Object.keys(CITY_DB).find(k => k.toLowerCase() === queryCity.toLowerCase()) === c.cnName
    );

    // Normalize city name key for CITY_DB lookup
    let cityKey = Object.keys(CITY_DB).find(k => k.toLowerCase() === queryCity.toLowerCase());
    if(!cityKey && knownCity) {
        cityKey = Object.keys(CITY_DB).find(key => CITY_DB[key].id === knownCity.id);
    }

    try {
        if (dataSource === 'openmeteo' || !apiKey) {
            let lat, lon, cityName = queryCity;

            if (cityKey && CITY_DB[cityKey]) {
                lat = CITY_DB[cityKey].lat;
                lon = CITY_DB[cityKey].lon;
                cityName = CITY_DB[cityKey].cnName;
            } else {
                // Fallback geocoding 
                const geoRes = await axios.get(`https://geocoding-api.open-meteo.com/v1/search?name=${queryCity}&count=1&language=zh&format=json`);
                if (geoRes.data.results && geoRes.data.results.length > 0) {
                    lat = geoRes.data.results[0].latitude;
                    lon = geoRes.data.results[0].longitude;
                    cityName = geoRes.data.results[0].name;
                } else {
                    return null;
                }
            }

            const res = await axios.get(`https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current=temperature_2m,relative_humidity_2m,weather_code,wind_speed_10m`);
            const current = res.data.current;
            const condition = getWeatherCondition(current.weather_code);

            return {
                city: cityName,
                temp: Math.round(current.temperature_2m),
                condition: condition.text,
                icon: `https://openweathermap.org/img/wn/${condition.icon}@4x.png`,
                humidity: current.relative_humidity_2m,
                windSpeed: current.wind_speed_10m
            };

        } else {
            // OpenWeatherMap
            const response = await axios.get(`https://api.openweathermap.org/data/2.5/weather?q=${queryCity}&units=metric&lang=zh_cn&appid=${apiKey}`);
            const data = response.data;
            return {
                city: data.name,
                temp: Math.round(data.main.temp),
                condition: data.weather[0].description,
                icon: `https://openweathermap.org/img/wn/${data.weather[0].icon}@4x.png`,
                humidity: data.main.humidity,
                windSpeed: data.wind.speed
            };
        }
    } catch (err) {
        console.error("Fetch weather error", err);
        return null;
    }
  };

  // Helper to get color gradient based on temperature
  const getTempColor = (temp: number) => {
      if (temp >= 35) return 'from-orange-500 to-red-600';
      if (temp >= 28) return 'from-orange-400 to-orange-500';
      if (temp >= 20) return 'from-blue-400 to-green-400';
      if (temp >= 10) return 'from-blue-500 to-blue-400';
      return 'from-blue-600 to-blue-800';
  };

  const getCityLink = (cityName: string) => {
     // Reverse lookup in DB
     const key = Object.keys(CITY_DB).find(k => CITY_DB[k].cnName === cityName);
     if (key && CITY_DB[key]) {
         return `http://www.weather.com.cn/weather/${CITY_DB[key].id}.shtml`;
     }
     return null;
  };

  return (
    <div className="mx-auto space-y-6">
      <div className="rounded-2xl bg-white p-6 shadow-sm border border-gray-100 dark:bg-slate-800 dark:border-slate-700">
        <div className="flex justify-between items-center mb-6 flex-wrap gap-4">
            <h2 className="text-xl font-bold text-gray-800 dark:text-white flex items-center gap-2">
                <ThermometerSun className="h-6 w-6 text-[var(--color-primary)]" />
                {t('weatherForecast')}
            </h2>
            <div className="flex items-center gap-2">
                <button 
                    onClick={loadRandomCities}
                    className="flex items-center gap-2 px-3 py-1.5 text-sm bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 dark:bg-slate-700 dark:text-gray-300 dark:hover:bg-slate-600 transition-colors"
                >
                    <RefreshCw className={`h-4 w-4 ${loading ? 'animate-spin' : ''}`} />
                    换一批
                </button>
                <button 
                    onClick={() => setShowConfig(!showConfig)}
                    className="text-gray-400 hover:text-[var(--color-primary)] transition-colors p-2 hover:bg-gray-100 dark:hover:bg-slate-700 rounded-full"
                    title="API 设置"
                >
                    <Settings className="h-5 w-5" />
                </button>
            </div>
        </div>

        {showConfig && (
            <div className="mb-6 p-4 bg-gray-50 rounded-xl dark:bg-slate-700/50 border border-gray-100 dark:border-slate-600 transition-all animate-fade-in">
                <label className="block text-xs font-bold text-gray-500 dark:text-gray-300 uppercase mb-2 tracking-wide">
                    天气数据源
                </label>
                <div className="space-y-3">
                    <div className="flex gap-2">
                         <input
                            type="text"
                            value={apiKey}
                            onChange={(e) => setApiKey(e.target.value)}
                            placeholder="OpenWeatherMap API Key (选填)"
                            className="flex-1 rounded-lg border border-gray-300 p-2 text-sm dark:bg-slate-600 dark:border-slate-500 dark:text-white focus:ring-2 focus:ring-[var(--color-primary)] outline-none"
                        />
                        <button onClick={saveConfig} className="bg-[var(--color-primary)] text-white px-4 py-2 rounded-lg text-sm font-medium hover:opacity-90">
                            {t('save')}
                        </button>
                    </div>
                </div>
            </div>
        )}

        <form onSubmit={handleSearch} className="flex gap-3 relative max-w-lg">
            <div className="relative flex-1 group">
                <Search className="absolute left-3 top-3 h-5 w-5 text-gray-400 group-focus-within:text-[var(--color-primary)] transition-colors" />
                <input
                type="text"
                value={searchCity}
                onChange={(e) => setSearchCity(e.target.value)}
                placeholder="输入城市名，添加至列表 (如: 拉萨)"
                className="block w-full rounded-xl border border-gray-300 pl-10 p-3 dark:bg-slate-700 dark:border-slate-600 dark:text-white focus:outline-none focus:ring-2 focus:ring-[var(--color-primary)]/50 focus:border-[var(--color-primary)] transition-all"
                />
            </div>
            <button
                type="submit"
                disabled={loading}
                className="rounded-xl bg-[var(--color-primary)] px-6 py-2 text-white font-medium hover:opacity-90 disabled:opacity-50 shadow-lg shadow-blue-500/20 active:scale-95 transition-all"
            >
                {loading ? '...' : <Plus className="h-5 w-5" />}
            </button>
        </form>

        {error && (
            <div className="mt-4 p-3 bg-red-50 text-red-600 text-sm rounded-lg text-center border border-red-100 dark:bg-red-900/20 dark:border-red-800 dark:text-red-400">
                {error}
            </div>
        )}
      </div>

      {/* Grid Layout for Weather Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {weatherList.map((weather, idx) => {
            const link = getCityLink(weather.city);
            return (
