                                <p className="mt-1 text-blue-50 font-medium">{weather.condition}</p>
                            </div>
                            <div className="flex flex-col items-center">
                                <img src={weather.icon} alt={weather.condition} className="h-16 w-16 drop-shadow-lg" />
                                {link && (
                                    <a 
