// Generate random traffic lines from other cities to specific hubs
const generateLinesData = (hubs: string[]) => {
    const lines: any[] = [];
    const cities = Object.keys(CHINA_CITIES);

    cities.forEach(fromCity => {
        if (Math.random() > 0.7) { // 30% chance to have a line
            const targetHub = hubs[Math.floor(Math.random() * hubs.length)];
            if (fromCity !== targetHub) {
                 lines.push({
                    fromName: fromCity,
                    toName: targetHub,
                    coords: [CHINA_CITIES[fromCity], CHINA_CITIES[targetHub]],
                    value: Math.floor(Math.random() * 100)
                });
            }
        }
    });
    return lines;
};

interface LogItem {
    id: string;
    city: string;
    action: string;
    time: string;
}

export const MapPage: React.FC = () => {
