  const [logs, setLogs] = useState<LogItem[]>([]);
  const timerRef = useRef<number | null>(null);

  // Real-time data simulation
  useEffect(() => {
    const actions = ['登录成功', '提交订单', '新用户注册', '文件上传', 'API 请求'];
    const cities = Object.keys(CHINA_CITIES);

    const interval = setInterval(() => {
        // Update total active users
        setActiveUsers(prev => prev + Math.floor(Math.random() * 10) - 4);

        // Add new log
        const randomCity = cities[Math.floor(Math.random() * cities.length)];
        const randomAction = actions[Math.floor(Math.random() * actions.length)];
        const newLog: LogItem = {
            id: Date.now().toString() + Math.random(),
            city: randomCity,
            action: randomAction,
            time: new Date().toLocaleTimeString()
        };

        setLogs(prev => [newLog, ...prev].slice(0, 8)); // Keep last 8 logs

    }, 2000);

    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    const chinaJsonUrl = 'https://geo.datav.aliyun.com/areas_v3/bound/100000_full.json';

    fetch(chinaJsonUrl)
      .then(response => response.json())
      .then(geoJson => {
        echarts.registerMap('china', geoJson);
        setLoading(false);
        initChart();
      })
      .catch(err => {
        console.error("Failed to load map data", err);
        setLoading(false);
      });

    const initChart = () => {
        if (!chartRef.current) return;

        if (chartInstance.current) {
            chartInstance.current.dispose();
        }

        const myChart = echarts.init(chartRef.current, theme.mode === 'dark' ? 'dark' : undefined);
        chartInstance.current = myChart;

        const updateData = () => {
            const hubs = ['北京', '上海', '深圳', '成都', '武汉'];
            const linesData = generateLinesData(hubs);
            const scatterData = Object.entries(CHINA_CITIES).map(([name, coords]) => ({
                name,
                value: [...coords, Math.floor(Math.random() * 500)]
            }));
            const top5 = scatterData.sort((a, b) => b.value[2] - a.value[2]).slice(0, 5);

            const isDark = theme.mode === 'dark';
            const bgColor = isDark ? 'transparent' : '#f8fafc';
            const areaColor = isDark ? '#1e293b' : '#e2e8f0';
            const borderColor = isDark ? '#334155' : '#cbd5e1';
            const textColor = isDark ? '#fff' : '#1e293b';

            const option: echarts.EChartsOption = {
                backgroundColor: bgColor,
