                        },
                        itemStyle: {
                            color: '#f59e0b',
                            shadowBlur: 10,
                            shadowColor: '#f59e0b'
                        },
                        zlevel: 1
                    },
                    // Lines
                    {
                        type: 'lines',
                        zlevel: 2,
                        effect: {
                            show: true,
                            period: 6,
                            trailLength: 0.7,
                            color: isDark ? '#fff' : '#2563eb',
                            symbolSize: 3
                        },
                        lineStyle: {
                            color: isDark ? '#a78bfa' : '#6366f1',
                            width: 0,
                            curveness: 0.2
                        },
                        data: linesData
                    }
                ]
            };

            myChart.setOption(option);
        };

        updateData();
        // Update map visualization every 5 seconds
        timerRef.current = window.setInterval(updateData, 5000);
    };

    const handleResize = () => {
        chartInstance.current?.resize();
