const HUBS = ['北京', '上海', '深圳', '成都', '武汉'];

interface LogItem {
    id: string;
    city: string;
    action: string;
    time: string;
    level: 'info' | 'warn' | 'error';
}

type ViewMode = 'traffic' | 'servers';

export const MapPage: React.FC = () => {
  const chartRef = useRef<HTMLDivElement>(null);
  const chartInstance = useRef<echarts.ECharts | null>(null);
  const { theme, t } = useApp();
  const [loading, setLoading] = useState(true);
  const [activeUsers, setActiveUsers] = useState(12450);
  const [serverLoad, setServerLoad] = useState(42);
  const [logs, setLogs] = useState<LogItem[]>([]);
  const [viewMode, setViewMode] = useState<ViewMode>('traffic');
  const [selectedCity, setSelectedCity] = useState<string | null>(null);

  // Stats for the selected city
  const [cityStats, setCityStats] = useState({ traffic: 0, health: 100, requests: 0 });

  // Real-time data simulation
  useEffect(() => {
    const actions = [
        { text: '用户登录', level: 'info' },
        { text: '订单创建', level: 'info' },
        { text: '数据同步', level: 'info' },
        { text: '延迟告警', level: 'warn' },
        { text: '节点异常', level: 'error' }
    ];
    const cities = Object.keys(CHINA_CITIES);

    const interval = setInterval(() => {
        // Random Stats Update
        setActiveUsers(prev => prev + Math.floor(Math.random() * 20) - 8);
        setServerLoad(prev => Math.min(100, Math.max(0, prev + Math.floor(Math.random() * 5) - 2)));

        // Add Log
        if (Math.random() > 0.3) {
            const randomCity = cities[Math.floor(Math.random() * cities.length)];
            const randomAction = actions[Math.floor(Math.random() * actions.length)];
            const newLog: LogItem = {
                id: Date.now().toString() + Math.random(),
                city: randomCity,
                action: randomAction.text,
                time: new Date().toLocaleTimeString(),
                level: randomAction.level as any
            };
            setLogs(prev => [newLog, ...prev].slice(0, 10));
        }
    }, 1500);

    return () => clearInterval(interval);
  }, []);

  // Update selected city stats when city changes
  useEffect(() => {
      if (selectedCity) {
          setCityStats({
              traffic: Math.floor(Math.random() * 5000) + 1000,
              health: Math.floor(Math.random() * 20) + 80,
              requests: Math.floor(Math.random() * 20000) + 5000
          });
      }
  }, [selectedCity]);

  // Chart Initialization
  useEffect(() => {
    const chinaJsonUrl = 'https://geo.datav.aliyun.com/areas_v3/bound/100000_full.json';
    let isMounted = true;

    fetch(chinaJsonUrl)
      .then(response => response.json())
      .then(geoJson => {
        if (!isMounted) return;
        echarts.registerMap('china', geoJson);
        setLoading(false);
        initChart();
      })
      .catch(err => {
        console.error("Failed to load map data", err);
        setLoading(false);
      });

    const initChart = () => {
        if (!chartRef.current) return;

        if (chartInstance.current) {
            chartInstance.current.dispose();
        }

        const myChart = echarts.init(chartRef.current, theme.mode === 'dark' ? 'dark' : undefined);
        chartInstance.current = myChart;

        // Click Event
        myChart.on('click', (params) => {
            if (params.componentType === 'series' || params.componentType === 'geo') {
                setSelectedCity(params.name);
            }
        });

        // Click blank to deselect
        myChart.getZr().on('click', (params) => {
            if (!params.target) {
                setSelectedCity(null);
            }
        });

        const updateData = () => {
            if (!chartInstance.current) return;

            const isDark = theme.mode === 'dark';

            // --- Colors & Styles ---
            const styles = {
                bg: isDark ? 'transparent' : 'transparent',
                areaColor: isDark ? '#2c3457' : '#e0e7f3',
                borderColor: isDark ? '#4c60ff' : '#ffffff',
                borderWidth: 1.5,
                hoverColor: isDark ? '#3d4d8a' : '#c4d7f5',
                shadowColor: isDark ? 'rgba(76, 96, 255, 0.5)' : 'rgba(0, 0, 0, 0.1)',
                lineColor: isDark ? '#00eaff' : '#3b82f6',
                pointColor: isDark ? '#ffd700' : '#f59e0b',
                textColor: isDark ? '#fff' : '#1e293b'
            };

            // --- Data Generation ---
            const linesData: any[] = [];
            const scatterData: any[] = [];

            Object.entries(CHINA_CITIES).forEach(([name, data]) => {
                // Scatter Points
                scatterData.push({
                    name,
                    value: [...data.coords, Math.floor(Math.random() * 100)], // [lon, lat, value]
                    itemStyle: {
                        color: data.type === 'hub' ? (isDark ? '#ff0055' : '#ef4444') : styles.pointColor
                    }
                });

                // Lines
                if (viewMode === 'traffic') {
                    if (data.type !== 'hub') {
                        // Connect to nearest Hub (Simplified: Random Hub)
                        const targetHub = HUBS[Math.floor(Math.random() * HUBS.length)];
                        if (name !== targetHub) {
                             linesData.push({
                                fromName: name,
                                toName: targetHub,
                                coords: [data.coords, CHINA_CITIES[targetHub].coords],
                                value: Math.random() * 10
                            });
                        }
                    }
                } else {
                    // Server Mode: Connect Hubs to Hubs
                     if (data.type === 'hub') {
                        HUBS.forEach(h => {
                            if (h !== name && Math.random() > 0.5) {
                                 linesData.push({
                                    fromName: name,
                                    toName: h,
                                    coords: [data.coords, CHINA_CITIES[h].coords],
                                    lineStyle: { type: 'dashed', color: isDark ? '#00ffaa' : '#10b981' }
                                });
                            }
                        })
                    }
                }
            });

            // Top cities for ripple effect
            const topCities = scatterData.filter(d => HUBS.includes(d.name));

            const option: echarts.EChartsOption = {
                backgroundColor: styles.bg,
                tooltip: {
                    trigger: 'item',
                    backgroundColor: isDark ? 'rgba(15, 23, 42, 0.9)' : 'rgba(255, 255, 255, 0.95)',
                    borderColor: styles.borderColor,
                    textStyle: { color: styles.textColor },
                    formatter: (params: any) => {
                        return `<div class="font-bold mb-1">${params.name}</div>
                                <div class="text-xs opacity-80">状态: 在线</div>
                                <div class="text-xs opacity-80">数值: ${params.value[2] || '-'}</div>`;
                    }
                },
                geo: [
                    // Shadow Layer for 3D effect
                    {
                        map: 'china',
                        roam: true,
                        layoutCenter: ['50%', '50%'],
                        layoutSize: '110%',
                        zlevel: 1,
                        itemStyle: {
                            areaColor: isDark ? '#0f172a' : '#cbd5e1',
                            borderColor: 'transparent',
                            shadowColor: isDark ? 'rgba(0,0,0,0.5)' : 'rgba(0,0,0,0.2)',
                            shadowBlur: 20,
                            shadowOffsetX: 8,
                            shadowOffsetY: 8
                        },
                        silent: true
                    },
                    // Main Map Layer
                    {
                        map: 'china',
                        roam: true,
                        layoutCenter: ['50%', '50%'],
                        layoutSize: '110%',
                        zlevel: 2,
                        label: {
                            show: true,
                            color: isDark ? 'rgba(255,255,255,0.4)' : 'rgba(0,0,0,0.4)',
                            fontSize: 10
                        },
                        itemStyle: {
                            areaColor: styles.areaColor,
                            borderColor: styles.borderColor,
                            borderWidth: 1,
                            shadowColor: styles.shadowColor,
                            shadowBlur: 5
                        },
                        emphasis: {
                            itemStyle: {
                                areaColor: styles.hoverColor,
                                shadowBlur: 10
                            },
                            label: { color: styles.textColor }
                        }
                    }
                ],
                series: [
                    // Effect Scatter (Ripples)
                    {
                        type: 'effectScatter',
                        coordinateSystem: 'geo',
                        geoIndex: 1, // Bind to main map
                        zlevel: 4,
                        data: topCities,
                        symbolSize: 12,
                        showEffectOn: 'render',
                        rippleEffect: {
                            brushType: 'stroke',
                            scale: 4,
                            period: 4
                        },
                        itemStyle: {
                            color: isDark ? '#ff0055' : '#ef4444',
                            shadowBlur: 10
                        }
                    },
                    // Normal Scatter
                    {
                        type: 'scatter',
                        coordinateSystem: 'geo',
                        geoIndex: 1,
                        zlevel: 4,
                        data: scatterData.filter(d => !HUBS.includes(d.name)),
                        symbolSize: 6,
                        itemStyle: {
                            color: styles.pointColor,
                            opacity: 0.8
                        }
                    },
                    // Lines
                    {
                        type: 'lines',
                        zlevel: 3,
                        effect: {
                            show: true,
                            period: 4,
                            trailLength: 0.5,
                            color: isDark ? '#fff' : '#2563eb', // Trail color
                            symbol: 'arrow',
                            symbolSize: 4
                        },
                        lineStyle: {
                            color: styles.lineColor,
                            width: 1,
                            opacity: 0.4,
                            curveness: 0.2
                        },
                        data: linesData
                    }
                ]
            };

            myChart.setOption(option);
        };

        updateData();
        const timer = setInterval(updateData, 6000); // Re-generate data every 6s

        return () => clearInterval(timer);
    };

    const handleResize = () => chartInstance.current?.resize();
    window.addEventListener('resize', handleResize);

    return () => {
        isMounted = false;
        window.removeEventListener('resize', handleResize);
        chartInstance.current?.dispose();
    };
  }, [theme.mode, viewMode]); // Re-init when theme or mode changes

  return (
    <div className="relative h-[calc(100vh-8rem)] w-full rounded-2xl border border-gray-200 shadow-xl bg-slate-50 dark:bg-[#0b1121] dark:border-slate-800 overflow-hidden flex flex-col">
        {/* Decorative Grid Background */}
        <div className="absolute inset-0 pointer-events-none" 
             style={{ 
                 backgroundImage: theme.mode === 'dark' 
                    ? 'radial-gradient(#1e293b 1px, transparent 1px)' 
                    : 'radial-gradient(#e2e8f0 1px, transparent 1px)', 
                 backgroundSize: '20px 20px', 
                 opacity: 0.5 
             }}>
        </div>

        {loading && (
            <div className="absolute inset-0 flex items-center justify-center bg-white/50 dark:bg-slate-900/50 z-50 backdrop-blur-sm">
                <div className="flex flex-col items-center">
                    <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-[var(--color-primary)] mb-4"></div>
                    <p className="text-gray-600 dark:text-gray-300 font-mono text-sm animate-pulse">INITIALIZING GEO-DATA...</p>
                </div>
            </div>
        )}

        {/* Top Control Bar */}
        <div className="absolute top-4 left-1/2 -translate-x-1/2 z-30 flex gap-2 p-1.5 bg-white/80 dark:bg-slate-800/80 backdrop-blur-md rounded-full shadow-lg border border-gray-100 dark:border-slate-700">
            <button 
                onClick={() => setViewMode('traffic')}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-medium transition-all ${viewMode === 'traffic' ? 'bg-[var(--color-primary)] text-white shadow-md' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-slate-700'}`}
            >
                <Activity className="h-4 w-4" />
                <span>实时流量</span>
            </button>
            <button 
                onClick={() => setViewMode('servers')}
                className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-sm font-medium transition-all ${viewMode === 'servers' ? 'bg-indigo-500 text-white shadow-md' : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-slate-700'}`}
            >
                <Server className="h-4 w-4" />
                <span>服务器状态</span>
            </button>
        </div>

        {/* Left Stats Panel - Glassmorphism */}
        <div className="absolute top-4 left-4 z-20 space-y-4 w-64">
            <div className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-md p-5 rounded-2xl shadow-lg border border-gray-100 dark:border-slate-700">
                <h3 className="text-xs font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-4 flex items-center gap-2">
                    <Globe className="h-3 w-3" /> 全局监控
                </h3>

                <div className="grid grid-cols-2 gap-4 mb-4">
                     <div className="space-y-1">
                        <p className="text-xs text-gray-500">活跃用户</p>
                        <p className="text-xl font-bold text-gray-900 dark:text-white tabular-nums">{activeUsers.toLocaleString()}</p>
                     </div>
                     <div className="space-y-1">
                        <p className="text-xs text-gray-500">负载率</p>
                        <div className="flex items-center gap-2">
                            <p className={`text-xl font-bold tabular-nums ${serverLoad > 80 ? 'text-red-500' : 'text-green-500'}`}>{serverLoad}%</p>
                            <Activity className={`h-4 w-4 ${serverLoad > 80 ? 'text-red-500 animate-pulse' : 'text-green-500'}`} />
                        </div>
                     </div>
                </div>

                <div className="w-full bg-gray-200 dark:bg-slate-700 rounded-full h-1.5 overflow-hidden">
                    <div className="bg-[var(--color-primary)] h-1.5 rounded-full transition-all duration-500" style={{ width: `${(activeUsers % 100)}%` }}></div>
                </div>
            </div>

             <div className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-md p-0 rounded-2xl shadow-lg border border-gray-100 dark:border-slate-700 overflow-hidden">
                 <div className="p-3 border-b border-gray-100 dark:border-slate-700 bg-gray-50/50 dark:bg-slate-800/50 flex justify-between items-center">
                    <h3 className="text-xs font-bold text-gray-700 dark:text-gray-300 flex items-center gap-2">
                        <Radio className="h-3 w-3 text-red-500 animate-pulse" />
                        系统日志
                    </h3>
                    <span className="text-[10px] bg-gray-200 dark:bg-slate-700 px-1.5 py-0.5 rounded text-gray-500">LIVE</span>
                 </div>
                 <div className="max-h-[180px] overflow-hidden relative">
                    <div className="absolute inset-0 bg-gradient-to-b from-transparent via-transparent to-white/90 dark:to-slate-900/90 pointer-events-none z-10"></div>
                     <div className="p-3 space-y-2.5">
                        {logs.map(log => (
                            <div key={log.id} className="flex items-center gap-3 text-xs animate-fade-in-down">
                                <span className={`w-1.5 h-1.5 rounded-full shrink-0 ${
                                    log.level === 'error' ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.6)]' : 
                                    log.level === 'warn' ? 'bg-amber-500' : 'bg-green-500'
                                }`}></span>
                                <div className="flex-1 min-w-0 flex justify-between">
                                    <span className="text-gray-700 dark:text-gray-300 font-medium truncate">{log.city}</span>
