const HUBS = ['北京', '上海', '深圳', '成都', '武汉'];

interface LogItem {
    id: string;
    city: string;
    action: string;
    time: string;
    level: 'info' | 'warn' | 'error';
    mode: ViewMode;
}

type ViewMode = 'business' | 'infra' | 'security';

export const MapPage: React.FC = () => {
  const chartRef = useRef<HTMLDivElement>(null);
  const chartInstance = useRef<echarts.ECharts | null>(null);
  const { theme } = useApp();
  const [loading, setLoading] = useState(true);

  // View State
  const [viewMode, setViewMode] = useState<ViewMode>('business');
  const [selectedCity, setSelectedCity] = useState<string | null>(null);

  // Data State
  const [activeUsers, setActiveUsers] = useState(12450);
  const [threatLevel, setThreatLevel] = useState(0); // For Security Mode
  const [systemLoad, setSystemLoad] = useState(42); // For Infra Mode
  const [logs, setLogs] = useState<LogItem[]>([]);
  const [trendData, setTrendData] = useState<number[]>(new Array(20).fill(0));

  // --- Real-time Simulation Engine ---
  useEffect(() => {
    const cities = Object.keys(CHINA_CITIES);

    // Log Templates per mode
