            { text: '自动扩容完成', level: 'info' },
            { text: '缓存命中率下降', level: 'warn' },
            { text: '数据库连接池波动', level: 'warn' },
            { text: '服务健康检查: OK', level: 'info' }
        ],
        security: [
            { text: '拦截 SQL 注入攻击', level: 'error' },
            { text: '检测到异常登录', level: 'warn' },
            { text: 'DDoS 流量清洗中', level: 'error' },
            { text: '黑名单 IP 封禁', level: 'info' },
            { text: 'WAF 规则触发', level: 'warn' }
        ]
    };

    const interval = setInterval(() => {
        // 1. Update Metrics based on mode
        if (viewMode === 'business') {
            setActiveUsers(prev => prev + Math.floor(Math.random() * 20) - 8);
        } else if (viewMode === 'infra') {
            setSystemLoad(prev => Math.min(100, Math.max(0, prev + Math.floor(Math.random() * 10) - 4)));
        } else {
            setThreatLevel(prev => Math.floor(Math.random() * 100));
        }

        // 2. Update Trend Data (Sparkline)
        setTrendData(prev => {
            const newVal = Math.floor(Math.random() * 50) + 20;
            return [...prev.slice(1), newVal];
        });

        // 3. Generate Logs
        if (Math.random() > 0.4) {
            const randomCity = cities[Math.floor(Math.random() * cities.length)];
            const templates = logTemplates[viewMode];
            const randomTemplate = templates[Math.floor(Math.random() * templates.length)];

            const newLog: LogItem = {
                id: Date.now().toString() + Math.random(),
                city: randomCity,
                action: randomTemplate.text,
                time: new Date().toLocaleTimeString('zh-CN', { hour12: false }),
                level: randomTemplate.level,
                mode: viewMode
            };
            setLogs(prev => [newLog, ...prev].slice(0, 8));
        }
    }, 1200);

    return () => clearInterval(interval);
  }, [viewMode]);

  // --- ECharts Logic ---
  useEffect(() => {
    const chinaJsonUrl = 'https://geo.datav.aliyun.com/areas_v3/bound/100000_full.json';
    let isMounted = true;

    if (!window.echartsMapData) {
         fetch(chinaJsonUrl)
          .then(response => response.json())
          .then(geoJson => {
            if (!isMounted) return;
            echarts.registerMap('china', geoJson);
            window.echartsMapData = true; // Simple cache flag
            setLoading(false);
            initChart();
          })
          .catch(err => {
            console.error("Map load failed", err);
            setLoading(false);
          });
    } else {
        setLoading(false);
        initChart();
