    const updateChartOption = (chart: echarts.ECharts) => {
        const isDark = theme.mode === 'dark';

        // --- Theme Config ---
        const colors = {
            business: {
                area: isDark ? '#1e293b' : '#e2e8f0',
                line: '#3b82f6',
                point: '#60a5fa',
