            infra: {
                area: isDark ? '#1e1b4b' : '#ede9fe', // darker purple bg
                line: '#a855f7',
                point: '#d8b4fe',
                effect: '#7c3aed'
            },
            security: {
                area: isDark ? '#2a0a0a' : '#fee2e2', // dark red bg
                line: '#ef4444',
                point: '#fca5a5',
                effect: '#dc2626'
