        // --- Data Generation ---
        const linesData: any[] = [];
        const scatterData: any[] = [];

        Object.entries(CHINA_CITIES).forEach(([name, data]) => {
            scatterData.push({
                name,
                value: [...data.coords, Math.floor(Math.random() * 100)],
                itemStyle: { 
                    color: viewMode === 'security' && data.type === 'hub' ? '#ff0000' : colors.point 
                }
