                  placeholder="添加城市..."
                  className="w-full pl-12 pr-4 py-3 rounded-2xl bg-white dark:bg-slate-800 border border-gray-100 dark:border-slate-700 text-gray-900 dark:text-white shadow-sm focus:ring-2 focus:ring-[var(--color-primary)] outline-none transition-all"
              />
              {error && <span className="absolute right-4 top-3.5 text-xs text-red-500 animate-pulse">{error}</span>}
          </form>

          {/* City List */}
          <div className="flex-1 overflow-y-auto space-y-3 custom-scrollbar pr-1">
              {monitoredCities.map((city) => {
                  const info = getWeatherInfo(city.current.code, city.current.isDay);
                  const isActive = activeCity?.city === city.city;
                  return (
                      <div 
                        key={city.city}
                        onClick={() => setActiveCity(city)}
                        className={`
                            relative group cursor-pointer p-4 rounded-2xl border transition-all duration-300
                            ${isActive 
                                ? 'bg-gradient-to-br from-[var(--color-primary)] to-purple-600 text-white shadow-lg scale-[1.02] border-transparent' 
                                : 'bg-white dark:bg-slate-800 border-gray-100 dark:border-slate-700 hover:shadow-md hover:border-[var(--color-primary)]/30'
                            }
                        `}
                      >
                          <div className="flex justify-between items-start">
                              <div>
                                  <h4 className={`font-bold text-lg ${isActive ? 'text-white' : 'text-gray-900 dark:text-white'}`}>{city.cnName}</h4>
                                  <p className={`text-xs ${isActive ? 'text-blue-100' : 'text-gray-500 dark:text-gray-400'}`}>{info.text}</p>
                              </div>
                              <div className="text-right">
                                  <span className={`text-2xl font-bold tracking-tight ${isActive ? 'text-white' : 'text-gray-900 dark:text-white'}`}>{city.current.temp}°</span>
                              </div>
                          </div>

                          <div className="mt-3 flex items-center justify-between">
                              <div className="flex items-center gap-3">
                                  <div className="flex items-center gap-1">
                                      <Droplets className={`h-3 w-3 ${isActive ? 'text-blue-200' : 'text-gray-400'}`} />
                                      <span className={`text-xs ${isActive ? 'text-blue-100' : 'text-gray-500'}`}>{city.current.humidity}%</span>
                                  </div>
                                  <div className="flex items-center gap-1">
                                      <Wind className={`h-3 w-3 ${isActive ? 'text-blue-200' : 'text-gray-400'}`} />
                                      <span className={`text-xs ${isActive ? 'text-blue-100' : 'text-gray-500'}`}>{city.current.windSpeed}m/s</span>
                                  </div>
                              </div>
                              <info.icon className={`h-8 w-8 ${isActive ? 'text-white/80' : 'text-gray-300 dark:text-slate-600'}`} />
                          </div>

                          {!isActive && (
                              <button 
                                onClick={(e) => removeCity(e, city.city)}
                                className="absolute -top-2 -right-2 bg-red-500 text-white rounded-full p-1 opacity-0 group-hover:opacity-100 transition-opacity shadow-sm hover:bg-red-600"
                              >
                                  <X className="h-3 w-3" />
                              </button>
                          )}
                      </div>
                  );
              })}

              {monitoredCities.length === 0 && (
                  <div className="text-center py-10 text-gray-400 text-sm border-2 border-dashed border-gray-200 dark:border-slate-700 rounded-2xl">
                      暂无关注城市<br/>请搜索添加
                  </div>
              )}
          </div>
      </div>

    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import axios from 'axios';
import { 
  Cloud, Search, Droplets, Wind, Settings, MapPin, 
  ThermometerSun, Plus, X, Sun, Moon, CloudRain, CloudSnow, 
  CloudLightning, Eye, Gauge, Navigation, Calendar, RefreshCw 
} from 'lucide-react';
import { 
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer 
} from 'recharts';
import { useApp } from '../contexts/AppContext';

// --- Types & Constants ---

interface HourlyData {
  time: string;
  temp: number;
  code: number;
}

interface DailyData {
  date: string;
  max: number;
  min: number;
  code: number;
}

interface DetailedWeatherData {
  city: string;
  cnName: string;
  current: {
    temp: number;
    condition: string;
    code: number;
    humidity: number;
    windSpeed: number;
    pressure: number;
    feelsLike: number;
    isDay: number;
  };
  hourly: HourlyData[];
  daily: DailyData[];
  updatedAt: number;
}

