    'Chengdu': { lat: 30.5728, lon: 104.0668, cnName: '成都' },
    'Hangzhou': { lat: 30.2741, lon: 120.1551, cnName: '杭州' },
    'Wuhan': { lat: 30.5928, lon: 114.3055, cnName: '武汉' },
    'Xi\'an': { lat: 34.3416, lon: 108.9398, cnName: '西安' },
