import React, { useState, useRef, useEffect } from 'react';
import { authService } from '../services/authService';
import { UserProfile } from '../types';
import { Camera, Save, Lock, AlertCircle } from 'lucide-react';
import { useApp } from '../contexts/AppContext';

export const ProfilePage: React.FC = () => {
  const { user: contextUser, refreshUser, t } = useApp();

  // Local state for profile fields (excluding password)
  const [user, setUser] = useState<UserProfile | null>(contextUser ? { ...contextUser } : null);

  // Separate state for password handling ensures we don't accidentally overwrite it
  const [newPassword, setNewPassword] = useState('');
  const [confirmNewPassword, setConfirmNewPassword] = useState('');

  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync with context if it updates elsewhere
  useEffect(() => {
    if (contextUser) {
        // We only update if the ID matches to prevent weird swaps, 
        // though usually contextUser is stable.
        setUser(prev => prev?.id === contextUser.id ? { ...prev, ...contextUser } : { ...contextUser });
    }
  }, [contextUser]);

  if (!user) return <div>Loading...</div>;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setUser({ ...user, [e.target.name]: e.target.value });
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUser({ ...user, avatar: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (!contextUser) return;
    setError('');
    setMessage('');

    // Password Validation
    if (newPassword) {
        if (newPassword.length < 6) {
            setError('密码长度至少需要6位');
            return;
        }
        if (newPassword !== confirmNewPassword) {
            setError('两次输入的密码不一致');
            return;
        }
    }

    // Construct payload
    const userToSave: UserProfile = { ...user };

    // CRITICAL FIX: 
    // If newPassword is provided, update it.
    // If NOT provided, explicitly ensure we keep the EXISTING password from context.
    // This prevents overwriting the password with "" or undefined.
    if (newPassword) {
        userToSave.password = newPassword;
    } else {
        userToSave.password = contextUser.password;
    }

    authService.updateUser(userToSave);
    refreshUser(); 

    // Reset password fields
    setNewPassword('');
    setConfirmNewPassword('');

    setMessage(t('success') + '!');
    setTimeout(() => setMessage(''), 3000);
  };

  return (
    <div className="max-w-3xl mx-auto bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden dark:bg-slate-800 dark:border-slate-700 transition-all">
      {/* Header Cover */}
      <div className="h-32 bg-gradient-to-r from-[var(--color-primary)] to-purple-600 relative">
          <div className="absolute inset-0 bg-black/10"></div>
      </div>

      <div className="px-8 pb-8">
        {/* Avatar Section */}
        <div className="relative -mt-12 mb-8 flex justify-between items-end">
          <div className="relative group">
            <div className="absolute -inset-0.5 bg-gradient-to-r from-blue-600 to-purple-600 rounded-full opacity-75 group-hover:opacity-100 transition duration-200 blur"></div>
            <img
              src={user.avatar || 'https://ui-avatars.com/api/?name=' + user.username}
              alt="Profile"
              className="relative h-28 w-28 rounded-full border-4 border-white bg-white object-cover shadow-lg dark:border-slate-800 dark:bg-slate-800"
            />
            <button
              onClick={() => fileInputRef.current?.click()}
              className="absolute bottom-1 right-1 rounded-full bg-gray-900 p-2 text-white hover:bg-[var(--color-primary)] transition-colors shadow-lg dark:bg-slate-700"
              title="Change Avatar"
            >
              <Camera className="h-4 w-4" />
            </button>
            <input
              type="file"
              ref={fileInputRef}
              className="hidden"
              accept="image/*"
              onChange={handleImageUpload}
            />
          </div>
          <div className="text-right hidden sm:block mb-2">
              <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300">
                {user.role === 'admin' ? t('admin') : t('user')}
              </span>
          </div>
        </div>

        {/* Form Section */}
        <div className="space-y-8">
          {/* Basic Info */}
          <div className="grid grid-cols-1 gap-6 sm:grid-cols-2">
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">{t('username')}</label>
              <input
                type="text"
                disabled
                value={user.username}
                className="block w-full rounded-lg border border-gray-200 bg-gray-50 px-4 py-2.5 text-gray-500 cursor-not-allowed dark:bg-slate-700/50 dark:border-slate-600 dark:text-gray-400"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">昵称</label>
              <input
                type="text"
