import React, { useState, useEffect } from 'react';
import { userService } from '../services/userService';
import { authService } from '../services/authService';
import { User } from '../types';
import { Search, Plus, Trash2, Edit2, X, Crown, AlertTriangle, Save, Coins, Eye, EyeOff } from 'lucide-react';
import { useApp } from '../contexts/AppContext';

export const UsersPage: React.FC = () => {
  const [users, setUsers] = useState<User[]>([]);
  const [searchTerm, setSearchTerm] = useState('');

  // Edit/Create Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [formData, setFormData] = useState<Partial<User>>({});
  const [showPassword, setShowPassword] = useState(false);

  // Delete Confirmation Modal State
  const [isDeleteModalOpen, setIsDeleteModalOpen] = useState(false);
  const [userToDelete, setUserToDelete] = useState<User | null>(null);

  const { t, user: currentUser, refreshUser } = useApp();

  useEffect(() => {
    loadUsers();
  }, []);

  const loadUsers = () => {
    const freshUsers = userService.getUsers();
    setUsers([...freshUsers]);
  };

  const filteredUsers = users.filter(user => 
    user.username.toLowerCase().includes(searchTerm.toLowerCase()) || 
    user.email.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (user.nickname && user.nickname.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  // --- Handlers ---

  const handleDeleteClick = (user: User) => {
    if (user.username === 'admin') return;
    setUserToDelete(user);
    setIsDeleteModalOpen(true);
  };

  const confirmDelete = () => {
    if (userToDelete) {
      userService.deleteUser(userToDelete.id);
      setIsDeleteModalOpen(false);
      setUserToDelete(null);
      loadUsers();
    }
  };

  const handleOpenModal = (user?: User) => {
    setShowPassword(false); // Reset password view state
    if (user) {
      setEditingUser(user);
      // Clone user data but DO NOT pre-fill password for security and UX
      const { password, ...rest } = user;
      setFormData({ ...rest }); 
    } else {
      setEditingUser(null);
      setFormData({ status: 'active', role: 'user', points: 0 });
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.username) return;

    // Safety check for Super Admin
    const isSuperAdmin = editingUser?.username === 'admin';
    const finalRole = isSuperAdmin ? 'admin' : (formData.role as 'admin' | 'user');
    const finalStatus = isSuperAdmin ? 'active' : (formData.status as 'active' | 'inactive');

    const userToSave: User = {
      id: editingUser ? editingUser.id : '',
      username: formData.username,
      email: formData.email || '', 
      status: finalStatus,
      role: finalRole,
      createdAt: editingUser ? editingUser.createdAt : '',
      // Only update password if formData.password is provided, otherwise keep existing
      password: formData.password || (editingUser ? editingUser.password : '123456'), 
      nickname: formData.nickname || formData.username,
      avatar: formData.avatar || editingUser?.avatar,
      points: Number(formData.points) || 0,
      lastCheckIn: editingUser?.lastCheckIn
    };

    // 1. Save to DB
    userService.saveUser(userToSave);

    // 2. CRITICAL: If we are editing the currently logged-in user, 
    // we MUST update the session storage and global context immediately.
    if (currentUser && currentUser.id === userToSave.id) {
        authService.updateUser(userToSave);
        refreshUser();
    }

    setIsModalOpen(false);
    loadUsers();
  };

  const getRankName = (points: number = 0) => {
      if (points >= 6001) return t('rankSvip');
      if (points >= 3001) return t('rankVip');
      if (points >= 1000) return t('rankNormal');
      return t('rankNewbie');
  };

  const getRankColor = (points: number = 0) => {
      if (points >= 6001) return 'text-amber-600 bg-amber-100 border-amber-200';
      if (points >= 3001) return 'text-purple-600 bg-purple-100 border-purple-200';
      if (points >= 1000) return 'text-blue-600 bg-blue-100 border-blue-200';
      return 'text-gray-600 bg-gray-100 border-gray-200';
  };

  return (
    <div className="space-y-6">
      {/* Header Actions */}
      <div className="flex flex-col justify-between gap-4 sm:flex-row sm:items-center">
        <div className="relative">
          <Search className="absolute left-3 top-2.5 h-5 w-5 text-gray-400" />
          <input
            type="text"
            placeholder={t('search')}
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="w-full rounded-lg border border-gray-300 pl-10 p-2 focus:border-[var(--color-primary)] focus:ring-[var(--color-primary)] sm:w-64 dark:bg-slate-800 dark:border-slate-700 dark:text-white"
          />
        </div>
        <button
          onClick={() => handleOpenModal()}
          className="flex items-center justify-center rounded-lg bg-[var(--color-primary)] px-4 py-2 text-sm font-medium text-white hover:opacity-90 transition-opacity"
        >
          <Plus className="mr-2 h-4 w-4" />
          {t('addUser')}
        </button>
      </div>

      {/* Table */}
      <div className="overflow-hidden rounded-xl border border-gray-200 bg-white shadow-sm dark:bg-slate-800 dark:border-slate-700">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-gray-500 dark:text-gray-400">
            <thead className="bg-gray-50 text-xs uppercase text-gray-700 dark:bg-slate-700 dark:text-gray-200">
              <tr>
                <th className="px-6 py-3">{t('user')}</th>
                <th className="px-6 py-3">{t('points')}</th>
                <th className="px-6 py-3">{t('role')}</th>
                <th className="px-6 py-3">{t('status')}</th>
