import React, { useState, useRef, useEffect } from 'react';
import { authService } from '../services/authService';
import { UserProfile } from '../types';
import { Camera, Save, Lock, AlertCircle, Eye, EyeOff } from 'lucide-react';
import { useApp } from '../contexts/AppContext';

export const ProfilePage: React.FC = () => {
  const { user: contextUser, refreshUser, t } = useApp();

  // Local state for profile fields (excluding password)
  const [user, setUser] = useState<UserProfile | null>(contextUser ? { ...contextUser } : null);

  // Separate state for password handling ensures we don't accidentally overwrite it
  const [newPassword, setNewPassword] = useState('');
  const [confirmNewPassword, setConfirmNewPassword] = useState('');
  const [showNewPassword, setShowNewPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const [message, setMessage] = useState('');
  const [error, setError] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Sync with context if it updates elsewhere
  useEffect(() => {
    if (contextUser) {
        // We only update if the ID matches to prevent weird swaps, 
        // though usually contextUser is stable.
        setUser(prev => prev?.id === contextUser.id ? { ...prev, ...contextUser } : { ...contextUser });
    }
  }, [contextUser]);

  if (!user) return <div>Loading...</div>;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setUser({ ...user, [e.target.name]: e.target.value });
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setUser({ ...user, avatar: reader.result as string });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (!contextUser) return;
    setError('');
    setMessage('');

    // Password Validation
    if (newPassword) {
        if (newPassword.length < 6) {
            setError('密码长度至少需要6位');
            return;
        }
        if (newPassword !== confirmNewPassword) {
            setError('两次输入的密码不一致');
            return;
        }
    }

    // Construct payload
    const userToSave: UserProfile = { ...user };

    // CRITICAL FIX: 
    // If newPassword is provided, update it.
    // If NOT provided, explicitly ensure we keep the EXISTING password from context.
    // This prevents overwriting the password with "" or undefined.
    if (newPassword) {
        userToSave.password = newPassword;
    } else {
        userToSave.password = contextUser.password;
    }

    authService.updateUser(userToSave);
    refreshUser(); 

    // Reset password fields
    setNewPassword('');
    setConfirmNewPassword('');

    setMessage(t('success') + '!');
    setTimeout(() => setMessage(''), 3000);
  };

  return (
    <div className="max-w-3xl mx-auto bg-white rounded-2xl shadow-xl border border-gray-100 overflow-hidden dark:bg-slate-800 dark:border-slate-700 transition-all">
      {/* Header Cover */}
      <div className="h-32 bg-gradient-to-r from-[var(--color-primary)] to-purple-600 relative">
          <div className="absolute inset-0 bg-black/10"></div>
      </div>

      <div className="px-8 pb-8">
        {/* Avatar Section */}
        <div className="relative -mt-12 mb-8 flex justify-between items-end">
          <div className="relative group">
            <div className="absolute -inset-0.5 bg-gradient-to-r from-blue-600 to-purple-600 rounded-full opacity-75 group-hover:opacity-100 transition duration-200 blur"></div>
            <img
              src={user.avatar || 'https://ui-avatars.com/api/?name=' + user.username}
              alt="Profile"
              className="relative h-28 w-28 rounded-full border-4 border-white bg-white object-cover shadow-lg dark:border-slate-800 dark:bg-slate-800"
            />
            <button
              onClick={() => fileInputRef.current?.click()}
              className="absolute bottom-1 right-1 rounded-full bg-gray-900 p-2 text-white hover:bg-[var(--color-primary)] transition-colors shadow-lg dark:bg-slate-700"
              title="Change Avatar"
            >
              <Camera className="h-4 w-4" />
            </button>
            <input
              type="file"
              ref={fileInputRef}
              className="hidden"
              accept="image/*"
              onChange={handleImageUpload}
            />
          </div>
          <div className="text-right hidden sm:block mb-2">
              <span className="inline-flex items-center px-3 py-1 rounded-full text-xs font-medium bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300">
                {user.role === 'admin' ? t('admin') : t('user')}
              </span>
          </div>
        </div>

        {/* Form Section */}
        <div className="space-y-8">
          {/* Basic Info */}
          <div className="grid grid-cols-1 gap-6 sm:grid-cols-2">
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">{t('username')}</label>
              <input
                type="text"
                disabled
                value={user.username}
                className="block w-full rounded-lg border border-gray-200 bg-gray-50 px-4 py-2.5 text-gray-500 cursor-not-allowed dark:bg-slate-700/50 dark:border-slate-600 dark:text-gray-400"
              />
            </div>
            <div>
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">昵称</label>
              <input
                type="text"
                name="nickname"
                value={user.nickname || ''}
                onChange={handleChange}
                placeholder="如何称呼您"
                className="block w-full rounded-lg border border-gray-300 px-4 py-2.5 focus:border-[var(--color-primary)] focus:ring-2 focus:ring-[var(--color-primary)]/20 outline-none transition-all dark:bg-slate-700 dark:border-slate-600 dark:text-white"
              />
            </div>
            <div className="sm:col-span-2">
              <label className="block text-sm font-semibold text-gray-700 dark:text-gray-300 mb-2">Email</label>
              <input
                type="email"
                name="email"
                value={user.email}
                onChange={handleChange}
                placeholder="您的邮箱地址"
                className="block w-full rounded-lg border border-gray-300 px-4 py-2.5 focus:border-[var(--color-primary)] focus:ring-2 focus:ring-[var(--color-primary)]/20 outline-none transition-all dark:bg-slate-700 dark:border-slate-600 dark:text-white"
              />
            </div>
          </div>

          {/* Security Section */}
          <div className="border-t border-gray-100 pt-6 dark:border-slate-700">
            <h4 className="text-base font-bold text-gray-900 mb-6 flex items-center gap-2 dark:text-white">
                <Lock className="h-4 w-4 text-[var(--color-primary)]" />
                {t('changePassword')}
            </h4>
            <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 bg-gray-50 dark:bg-slate-800/50 p-6 rounded-xl border border-gray-100 dark:border-slate-700">
                 <div className="sm:col-span-2">
                    <p className="text-xs text-gray-500 mb-2 dark:text-gray-400 flex items-center gap-1">
                        <AlertCircle className="h-3 w-3" />
                        如无需修改密码，请留空
                    </p>
                 </div>
                 <div>
                     <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 mb-1.5 uppercase">{t('newPassword')}</label>
                     <div className="relative">
                        <input
                            type={showNewPassword ? "text" : "password"}
                            value={newPassword}
                            onChange={(e) => setNewPassword(e.target.value)}
                            placeholder="输入新密码"
                            className="block w-full rounded-lg border border-gray-300 px-4 py-2 focus:border-[var(--color-primary)] focus:ring-2 focus:ring-[var(--color-primary)]/20 outline-none transition-all dark:bg-slate-700 dark:border-slate-600 dark:text-white pr-10"
                        />
                        <button
                            type="button"
                            onClick={() => setShowNewPassword(!showNewPassword)}
                            className="absolute right-3 top-2.5 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200"
                        >
                            {showNewPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
                        </button>
                     </div>
                 </div>
                 <div>
                     <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 mb-1.5 uppercase">{t('confirmPassword')}</label>
                     <div className="relative">
                        <input
                            type={showConfirmPassword ? "text" : "password"}
                            value={confirmNewPassword}
                            onChange={(e) => setConfirmNewPassword(e.target.value)}
                            placeholder="再次输入新密码"
                            className={`block w-full rounded-lg border px-4 py-2 outline-none transition-all dark:bg-slate-700 dark:text-white pr-10
                                ${newPassword && confirmNewPassword && newPassword !== confirmNewPassword 
                                    ? 'border-red-300 focus:border-red-500 focus:ring-red-200 dark:border-red-800' 
                                    : 'border-gray-300 focus:border-[var(--color-primary)] focus:ring-[var(--color-primary)]/20 dark:border-slate-600'
                                }
                            `}
                        />
                        <button
                            type="button"
                            onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                            className="absolute right-3 top-2.5 text-gray-400 hover:text-gray-600 dark:hover:text-gray-200"
                        >
                            {showConfirmPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
                        </button>
                     </div>
                 </div>
            </div>
          </div>

          {/* Actions */}
          <div className="flex items-center justify-end pt-4 gap-4">
            {error && <span className="text-sm text-red-500 font-medium animate-pulse">{error}</span>}
            {message && <span className="text-sm text-green-600 font-medium animate-fade-in">{message}</span>}
            <button
              onClick={handleSave}
              className="flex items-center rounded-lg bg-[var(--color-primary)] px-8 py-2.5 text-sm font-bold text-white hover:opacity-90 shadow-lg shadow-blue-500/30 hover:shadow-blue-500/40 transform hover:-translate-y-0.5 transition-all"
            >
              <Save className="mr-2 h-4 w-4" />
              {t('saveChanges')}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import { authService } from '../services/authService';
import { userService } from '../services/userService';
import { Lock, User as UserIcon, AlertCircle, Eye, EyeOff, ArrowRight, LayoutDashboard, Check, AlertTriangle } from 'lucide-react';
import { RoutePath, User } from '../types';
import { useApp } from '../contexts/AppContext';

export const Login: React.FC = () => {
