  const { setUser, t } = useApp();

  // Form State
  const [username, setUsername] = useState('admin');
  const [password, setPassword] = useState('123456');
  const [showPassword, setShowPassword] = useState(false);

  // UI State
  const [loginStatus, setLoginStatus] = useState<'idle' | 'loading' | 'success' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [capsLockOn, setCapsLockOn] = useState(false);
  const [matchedUser, setMatchedUser] = useState<User | undefined>(undefined);

  // Refs
  const containerRef = useRef<HTMLDivElement>(null);

  // Effect: User Lookup
  useEffect(() => {
    const user = userService.getUserByUsername(username);
    setMatchedUser(user);
  }, [username]);

  // Effect: Caps Lock Detection
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.getModifierState && e.getModifierState('CapsLock')) {
        setCapsLockOn(true);
      } else {
        setCapsLockOn(false);
      }
    };
    window.addEventListener('keydown', handleKey);
    window.addEventListener('keyup', handleKey);
    return () => {
        window.removeEventListener('keydown', handleKey);
        window.removeEventListener('keyup', handleKey);
    };
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setErrorMessage('');
    setLoginStatus('loading');

    try {
      // Artificial delay for premium feel & to show loading state clearly
      await new Promise(resolve => setTimeout(resolve, 800));

      const userProfile = await authService.login(username, password);

      if (userProfile) {
        setLoginStatus('success');
        setUser(userProfile);

        // Wait a brief moment to show the success checkmark
        setTimeout(() => {
            navigate(RoutePath.DASHBOARD);
        }, 600);
      } else {
        setLoginStatus('error');
        setErrorMessage('用户名或密码错误');
        // Reset to idle after shake animation might finish
        setTimeout(() => setLoginStatus('idle'), 500);
      }
    } catch (err) {
      setLoginStatus('error');
      setErrorMessage('登录服务暂时不可用');
      setTimeout(() => setLoginStatus('idle'), 500);
    }
  };

  return (
    <div className="relative min-h-screen w-full flex items-center justify-center overflow-hidden bg-[#0f172a] text-slate-200 font-sans selection:bg-blue-500/30">

      {/* Styles for Custom Animations */}
      <style>{`
        @keyframes subtle-float {
          0%, 100% { transform: translateY(0px); }
          50% { transform: translateY(-10px); }
        }
        @keyframes grid-move {
          0% { background-position: 0 0; }
          100% { background-position: 40px 40px; }
        }
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          20% { transform: translateX(-4px); }
          40% { transform: translateX(4px); }
          60% { transform: translateX(-2px); }
          80% { transform: translateX(2px); }
        }
        .animate-subtle-float { animation: subtle-float 10s ease-in-out infinite; }
        .animate-shake { animation: shake 0.4s cubic-bezier(.36,.07,.19,.97) both; }

        /* Floating Label CSS Logic */
        .floating-input:placeholder-shown ~ .floating-label {
          top: 1rem;
          font-size: 0.875rem;
          color: #94a3b8;
        }
        .floating-input:focus ~ .floating-label,
        .floating-input:not(:placeholder-shown) ~ .floating-label {
          top: 0.25rem;
          font-size: 0.65rem;
          color: #60a5fa;
          font-weight: 700;
          letter-spacing: 0.05em;
        }
      `}</style>

      {/* --- Dynamic Background --- */}
      <div className="absolute inset-0 w-full h-full overflow-hidden">
        {/* Tech Grid Overlay */}
        <div 
            className="absolute inset-0 opacity-[0.03]" 
            style={{ 
                backgroundImage: 'linear-gradient(#fff 1px, transparent 1px), linear-gradient(90deg, #fff 1px, transparent 1px)', 
                backgroundSize: '40px 40px',
                animation: 'grid-move 20s linear infinite'
            }}
        ></div>

        {/* Color Blobs */}
        <div className="absolute top-[-10%] left-[-10%] w-[600px] h-[600px] rounded-full bg-blue-600/20 blur-[120px] animate-pulse"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[600px] h-[600px] rounded-full bg-indigo-600/20 blur-[120px] animate-pulse delay-700"></div>
        <div className="absolute top-[40%] left-[40%] w-[300px] h-[300px] rounded-full bg-cyan-500/10 blur-[80px] animate-subtle-float"></div>
      </div>

      {/* --- Main Card --- */}
      <div 
        ref={containerRef}
        className={`
            relative z-10 w-full max-w-[420px] p-8 m-4
            backdrop-blur-2xl bg-white/5 border border-white/10 
            rounded-3xl shadow-[0_0_40px_-10px_rgba(0,0,0,0.3)]
            ring-1 ring-white/10
            transform transition-all duration-300
            ${loginStatus === 'error' ? 'animate-shake ring-red-500/30' : ''}
        `}
      >
          {/* Top Highlight Line */}
          <div className="absolute top-0 left-1/2 -translate-x-1/2 w-1/3 h-[1px] bg-gradient-to-r from-transparent via-blue-400/50 to-transparent"></div>

          {/* Header */}
          <div className="text-center mb-8 relative group cursor-default">
             <div className="relative mx-auto h-16 w-16 mb-4 transform transition-transform duration-500 group-hover:rotate-12 group-hover:scale-110">
                <div className="absolute inset-0 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-2xl shadow-lg shadow-blue-500/40"></div>
                <div className="absolute inset-[1px] bg-[#0f172a] rounded-2xl flex items-center justify-center">
                    <LayoutDashboard className="h-8 w-8 text-blue-500" />
                </div>
             </div>
             <h2 className="text-3xl font-bold tracking-tight text-white mb-2">Admin Pro</h2>
             <p className="text-slate-400 text-sm">{t('loginDesc')}</p>
          </div>

          {/* User Preview Animation */}
          <div className={`
              overflow-hidden transition-all duration-500 ease-out mb-6
              ${matchedUser ? 'max-h-24 opacity-100' : 'max-h-0 opacity-0'}
          `}>
              <div className="flex items-center gap-4 bg-slate-800/50 rounded-xl p-3 border border-white/5 mx-2">
                 <div className="relative h-12 w-12 shrink-0">
                    <img 
                        src={matchedUser?.avatar || `https://ui-avatars.com/api/?name=${matchedUser?.username}`}
                        className="h-full w-full rounded-full object-cover border border-white/10"
                        alt="Avatar" 
                    />
                    <div className="absolute bottom-0 right-0 h-3 w-3 bg-green-500 rounded-full border-2 border-slate-900"></div>
                 </div>
                 <div className="flex-1 min-w-0">
                     <p className="text-sm font-medium text-white truncate">{matchedUser?.nickname || matchedUser?.username}</p>
                     <p className="text-xs text-slate-400 truncate capitalize">{t(matchedUser?.role || 'user')}</p>
                 </div>
              </div>
          </div>

          {/* Form */}
          <form onSubmit={handleSubmit} className="space-y-5">

              {errorMessage && (
                <div className="flex items-center gap-2 text-sm text-red-400 bg-red-400/10 border border-red-400/20 px-4 py-3 rounded-xl animate-fade-in">
                  <AlertCircle className="h-4 w-4 shrink-0" />
                  {errorMessage}
                </div>
              )}

              {/* Username Field */}
              <div className="relative group">
                  <div className="absolute left-4 top-[1.15rem] text-slate-500 transition-colors group-focus-within:text-blue-500">
                    <UserIcon className="h-5 w-5" />
                  </div>
                  <input
                    id="username"
                    type="text"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    className="floating-input peer w-full bg-slate-900/50 border border-white/10 rounded-xl px-12 pt-6 pb-2 text-white outline-none focus:border-blue-500/50 focus:bg-slate-900/80 focus:ring-4 focus:ring-blue-500/10 transition-all placeholder-transparent"
                    placeholder="Username"
                    required
                  />
                  <label htmlFor="username" className="floating-label absolute left-12 text-slate-400 uppercase pointer-events-none transition-all duration-200">
                    {t('username')}
                  </label>
              </div>

              {/* Password Field */}
              <div className="relative group">
                  <div className="absolute left-4 top-[1.15rem] text-slate-500 transition-colors group-focus-within:text-purple-500">
                    <Lock className="h-5 w-5" />
                  </div>
                  <input
                    id="password"
                    type={showPassword ? 'text' : 'password'}
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="floating-input peer w-full bg-slate-900/50 border border-white/10 rounded-xl px-12 pt-6 pb-2 text-white outline-none focus:border-purple-500/50 focus:bg-slate-900/80 focus:ring-4 focus:ring-purple-500/10 transition-all placeholder-transparent"
                    placeholder="Password"
                  />
                  <label htmlFor="password" className="floating-label absolute left-12 text-slate-400 uppercase pointer-events-none transition-all duration-200">
                    {t('password')}
                  </label>

                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-4 top-4 text-slate-500 hover:text-white transition-colors focus:outline-none"
                    tabIndex={-1}
                  >
                    {showPassword ? <EyeOff className="h-5 w-5" /> : <Eye className="h-5 w-5" />}
                  </button>
              </div>

              {/* Caps Lock Warning */}
              {capsLockOn && (
                  <div className="flex items-center gap-2 text-xs text-amber-400 animate-fade-in pl-1">
                      <AlertTriangle className="h-3 w-3" />
                      <span>Caps Lock is ON</span>
                  </div>
              )}

              {/* Submit Button */}
              <button
                type="submit"
                disabled={loginStatus === 'loading' || loginStatus === 'success'}
                className={`
                    group relative w-full flex items-center justify-center py-4 px-4 rounded-xl font-bold text-sm text-white overflow-hidden transition-all duration-300
                    ${loginStatus === 'success' 
                        ? 'bg-green-500 scale-95 ring-4 ring-green-500/20' 
                        : 'bg-gradient-to-r from-blue-600 to-indigo-600 hover:shadow-[0_0_20px_-5px_rgba(79,70,229,0.5)] hover:scale-[1.02] active:scale-95'
                    }
                    disabled:opacity-80 disabled:cursor-not-allowed
                `}
              >
                {/* Button Content Transition */}
                <div className="relative z-10 flex items-center gap-2">
                    {loginStatus === 'loading' ? (
                        <>
                            <div className="h-4 w-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                            <span>{t('signingIn')}</span>
                        </>
                    ) : loginStatus === 'success' ? (
                        <>
                            <Check className="h-5 w-5 animate-bounce" />
                            <span>{t('success')}</span>
                        </>
                    ) : (
                        <>
                            <span>{t('signIn')}</span>
                            <ArrowRight className="h-4 w-4 transition-transform group-hover:translate-x-1" />
                        </>
                    )}
                </div>

                {/* Shimmer Effect overlay (only when idle) */}
                {loginStatus === 'idle' && (
                    <div className="absolute inset-0 -translate-x-full group-hover:animate-[shimmer_1.5s_infinite] bg-gradient-to-r from-transparent via-white/20 to-transparent z-0"></div>
                )}
              </button>

              <div className="pt-4 text-center">
                 <p className="text-xs text-slate-500">
                    管理员账号 <span className="text-slate-400 font-mono bg-white/5 px-1 rounded">admin</span> 密码 <span className="text-slate-400 font-mono bg-white/5 px-1 rounded">123456</span>
                 </p>
              </div>
          </form>
      </div>

      <p className="absolute bottom-6 text-xs text-slate-600 font-medium tracking-wide">
         SECURE ADMIN DASHBOARD &copy; 2024
      </p>
    </div>
  );
};

