export const userService = {
  getUsers: (): User[] => {
    const stored = localStorage.getItem(USERS_STORAGE_KEY);
    let users: User[] = [];

    if (!stored) {
      users = [...INITIAL_USERS];
      localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(users));
    } else {
      try {
        users = JSON.parse(stored);
      } catch (e) {
        // If data is corrupted, reset
        users = [...INITIAL_USERS];
        localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(users));
      }
    }

    // CRITICAL FIX: Ensure 'admin' user always exists and has valid password
    // This handles cases where local storage might have preserved a state where admin was deleted or modified
    const adminIndex = users.findIndex(u => u.username === 'admin');
    if (adminIndex === -1) {
        const defaultAdmin = INITIAL_USERS.find(u => u.username === 'admin');
        if (defaultAdmin) {
            users.unshift(defaultAdmin);
            localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(users));
        }
    } else {
        // Optional: Reset admin password to default if login issues persist
        // Uncomment the line below if you want to force reset password on every load
        // users[adminIndex].password = '123456';
    }

    return users;
  },

  getUserByUsername: (username: string): User | undefined => {
    const users = userService.getUsers();
    return users.find(u => u.username === username);
  },

  saveUser: (user: User): void => {
    const users = userService.getUsers();
    const index = users.findIndex(u => u.id === user.id);

    // If creating a new user without a password, set a default one
    if (index === -1 && !user.password) {
        user.password = '123456'; 
    }

    // Preserve password if editing and not provided
    if (index >= 0 && !user.password) {
        user.password = users[index].password;
    }

    // Preserve points and check-in if not provided in update
    if (index >= 0) {
        if (user.points === undefined) user.points = users[index].points;
        if (user.lastCheckIn === undefined) user.lastCheckIn = users[index].lastCheckIn;
    } else {
        // New user default points
        if (user.points === undefined) user.points = 0;
    }

    if (index >= 0) {
      users[index] = { ...users[index], ...user };
    } else {
      users.push({ ...user, id: Date.now().toString(), createdAt: new Date().toISOString().split('T')[0] });
    }

    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(users));
  },

  deleteUser: (id: string): void => {
    const users = userService.getUsers();
    const newUsers = users.filter(u => u.id !== id);
    localStorage.setItem(USERS_STORAGE_KEY, JSON.stringify(newUsers));
  }
};

import { UserProfile } from '../types';
import { userService } from './userService';
import { activityService } from './activityService';

const TOKEN_KEY = 'admin_dashboard_token';
const USER_KEY = 'admin_dashboard_user';

export const authService = {
  login: async (username: string, password: string): Promise<UserProfile | null> => {
    // Mock API delay
    await new Promise(resolve => setTimeout(resolve, 600));

    // Trim inputs to avoid whitespace errors
    const cleanUsername = username.trim();
    const cleanPassword = password.trim();

    const user = userService.getUserByUsername(cleanUsername);

    if (user && user.password === cleanPassword && user.status === 'active') {
      const token = 'mock-jwt-token-' + Date.now();

      const profile: UserProfile = {
        ...user
      };

      localStorage.setItem(TOKEN_KEY, token);
      localStorage.setItem(USER_KEY, JSON.stringify(profile));

      // Log Activity
      activityService.logActivity(profile, 'login', 'User logged in successfully');

      return profile;
    }
    return null;
  },

  logout: () => {
    // Optional: Log logout before clearing storage if we had the user object available easily here
    localStorage.removeItem(TOKEN_KEY);
    localStorage.removeItem(USER_KEY);
  },

  isAuthenticated: (): boolean => {
    return !!localStorage.getItem(TOKEN_KEY);
  },

  getUser: (): UserProfile | null => {
    const userStr = localStorage.getItem(USER_KEY);
    return userStr ? JSON.parse(userStr) : null;
  },

  updateUser: (user: UserProfile) => {
    localStorage.setItem(USER_KEY, JSON.stringify(user));
    // Also update the source of truth in user service
    userService.saveUser(user);
    // Log Activity
    activityService.logActivity(user, 'update', 'User profile updated');
  }
};
